window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q09"]=window.__LIBQ["tien-nghich"]["q09"]||{};window.__LIBQ["tien-nghich"]["q09"]["artifacts"]={"updatedAt":"2026-07-11","count":150,"artifacts":[{"id":"tam-huyet-co-than","name":"Tâm huyết Cổ Thần","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối tinh thể màu máu lớn nằm bên trong cơ thể huyết long, chứa tinh hoa tâm huyết của Cổ Thần. Trước đó bị Thác Sâm đoạt hết, Vương Lâm bất ngờ thu được.","detail":"Khối tinh thể màu máu lớn bên trong cơ thể huyết long. Toàn bộ tâm huyết Cổ Thần trong cơ thể Cổ Thần đã bị Thác Sâm đoạt lấy trước đó, nhưng Vương Lâm lợi dụng lúc lao vào vết thương huyết long mà thu được khối tinh thể này vào không gian trữ vật.","hinhDang":"Khối tinh thể màu máu lớn","nguonGoc":"Bên trong cơ thể huyết long (Cổ Thần)","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Thác Sâm","tuChuong":"@c1064","denChuong":"@c1064","cachCoDuoc":"Đoạt từ Cổ Thần","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1064","denChuong":"","cachCoDuoc":"Lao vào vết thương huyết long thu lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1064","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm đoạt được","text":"Vương Lâm lao vào vết thương huyết long, thu khối tinh thể màu máu lớn (tâm huyết Cổ Thần) vào không gian trữ vật. Trước đó toàn bộ đã bị Thác Sâm đoạt.","anchor":"hắn biết được toàn bộ tâm huyết trong cơ thể của Cổ Thần đều đã bị Thác Sâm đoạt lấy"}]},"nguon":["@c1064"]},{"id":"thanh-kiem-gay","name":"Thanh kiếm gãy (của Lỗ phu tử)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả áo đen"],"trangThai":"Đã bị hủy","blurb":"Thanh kiếm chỉ còn một nửa của Lỗ phu tử, mang uy áp kinh thiên, cần phun máu tươi lên mới kích hoạt. Từng xuyên thấu chân phải Cổ Thần Thác Sâm nhưng sau đó bị Diệt Thần Mâu hủy hoàn toàn.","detail":"Thanh kiếm gãy của Lỗ phu tử chỉ còn lại một nửa nhưng vẫn mang uy áp kinh thiên, phải phun máu tươi lên mới kích hoạt. Khi Lỗ phu tử rút kiếm phun máu kích hoạt, thanh kiếm tấn công với tốc độ cực cao, xuyên thấu chân phải Cổ Thần Thác Sâm rồi lao thẳng tới tinh điểm thứ tư, nhưng bị tu sĩ xương khô từ tinh điểm thứ ba dùng hai ngón tay kẹp giữ đẩy bay. Sau đó thanh kiếm được triệu hồi lại để chặn Diệt Thần Mâu nhưng bị hủy hoàn toàn @c1066.","congNang":["Cần phun máu tươi lên mới kích hoạt @c1066","Tấn công với tốc độ cực cao, xuyên thấu thân Cổ Thần @c1066","Có thể được triệu hồi lại để chặn đòn tấn công @c1066"],"dacDiem":"Chỉ còn lại một nửa, cần máu kích hoạt","chuSoHuu":[{"ten":"Lão giả áo đen","tuChuong":"@c1066","denChuong":"@c1066","cachCoDuoc":"Sở hữu từ trước","trangThai":"Đã bị hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"dùng","importance":"major","giaiDoan":"Sử dụng và bị hủy","text":"Lỗ phu tử rút kiếm gãy phun máu kích hoạt, xuyên thấu chân phải Thác Sâm. Bị tu sĩ xương khô kẹp đẩy bay. Triệu hồi lại chặn Diệt Thần Mâu nhưng kiếm hóa hư vô, bị hủy hoàn toàn.","anchor":"thanh kiếm gãy này đã xuyên thấu qua chân phải của Cổ Thần Thác Sâm"}]},"nguon":["@c1066"],"uyLuc":"Mang uy áp kinh thiên, xuyên thấu chân phải Cổ Thần Thác Sâm @c1066"},{"id":"ran-ngu-giai-tu-muc","name":"Rắn Ngũ Giai Tử Mục","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Chưởng môn Quy Nguyên Tông"],"trangThai":"Thú trấn tông Quy Nguyên Tông","blurb":"Con rắn lớn toàn thân đen nhánh dài mấy trượng, được chưởng môn Quy Nguyên Tông nuôi dưỡng và giao phó làm thú trấn tông sau khi lão quy tiên.","detail":"Được nuôi trong khe trữ vật màu tím đỏ của chưởng môn. Khi xuất hiện mang uy áp tràn ngập khắp nơi, nhưng uể oải vờn quanh chủ nhân, lộ vẻ bi ai. Sau khi chưởng môn chết, trở thành thú trấn tông của Quy Nguyên Tông, bốn đệ tử thân truyền được dặn phải đối đãi tốt.","hinhDang":"Toàn thân đen nhánh, dài mấy trượng","congNang":["Thú trấn tông Quy Nguyên Tông, uy áp mạnh @c1068"],"chuSoHuu":[{"ten":"Chưởng môn Quy Nguyên Tông","tuChuong":"@c1068","denChuong":"@c1068","cachCoDuoc":"Nuôi dưỡng","trangThai":"chu-da-chet"}],"tabs":{"tienTrinh":[{"chuong":"@c1068","loai":"xuất hiện","importance":"normal","giaiDoan":"Được giao phó làm thú trấn tông","text":"Chưởng môn thả rắn Ngũ Giai Tử Mục ra từ khe trữ vật, dặn bốn đệ tử đối đãi tốt, giao phó làm thú trấn tông Quy Nguyên Tông.","anchor":"con rắn Ngũ Giai Tử Mục này chính là con thú trấn tông của Quy Nguyên Tông ta"}]},"capNhatToi":"@c1068","nguon":["@c1068"]},{"id":"ngoc-gian-mau-tim","name":"Ngọc giản màu tím","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lữ Yên Phi"],"trangThai":"dang-co","blurb":"Ngọc giản toàn bộ màu tím mà Lữ Yên Phi cầm chặt đầy nhẫn nhục, liên quan tới việc bị Lô Địch ép song tu. Nàng muốn bóp nát nhưng sợ hậu quả.","detail":"Ngọc giản toàn bộ có màu tím, gắn liền với việc ép buộc song tu từ Lô Địch. Lữ Yên Phi nắm chặt trong tay đầy đau buồn và nhẫn nhục, muốn bóp nát nhưng không dám vì sợ hậu quả.","congNang":["Chứa nội dung liên quan ép buộc song tu (chưa rõ cụ thể)"],"chuSoHuu":[{"ten":"Lữ Yên Phi","tuChuong":"@c1070","denChuong":"","cachCoDuoc":"Nhận được (liên quan Lô Địch)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1070","loai":"xuat-hien","importance":"normal","giaiDoan":"Lữ Yên Phi cầm ngọc giản đầy nhẫn nhục","text":"Ngọc giản màu tím xuất hiện trong tay Lữ Yên Phi, liên quan tới việc Lô Địch ép nàng song tu. Nàng muốn bóp nát nhưng sợ hậu quả.","anchor":"ngọc giản này toàn bộ có màu tím, bị nâng mạnh mẽ nắm chặt trong tay"}]},"nguon":["@c1070"]},{"id":"nhap-tu-ly-hon-dan","name":"Nhập Tử Ly Hồn Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Tôn Vân"],"trangThai":"dang-co","blurb":"Nhập Tử Ly Hồn Đan là viên đan dược màu đen bọc sáp, chứa thiên địa nguyên lực nồng đậm cùng hồn lực kỳ dị. Tôn Vân định dùng nó để đột phá Dương Thực sau khi thất bại và nguyên thần bị thương, nhưng bị Vương Lâm truyền âm ngăn lại.","detail":"Nhập Tử Ly Hồn Đan là viên đan dược màu đen bọc trong lớp sáp, khi lộ ra phát tỏa thiên địa nguyên lực nồng đậm cùng hồn lực kỳ dị, được miêu tả đáng sợ. Đan dược này có tác dụng trợ giúp đột phá cảnh giới nhưng ẩn chứa nguy hiểm. Trong truyện, sau khi đột phá Dương Thực thất bại và nguyên thần bị thương, Tôn Vân quyết định nuốt viên đan này để đột phá, nhưng đúng lúc định nuốt thì bị Vương Lâm truyền âm chữ Định ngăn lại. @c1070","congNang":["Trợ giúp đột phá cảnh giới, nhưng đi kèm nguy hiểm @c1070"],"dacDiem":"Đan dược màu đen bọc sáp, phát ra thiên địa nguyên lực nồng đậm và hồn lực kỳ dị","chuSoHuu":[{"ten":"Tôn Vân","tuChuong":"@c1070","denChuong":"","cachCoDuoc":"Không rõ nguồn gốc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1070","loai":"xuat-hien","importance":"major","giaiDoan":"Tôn Vân lấy ra định uống, bị ngăn","text":"Tôn Vân đột phá Dương Thực thất bại, nguyên thần bị thương, lấy Nhập Tử Ly Hồn Đan ra định nuốt. Vương Lâm truyền âm chữ Định ngăn lại.","anchor":"bên trong lộ ra một đan dược màu đen. Ngay khi đan dược này xuất hiện, một luông thiên địa nguyên lực nồng đậm lập tức từ bên trong tràn ra"}]},"nguon":["@c1070"]},{"id":"tu-muc-mang","name":"Tử Mục Mãng","cn":"","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Lữ Yên Phi"],"trangThai":"dang-co","blurb":"Linh vật sư tôn Lữ Yên Phi để lại, dùng kiểm nghiệm tư chất đệ tử mới — phải được nó tán thành mới trở thành Bạn Linh Tử.","detail":"Tử Mục Mãng là linh vật do sư tôn Lữ Yên Phi để lại cho Quy Nguyên Tông. Dùng để kiểm nghiệm tư chất đệ tử mới nhập môn: phải được nó tán thành mới có thể trở thành Bạn Linh Tử của tông phái.","nguon":["@c1070"]},{"id":"man-thien-dan","name":"Man Thiên Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Lữ Yên Phi"],"trangThai":"đã sử dụng (Lữ Yên Phi đã dùng để Vấn Đỉnh)","blurb":"Đan dược trợ giúp tu sĩ Vấn Đỉnh thành công, do sư tôn Lữ Yên Phi hao phí lượng lớn dược liệu, đi trao đổi nhiều tông phái rồi tự luyện cho nàng.","detail":"Man Thiên Đan là đan dược hiếm có thể trợ giúp tu sĩ Vấn Đỉnh thành công. Sư tôn Lữ Yên Phi bất chấp hao phí dược liệu, đi tới các tông phái khác ở rất xa trao đổi, cuối cùng tự mình luyện ra một viên cho nàng. Vương Lâm sau khi nghe Lữ Yên Phi kể đã đặc biệt hứng thú với loại đan dược này.","congNang":["Trợ giúp tu sĩ Vấn Đỉnh thành công"],"nguonGoc":"Sư tôn Lữ Yên Phi tự luyện, hao phí lượng lớn dược liệu và trao đổi nhiều tông phái","chuSoHuu":[{"ten":"Lữ Yên Phi","tuChuong":"@c1071","denChuong":"","cachCoDuoc":"Sư tôn luyện cho","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1071","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc đến trong lời kể của Lữ Yên Phi","text":"Lữ Yên Phi kể sư tôn hao phí dược liệu tự luyện Man Thiên Đan giúp nàng Vấn Đỉnh thành công. Vương Lâm nghe xong lộ vẻ hứng thú.","anchor":"lại đi tới các tông phái khác ở rất xa trao đổi… cuối cùng tự mình vì ta mà luyện ra một viên Man Thiên Đan"}]},"capNhatToi":"@c1071","nguon":["@c1071"]},{"id":"ly-hon-dan-cap-tam","name":"Ly Hồn Đan cấp tám","cn":"离魂丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp 8/13","soHuu":["Quy Nguyên Tông"],"trangThai":"phế đan","blurb":"Di bảo lão tổ Quy Nguyên Tông truyền lại, là phế đan — không dung nhập bất kỳ hồn linh thú nào. Vương Lâm dùng để chứng thực phỏng đoán về luyện đan Vân Hải.","detail":"Ly Hồn Đan cấp tám, di bảo lão tổ Quy Nguyên Tông truyền từ đời này qua đời khác, đặt trên giá trong đạo quán bí mật. Đáng tiếc là phế đan, không dung nhập bất kỳ hồn linh thú nào. Vương Lâm xem xét để chứng thực phỏng đoán về phương pháp luyện đan Vân Hải, không lấy đi.","nguonGoc":"Di bảo lão tổ Quy Nguyên Tông","dacDiem":"Phế đan, không có hồn linh thú","congNang":[],"chuSoHuu":[{"ten":"Quy Nguyên Tông","tuChuong":"@c1073","denChuong":"","cachCoDuoc":"di bảo lão tổ truyền lại","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1073","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm xem xét chứng thực","text":"Vương Lâm phá cấm chế trong đạo quán bí mật, xem xét Ly Hồn Đan cấp tám (phế đan) để chứng thực phỏng đoán về phương pháp luyện đan Vân Hải. Không lấy đi.","anchor":"Thứ mà lão tổ của Quy Nguyên Tông này để lại, là một Ly Hồn Đan cấp tám truyền từ đời này qua đời khác trong Quy Nguyên Tông"}]},"nguon":["@c1073"]},{"id":"doa-sen-den","name":"Đóa sen đen","cn":"","aliases":["Hoa sen màu đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Bị đổi chủ (Lô Địch → Vương Lâm)","blurb":"Đóa sen đen là bảo mệnh pháp bảo của Lô Địch, do phụ thân Lô Vân Tòng cho để phòng thân. Toàn thân đen nhánh, khi nở ra tỏa hàn quang yêu dị. Lô Địch chưa kịp kích hoạt thì đã bị Vương Lâm giết chết, đóa sen bị Vương Lâm thu lấy.","detail":"Đóa sen đen nhánh là bảo mệnh pháp bảo mà Lô Vân Tòng, tông chủ Tử Đạo Tông,ban cho con trai Lô Địch để phòng thân. Pháp bảo toàn thân đen nhánh, khi nở ra tỏa hàn quang mang vẻ yêu dị. Trong lúc hoảng loạn, Lô Địch lấy đóa sen ra làm bảo mệnh nhưng chưa kịp kích hoạt thì Vương Lâm đã điểm ngón tay giết chết hắn và thu lấy đóa sen (@c1075).","congNang":["Bảo mệnh pháp bảo — công năng cụ thể chưa rõ do chưa được kích hoạt (@c1075)"],"chuSoHuu":[{"ten":"Lô Địch","tuChuong":"@c1075","denChuong":"@c1075","cachCoDuoc":"Được phụ thân Lô Vân Tòng cho","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1075","denChuong":"","cachCoDuoc":"Thu từ Lô Địch sau khi giết","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1075","loai":"doi-chu","importance":"major","giaiDoan":"Lô Địch lấy ra → bị giết → Vương Lâm thu","text":"Lô Địch lấy đóa sen đen ra làm bảo mệnh nhưng chưa kịp kích hoạt đã bị Vương Lâm điểm ngón tay giết chết. Vương Lâm thu lấy đóa sen.","anchor":"Đóa sen này toàn bộ đen nhánh, nở ra một cách yêu dị, tỏa ra hàn quang"}]},"nguon":["@c1075"],"dacDiem":"Toàn thân đen nhánh, khi nở ra tỏa hàn quang yêu dị."},{"id":"ho-cot-hon-dan","name":"Hổ Cốt Hồn Đan","cn":"虎骨魂丹","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Lô Vân Tòng"],"trangThai":"Đang luyện, sắp thành","blurb":"Đan dược mà tông chủ Tử Đạo Tông Lô Vân Tòng đang luyện, cần nguyên liệu tinh hổ thú. Sắp luyện thành.","detail":"Hổ Cốt Hồn Đan là đan dược Lô Vân Tòng (tông chủ Tử Đạo Tông) đang luyện chế tại đại lục tím. Nguyên liệu chính là tinh hổ thú (loài mãnh thú giống hổ, lớn trăm trượng). Lão già áo tím chúc mừng tông chủ bắt thêm được tinh hổ thú và nói đan dược sắp luyện thành. Tác dụng cụ thể chưa rõ.","congNang":["Chưa rõ tác dụng"],"tabs":{"tienTrinh":[{"chuong":"@c1075","loai":"xuat-hien","importance":"normal","giaiDoan":"Đang luyện, sắp thành","text":"Lô Vân Tòng bắt thêm tinh hổ thú để luyện. Lão già áo tím nói sắp luyện thành.","anchor":"Hổ Cốt Hồn Đan của tông chủ sẽ có thể luyện thành"}]},"nguon":["@c1075"]},{"id":"co-nho-mau-vang","name":"Cờ nhỏ màu vàng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo từ túi trữ vật Lô Địch, bên trong chứa mấy trăm âm hồn nữ tử bị phong ấn cùng thú hồn hình rắn nuốt âm hồn, phát ra khí tức cực âm — mảnh ghép cuối để Thiên Nghịch Châu viên mãn lần hai.","detail":"Cờ nhỏ màu vàng tìm thấy trong túi trữ vật Lô Địch. Khi Vương Lâm đưa thần thức vào bên trong, phát hiện mấy trăm âm hồn nữ tử bị phong ấn và một thú hồn hình rắn nuốt âm hồn, phát ra khí tức cực âm. Cách nuôi dưỡng chưa đúng nên cực âm chưa hoàn chỉnh, kém xa cực dương mà Thiên Vận Tử mượn Bạch Vi sinh ra.","congNang":["Chứa âm hồn, nuôi dưỡng khí tức cực âm thông qua thú hồn hình rắn"],"chuSoHuu":[{"ten":"Lô Địch","tuChuong":"@c1076","denChuong":"@c1076","cachCoDuoc":"Sở hữu gốc","trangThai":"da-chet"},{"ten":"Vương Lâm","tuChuong":"@c1076","denChuong":"","cachCoDuoc":"Thu từ túi trữ vật Lô Địch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1076","loai":"xuat-hien","importance":"normal","giaiDoan":"Phát hiện trong túi Lô Địch","text":"Vương Lâm kiểm tra túi trữ vật Lô Địch, tìm thấy cờ nhỏ vàng. Đưa thần thức vào phát hiện mấy trăm âm hồn nữ tử và thú hồn hình rắn phát khí tức cực âm — mảnh ghép cuối cho Thiên Nghịch Châu viên mãn lần hai.","anchor":"lập tức hiện lên không dưới mấy trăm âm hồn của nữ tử"}]},"nguon":["@c1076"]},{"id":"thien-am-phien","name":"Thiên Âm Phiên","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật tông môn","soHuu":["Tử Đạo Tông"],"trangThai":"dang-co","blurb":"Bảo vật tông môn của Tử Đạo Tông, đặt ở Tử Vân Hải. Có khả năng phong ấn hồn phách. Lô Địch muốn lấy để phong ấn hồn phách nữ tử nuôi âm tiên nhưng chưa kịp thực hiện.","detail":"Thiên Âm Phiên là bảo vật tông môn Tử Đạo Tông, cất giữ tại Tử Vân Hải. Lô Địch trước khi chết muốn bắt lấy hồn phách Lữ Yên Phi cùng hồn phách các nữ tử đã thu trước đó phong ấn vào trong Thiên Âm Phiên để nuôi dưỡng âm tiên. Khi Lô Vân Tòng nghe tin này thì nổi giận dữ dội.","congNang":["Phong ấn hồn phách","Nuôi dưỡng âm tiên (theo ý đồ Lô Địch)"],"tabs":{"tienTrinh":[{"chuong":"@c1076","loai":"nhac-toi","importance":"normal","giaiDoan":"Lộ diện qua lời kể","text":"Lão già áo tím tiết lộ Lô Địch muốn lấy Thiên Âm Phiên ở Tử Vân Hải để phong ấn hồn phách nữ tử nuôi âm tiên, khiến Lô Vân Tòng nổi giận.","anchor":"muốn bắt lấy hồn phách của Lữ Yên Phi cùng với hồn phách của những nữ tư thu được trước đây phong ấn vào trong đó để nuôi dưỡng âm tiên"}]},"nguon":["@c1076"]},{"id":"binh-ngoc-mau-tim","name":"Bình ngọc màu tím","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chiến lợi phẩm từ Lô Địch, toàn thân có hơi nóng, bên trong sức mạnh thiên địa tuần hoàn xoay tròn chứa ba viên đan dược phát tử quang, mỗi viên có hồn phách hung ác.","detail":"Bình ngọc màu tím thu được từ Lô Địch. Toàn thân có hơi nóng, bên trong sức mạnh thiên địa tuần hoàn xoay tròn bảo quản ba viên đan dược phát tử quang. Mỗi viên đan dược có một hồn phách hung ác mờ ảo rít gào bên trong. Công dụng cụ thể chưa rõ.","congNang":["Bảo quản đan dược bằng tuần hoàn sức mạnh thiên địa"],"chuSoHuu":[{"ten":"Lô Địch","tuChuong":"@c1077","denChuong":"@c1077","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1077","denChuong":"","cachCoDuoc":"Thu làm chiến lợi phẩm từ Lô Địch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1077","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm kiểm tra chiến lợi phẩm","text":"Vương Lâm lấy bình ngọc tím ra xem xét, phát hiện bên trong có ba viên đan dược phát tử quang, mỗi viên chứa hồn phách hung ác mờ ảo.","anchor":"theo sức mạnh thiên địa xoay tròn có ba viên đan dược"}]},"nguon":["@c1077"]},{"id":"ngung-toai-thao","name":"Ngưng Toái Thảo","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"binh-thuong","blurb":"Phụ dược luyện đan, phần lớn phương pháp luyện đan Quy Nguyên Tông đều cần loại dược thảo này.","detail":"Dược thảo phổ biến tại Vân Hải Tinh Vực, là phụ dược luyện đan mà phần lớn phương pháp luyện đan của Quy Nguyên Tông đều cần.","nguon":["@c1077"]},{"id":"mac-van-chi","name":"Mặc Vân Chi","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"binh-thuong","blurb":"Chủ dược luyện chế Khuyết Vân Đan, được Tôn Vân giới thiệu cho Vương Lâm.","detail":"Dược thảo tại Vân Hải Tinh Vực, là chủ dược để luyện chế Khuyết Vân Đan.","nguon":["@c1077"]},{"id":"vu-trung-hoa","name":"Vụ Trung Hoa","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Lý sư thúc"],"trangThai":"binh-thuong","blurb":"Dược thảo quý hiếm chỉ mọc trên đại lục hoang dã bị tinh vụ bao phủ ngoài tinh vực, là nguyên liệu quan trọng để luyện Ly Hồn Đan tầng sáu trở lên.","detail":"Chỉ mọc trên đại lục hoang dã bị tinh vụ bao phủ ngoài tinh vực, nơi tinh vụ càng đậm đặc hoa càng nhiều. Trong Quy Nguyên Tông chỉ có ba cây hoa khô ở chỗ Lý sư thúc. Là dược liệu quan trọng để luyện Ly Hồn Đan từ tầng sáu trở lên.","nguon":["@c1077"]},{"id":"khuyet-van-dan","name":"Khuyết Vân Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"binh-thuong","blurb":"Đan dược cần Mặc Vân Chi làm chủ dược, được Tôn Vân nhắc tới khi giới thiệu dược thảo cho Vương Lâm.","detail":"Đan dược cần Mặc Vân Chi làm chủ dược, được Tôn Vân nhắc tới trong quá trình dạy Vương Lâm nhận biết dược thảo Vân Hải Tinh Vực.","nguon":["@c1077"]},{"id":"thu-hon-linh-thu-lo-dich","name":"Thú hồn linh thú Lô Địch","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hồn phách linh thú giống con nòng nọc của Lô Địch, bị Vương Lâm dùng làm nguyên liệu luyện đan dược tầng ba.","detail":"Hồn phách linh thú giống con nòng nọc, khi sống cực ngang ngược từng nuốt phàm nhân và tu sĩ bị thương. Bị Vương Lâm lấy từ khe trữ vật ném vào hỏa cầu dung hợp làm nguyên liệu luyện đan dược tầng ba, đan tạc lần đầu.","nguon":["@c1077"]},{"id":"dan-duoc-cap-ba","name":"Đan dược cấp ba","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp ba","soHuu":["Tôn Vân"],"trangThai":"da-tang","blurb":"Viên đan dược Vương Lâm luyện thành sau mười sáu lần thử trên Mạc La, cần thiết cho tu sĩ cảnh giới Dương Thực. Được ném cho Tôn Vân trước khi Vương Lâm rời đi.","detail":"Vương Lâm dùng thuật luyện đan Vân Hải kết hợp Thú hồn dung hợp, ba ngày luyện mười sáu lần chỉ lần đầu và lần cuối thành công. Dược thảo trong vườn Tôn Vân vốn đủ luyện đan dược cấp bốn, nếu Lý sư thúc luyện có thể đạt cấp năm, nhưng Vương Lâm mới học nên chỉ ra được cấp ba. Dù vậy đan dược cấp ba vẫn rất quý, rất cần thiết cho tu sĩ cảnh giới Dương Thực.","congNang":["Dùng cho tu sĩ cảnh giới Dương Thực"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1078","denChuong":"@c1078","cachCoDuoc":"Tự luyện chế","trangThai":"da-tang"},{"ten":"Tôn Vân","tuChuong":"@c1078","denChuong":"","cachCoDuoc":"Vương Lâm ném cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1078","loai":"xuat-hien","importance":"normal","giaiDoan":"Luyện thành và trao tay","text":"Vương Lâm luyện mười sáu lần trong ba ngày, chỉ hai lần thành công, luyện được đan dược cấp ba. Ném cho Tôn Vân trước khi rời Mạc La đại lục.","anchor":"đan dược cấp ba cũng rất quý, rất cần thiết cho tu sĩ cảnh giới Dương Thực"}]},"nguon":["@c1078"]},{"id":"cay-dai-thu-tim-man-hoang","name":"Cây đại thụ tím (Man Hoang)","cn":"","category":"khac","categoryLabel":"Dược thảo/Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"đã thu","blurb":"Cây đại thụ màu tím ở đỉnh núi Man Hoang, đã héo rũ nhiều năm nhưng không chết, lá trắng gân trong suốt, trên thân có hai quả trắng đen liên tục biến hóa kỳ dị.","detail":"Cây đại thụ màu tím chỉ cao tới cẳng chân khỉ đen, đã héo rũ nhưng không chết, nhánh rậm rạp, lá trắng như tuyết có gân trong suốt. Trên thân có hai quả như nắm tay, trắng đen liên tục biến hóa kỳ dị. Bị Vương Lâm vỗ tay thu gọn cả gốc lẫn ngọn vào khe trữ vật. Công dụng chưa rõ.","hinhDang":"Cây tím, nhánh rậm rạp, lá trắng như tuyết gân trong suốt, hai quả trắng đen biến hóa","congNang":[],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1079","denChuong":"","cachCoDuoc":"Vỗ tay thu gọn cả gốc lẫn ngọn vào khe trữ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1079","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Vương Lâm thu","text":"Cây đại thụ tím trên đỉnh núi Man Hoang, lá trắng gân trong suốt, hai quả trắng đen biến hóa. Vương Lâm vỗ tay thu gọn cả gốc lẫn ngọn vào khe trữ vật.","anchor":"trên thân cây lại có hai quả như nắm tay, trái cây kia có hai màu trắng đen liên tục biến hóa"}]},"capNhatToi":"@c1079","nguon":["@c1079"]},{"id":"ngoc-gian-pha-thien-tong","name":"Ngọc giản Phá Thiên Tông","cn":"","category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Cấp tám (nguồn gốc Phá Thiên Tông)","soHuu":["Thi Lạc Hình","Vương Lâm"],"trangThai":"Đang được Vương Lâm giữ","blurb":"Ngọc giản đến từ Phá Thiên Tông thuộc tinh vực cấp tám, chứa phương pháp bào chế Niết Không Đan trong truyền thuyết. Vì manh mối đan phương này, ngọc giản trở thành mục tiêu tranh đoạt của gần như toàn bộ tông phái tinh vực cấp sáu.","detail":"Ngọc giản có nguồn gốc từ Phá Thiên Tông, một thế lực thuộc tinh vực cấp tám, bên trong ghi chép phương pháp bào chế Niết Không Đan — đan dược được xem là truyền thuyết. Thi Lạc Hình theo manh mối tìm được ngọc giản trong tinh vực cấp ba (@c1080), nhưng hành tung bại lộ khiến gần như toàn bộ tông phái tinh vực cấp sáu ồ ạt truy đuổi tranh đoạt. Về sau, khi Vương Lâm luyện hóa hài cốt bốn đệ tử, y phát hiện trên ngọc giản ghi dấu Phá Thiên Tông cấp tám cùng một mảnh xương thú (@c1083).","nguonGoc":"Phá Thiên Tông, tinh vực cấp tám","congNang":["Chứa phương pháp bào chế Niết Không Đan trong truyền thuyết"],"chuSoHuu":[{"ten":"Thi Lạc Hình","tuChuong":"@c1080","denChuong":"@c1083","cachCoDuoc":"Không rõ nguồn gốc ban đầu","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1083","denChuong":"","cachCoDuoc":"Luyện hóa hài cốt đệ tử để tìm ra","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1080","loai":"xuất hiện","importance":"major","giaiDoan":"Bại lộ, tranh đoạt","text":"Thi Lạc Hình tìm được ngọc giản trong tinh vực cấp ba, hành tung bại lộ dẫn đến gần toàn bộ tông phái tinh vực cấp sáu truy đuổi. Lão bà Ngũ Độc Môn vây khốn Thi Lạc Hình uy hiếp giao nộp.","anchor":"Ngọc giản của Phá Thiên Tông tinh vực cấp tám, cũng chính là phương pháp bào chế Niết Không Đan trong truyền thuyết"},{"chuong":"@c1083","loai":"xuất hiện","importance":"major","giaiDoan":"Được Vương Lâm tìm ra từ tro hài cốt","text":"Vương Lâm luyện hóa hài cốt bốn đệ tử, phát hiện ngọc giản ghi Phá Thiên Tông cấp tám cùng mảnh xương thú trong tro bụi.","anchor":"khối ngọc giản và mảnh xương thú kia lập tức rơi vào trong tay"}]},"capNhatToi":"@c1080","nguon":["@c1080","@c1083"],"dacDiem":"Ghi dấu Phá Thiên Tông tinh vực cấp tám, đi kèm một mảnh xương thú (@c1083)"},{"id":"ngoc-gian-dan-phuong-nam-tu-trung-nien","name":"Ngọc giản và phương pháp luyện đan (nam tử trung niên)","cn":"","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Nam tử trung niên (sơn cốc Man Hoang)"],"trangThai":"chua-giao","blurb":"Ngọc giản và phương pháp luyện đan trong túi trữ vật của nam tử trung niên Tịnh Niết hậu kỳ, đáng giá đến mức gây ra cuộc chiến chết người với lão bà Ngũ Độc Môn. Chưa lộ nội dung cụ thể.","detail":"Nam tử trung niên muốn giao hai vật phẩm này cho Vương Lâm đổi lấy cái chết thống khoái. Hắn nhận định dù không giao thì Vương Lâm cũng có cách mở túi trữ vật. Nội dung ngọc giản và phương pháp luyện đan chưa được tiết lộ.","tabs":{"tienTrinh":[{"chuong":"@c1082","loai":"xuất hiện","importance":"normal","giaiDoan":"Nam tử trung niên đề nghị giao cho Vương Lâm","text":"Nam tử trung niên Tịnh Niết hậu kỳ trúng kịch độc xin Vương Lâm cho mượn nguyên lực mở túi trữ vật lấy ngọc giản và phương pháp luyện đan giao lại.","anchor":"Đạo hữu đến đây cũng đơn giản chỉ vì ngọc giản và phương pháp luyện đan"}]},"nguon":["@c1082"]},{"id":"con-ran-dau-mao-ga","name":"Con rắn nhỏ đầu mào gà","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh thú/Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Luồng khí thứ ba của lão bà Ngũ Độc Môn, con rắn nhỏ đầu mào gà phun khí cực độc. Bị Ngân Y Nữ Thi bắt sống sau khi nguyên thần lão bà bị thu.","detail":"Một trong ba luồng khí lão bà Ngũ Độc Môn phóng ra trong trận chiến với Vương Lâm. Con rắn nhỏ đầu mào gà xuyên qua lực trùng kích phóng tới Vương Lâm, chiến đấu với Ngân Y Nữ Thi rồi bị bắt sống khi nguyên thần lão bà bị thu.","nguon":["@c1082"]},{"id":"tam-dau-lau-phap-khi","name":"Tám đầu lâu (pháp khí trận pháp)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tám cái đầu lâu bao phủ sơn cốc tạo trận pháp vây khốn, nguyên thuộc lão bà Ngũ Độc Môn. Bị Vương Lâm phong ấn thành khô lâu xám nhỏ như nắm tay, giữ khả năng khôi phục bất cứ lúc nào.","detail":"Tám đầu lâu tạo trận pháp bao vây sơn cốc Man Hoang đại lục do lão bà Ngũ Độc Môn điều khiển. Sau khi lão bà chết, mất chủ trở nên bất ổn. Vương Lâm phong ấn chúng thành tám khô lâu xám nhỏ như nắm tay lơ lửng trên không, vẫn giữ khả năng khôi phục trận pháp vây khốn bất cứ lúc nào.","chuSoHuu":[{"ten":"Độc Bà Tử","tuChuong":"@c1082","denChuong":"@c1082","cachCoDuoc":"Sở hữu ban đầu","trangThai":"tu-vong"},{"ten":"Vương Lâm","tuChuong":"@c1082","denChuong":"","cachCoDuoc":"Phong ấn thu sau khi giết lão bà","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1082","loai":"đổi chủ","importance":"normal","giaiDoan":"Lão bà chết, Vương Lâm phong ấn thu","text":"Mất người điều khiển sau khi lão bà Ngũ Độc Môn bị giết, trở nên bất ổn. Vương Lâm phong ấn tám đầu lâu thành khô lâu xám nhỏ như nắm tay.","anchor":"hóa thành một cái đầu lâu xám nhỏ như nắm tay, vẫn lơ lửng trên bầu trời không nhúc nhích"}]},"nguon":["@c1082"]},{"id":"manh-xuong-thu-dan-phuong-niet-khong-dan","name":"Mảnh xương thú (đan phương Niết Không đan)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Đang được Vương Lâm giữ","blurb":"Mảnh xương thú nhỏ như bàn tay, khắc ghi đan phương luyện chế Niết Không đan. Đây là vật được Vương Lâm phát hiện, mang giá trị cực cao đủ khiến cả Tu Chân giới nổi kếp nạn tranh đoạt.","detail":"Mảnh xương thú ghi lại phương pháp luyện chế Niết Không đan, ban đầu bị một tên đàn ông trung niên giấu trong xác đệ tử. Đan dược luyện từ phương này có công hiệu trợ giúp tu hành Đệ Tam Bộ: ăn vào thì nắm chắc một phần quy tắc hóa bản nguyên trở thành tu sĩ Đệ Tam Bộ, nắm chắc năm phần vượt qua lần suy kiếp đầu tiên của Thiên Nhân, nắm chắc tám phần tiến vào cảnh giới Nhập Thần. Vương Lâm phát hiện và xác định vật này đủ khiến tu sĩ Tịnh Niết đại viên mãn cùng lão quái trong Thiên Nhân Suy Kiếp sẵn sàng liều mạng tranh đoạt.","nguon":["@c1083"],"tabs":{"tienTrinh":[{"chuong":"@c1083","loai":"xuất hiện","importance":"major","giaiDoan":"Được Vương Lâm tìm ra từ tro hài cốt","text":"Vương Lâm phát hiện mảnh xương thú ghi đan phương Niết Không đan, chấn động nhận ra giá trị cực cao đủ gây kiếp nạn cho Tu Chân giới.","anchor":"hắn nhìn mảnh xương thú nhỏ trong tay mà nửa ngày sau vẫn chưa nói lên lời"}]},"chuSoHuu":[{"ten":"Thi Lạc Hình","tuChuong":"@c1083","denChuong":"@c1083","cachCoDuoc":"Không rõ nguồn gốc ban đầu","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1083","denChuong":"","cachCoDuoc":"Luyện hóa hài cốt đệ tử để tìm ra","trangThai":"dang-co"}],"uyLuc":"Giá trị đủ khiến tu sĩ Tịnh Niết đại viên mãn và lão quái trong Thiên Nhân Suy Kiếp sẵn sàng liều mạng tranh đoạt, đủ gây kiếp nạn cho Tu Chân giới.","dacDiem":"Mảnh xương thú nhỏ như bàn tay, trên khắc ghi đan phương Niết Không đan.","congNang":["Ghi chép đan phương luyện chế Niết Không đan @c1083","Đan luyện thành giúp nắm chắc một phần quy tắc hóa bản nguyên, trở thành tu sĩ Đệ Tam Bộ","Nắm chắc năm phần vượt qua lần suy kiếp đầu tiên của Thiên Nhân","Nắm chắc tám phần tiến vào cảnh giới Nhập Thần"]},{"id":"manh-xuong-thu-nho-thi-lac-hinh","name":"Mảnh xương thú nhỏ (Thi Lạc Hình tìm được)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thi Lạc Hình"],"trangThai":"Mất tích sau khi Thi Lạc Hình chết","blurb":"Mảnh xương thú nhỏ và ngọc giản mà Thi Lạc Hình lấy được ở tinh vực cấp ba, chứa đầu mối liên quan phương pháp luyện Niết Không Đan. Hiện mất tích sau khi hắn bị Ngũ Độc Môn giết.","detail":"Thi Lạc Hình dẫn 19 đệ tử đến tinh vực cấp ba, thành công tìm được mảnh xương thú nhỏ kèm một khối ngọc giản, đều liên quan đến phương pháp luyện Niết Không Đan trong truyền thuyết. Trên đường mang về Hoa Thanh Tông thì bị Ngũ Độc Môn đuổi giết, vật phẩm hiện không rõ tung tích.","congNang":["Manh mối dẫn đến phương pháp luyện Niết Không Đan"],"chuSoHuu":[{"ten":"Thi Lạc Hình","tuChuong":"@c1084","denChuong":"@c1084","cachCoDuoc":"Tìm được ở tinh vực cấp ba","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1084","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Thi Lạc Hình tìm thấy rồi mất tích","text":"Thi Lạc Hình lấy được mảnh xương thú nhỏ và ngọc giản ở tinh vực cấp ba, nhưng bị Ngũ Độc Môn đuổi giết trên đường về, vật phẩm hiện mất tích.","anchor":"Hắn lấy được một mảnh xương thú nhỏ và một khối ngọc giản"}]},"nguon":["@c1084"]},{"id":"ba-vat-pham-hai-cot-khe-nut","name":"Ba vật phẩm từ hài cốt trong khe nứt không gian","cn":"","category":"khac","categoryLabel":"Bộ vật phẩm","phamCap":"Cực cao (tranh đoạt toàn tinh vực)","soHuu":["Phá Thiên Tông"],"trangThai":"Phân tán: đan dược + tàn kiếm bị dâng cho tông phái cấp chín; mảnh xương thú biến mất","blurb":"Bộ ba vật phẩm phát hiện bên cạnh hài cốt bí ẩn trong khe nứt không gian mười vạn tám ngàn năm trước: một viên đan dược, một thanh tàn kiếm, một mảnh xương thú chứa phương pháp luyện Niết Không Đan.","detail":"Mười vạn tám ngàn năm trước, Phá Thiên Tông (cấp tám) phát hiện khe nứt không gian dày đặc cấm chế, bên trong có bộ hài cốt kèm ba vật phẩm. Tin tức bị phản đồ truyền ra, dẫn đến toàn bộ tông phái cấp tám tranh đoạt, tinh vực cấp chín phải can thiệp. Phá Thiên Tông phân liệt: phần lớn dâng đan dược và tàn kiếm đổi lấy sinh tồn; phần nhỏ mang mảnh xương thú chiến đấu rồi biến mất.","congNang":["Viên đan dược và thanh tàn kiếm có giá trị cực cao khiến tông phái cấp chín phải ra tay","Mảnh xương thú chứa phương pháp luyện Niết Không Đan"],"laBo":true,"thanhVien":[{"id":"manh-xuong-thu-dan-phuong-niet-khong-dan","vaiTro":"Mảnh xương thú gốc chứa phương pháp luyện đan"}],"chuSoHuu":[{"ten":"Phá Thiên Tông","tuChuong":"@c1084","denChuong":"","cachCoDuoc":"Phát hiện trong khe nứt không gian","trangThai":"phan-tan"}],"tabs":{"tienTrinh":[{"chuong":"@c1084","loai":"xuat-hien","importance":"major","giaiDoan":"Phát hiện và tranh đoạt","text":"Phá Thiên Tông phát hiện ba vật phẩm bên hài cốt trong khe nứt không gian, tin bị lộ dẫn đến đại chiến toàn Vân Hải Tinh Vực, tông phái phân liệt, mảnh xương thú biến mất.","anchor":"Bên cạnh bộ hài cốt kia có ba vật phẩm, một viên đan dược, một thanh tàn kiếm, một mảnh xương thú"}]},"nguon":["@c1084"]},{"id":"phat-tran-trang-tien-quy-chung","name":"Phất trần trắng (Tiền Quý Chung)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tiền Quý Chung"],"trangThai":"dang-co","blurb":"Pháp bảo của Tiền Quý Chung, lấy từ vết nứt hư không, thi triển quy tắc thiên địa hóa bạch quang mưa kiếm có thể xuyên đùi Vương Lâm qua cả khôi giáp.","detail":"Tiền Quý Chung xé vết nứt hư không trước mặt lấy ra cây phất trần màu trắng, vung đập thi triển quy tắc thiên địa hóa bạch quang mưa kiếm tấn công Vương Lâm, xuyên đùi phải hắn qua cả lớp khôi giáp đỏ máu.","congNang":["Triệu quy tắc thiên địa hóa mưa kiếm bạch quang tấn công diện rộng"],"chuSoHuu":[{"ten":"Tiền Quý Chung","tuChuong":"@c1085","denChuong":"","cachCoDuoc":"Cất giữ trong vết nứt hư không","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1085","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Tiền Quý Chung xé vết nứt hư không lấy ra phất trần trắng, thi triển quy tắc thiên địa hóa bạch quang mưa kiếm tấn công Vương Lâm, xuyên đùi phải hắn.","anchor":"trước mặt hắn xuất hiện một vết nứt. Trong vết nứt bay ra một cây phất trần màu trắng"}]},"nguon":["@c1085"]},{"id":"truong-thuong-den-tien-quy-chung","name":"Trường thương đen (Tiền Quý Chung)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tiền Quý Chung"],"trangThai":"dang-co","blurb":"Pháp bảo của Tiền Quý Chung, hiện ra từ mãng xà đầu đen bên dưới, lao về phía Vương Lâm bị Phong Tiên Ấn chặn lại.","detail":"Tiền Quý Chung bấm pháp quyết, mãng xà đầu đen bên dưới lấp lánh hào quang hiện ra cây trường thương màu đen lao về phía Vương Lâm, bị Phong Tiên Ấn mười tám tầng địa ngục chặn đỡ.","congNang":["Tấn công tầm xa, lao thẳng về đối thủ"],"chuSoHuu":[{"ten":"Tiền Quý Chung","tuChuong":"@c1085","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1085","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Tiền Quý Chung triệu trường thương đen từ mãng xà đầu đen tấn công Vương Lâm, bị Phong Tiên Ấn chặn lại gây phản chấn.","anchor":"Một cây trường thương màu đên hiện lên rồi điên cuồng lao về phía Vương Lâm"}]},"nguon":["@c1085"]},{"id":"khoi-giap-do-mau","name":"Khôi giáp đỏ máu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bộ khôi giáp phòng ngự huyễn hóa trên người Vương Lâm khi mắt trái bùng lửa, cứu mạng hắn trước đòn mưa kiếm bạch quang Toái Niết của Tiền Quý Chung.","detail":"Khi bị mưa kiếm bạch quang từ phất trần trắng của Tiền Quý Chung tấn công, mắt trái Vương Lâm bùng lửa và một bộ khôi giáp màu đỏ máu huyễn hóa ra trên người phòng ngự toàn thân. Nếu không có khôi giáp này, Vương Lâm đã chết.","congNang":["Phòng ngự toàn thân, huyễn hóa từ mắt trái bùng lửa"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1085","denChuong":"","cachCoDuoc":"Huyễn hóa từ mắt trái","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1085","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Khôi giáp đỏ máu huyễn hóa trên người Vương Lâm khi bị mưa kiếm bạch quang tấn công, cứu mạng hắn trước đòn Toái Niết.","anchor":"một bộ khôi giáp màu đỏ máu đột nhiên huyễn hóa ra trên người hắn"}]},"nguon":["@c1085"]},{"id":"phat-tran-tien-quy-chung","name":"Phất trần Tiền Quý Chung","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tiền Quý Chung"],"trangThai":"da-huy","blurb":"Pháp bảo của Tiền Quý Chung, cuốn quanh nguyên thần khi thoát thân, nổ tung hóa thành sợi tơ trắng tấn công Chu Tước. Sợi tơ trắng xuyên vào ngực Vương Lâm gây thương tích kéo dài ba ngày.","detail":"Khi nguyên thần Tiền Quý Chung thoát ra, phất trần cuốn quanh bảo vệ. Trong lúc tuyệt vọng, Tiền Quý Chung tự bạo phất trần, nổ tung hóa thành vô số sợi tơ trắng tấn công Chu Tước (Vương Lâm). Sợi tơ trắng xuyên vào ngực Vương Lâm, phải mất ba ngày mới rút hết tàn dư bóp nát thành tro.","nguon":["@c1086"]},{"id":"kiem-su-thu-cap-tam","name":"Kiếm Sư Thú cấp tám","category":"khac","categoryLabel":"Hung thú","phamCap":"Cấp tám","soHuu":[],"trangThai":"bi-tieu-diet","blurb":"Hung thú sư tử toàn thân gai nhọn dài hai trăm trượng, cấp tám, bị Vương Lâm một đòn húc nổ tan thành sương máu.","detail":"Kiếm Sư Thú là hung thú sư tử khổng lồ dài hai trăm trượng, toàn thân phủ gai nhọn, uy lực đạt cấp tám. Khi xuất hiện, các mãnh thú khác đều tản ra không dám đến gần. Bị Vương Lâm xông lên như lưu tinh, dùng đùi phải húc thẳng, một đòn nổ tan thành sương máu. Sinh cơ khổng lồ từ thân thể nó bị Vương Lâm hấp thu.","nguon":["@c1089"]},{"id":"ngoc-gian-tu-ma-mac","name":"Ngọc giản Tư Mã Mặc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản mang tên Tư Mã Mặc là pháp bảo lưu trữ một phương pháp luyện đan đặc biệt. Tin tức về nó truyền ra gây chấn động từ tinh vực cấp bảy đến cấp tám, khiến Phá Thiên Tông cấp chín phải cử người truy tìm.","detail":"Ngọc giản được gọi bằng tên Tư Mã Mặc, sư huynh của sư tổ Phá Thiên Tông. Vật này chứa đựng một phương pháp luyện đan đặc biệt. Khi tin tức về ngọc giản cùng phương pháp luyện đan truyền ra, nó kinh động tinh vực cấp bảy và cấp tám, thu hút nhiều tu sĩ mạnh đổ về (@c1090). Phá Thiên Tông đã cử Lý Thiến Mai (Toái Niết hậu kỳ) đi truy tìm kẻ đoạt ngọc giản.","nguonGoc":"Thuộc về Tư Mã Mặc, sư huynh của sư tổ Phá Thiên Tông","congNang":["Chứa đựng một phương pháp luyện đan đặc biệt @c1090"],"chuSoHuu":[{"ten":"Tư Mã Mặc","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ nhân gốc","trangThai":"khong-ro"},{"ten":"Vương Lâm","tuChuong":"@c1059","denChuong":"","cachCoDuoc":"Thu được từ thi thể Cổ Thần","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1090","loai":"nhac-toi","importance":"major","giaiDoan":"Tin tức lan rộng, Phá Thiên Tông truy tìm","text":"Tin tức về ngọc giản Tư Mã Mặc và phương pháp luyện đan truyền ra kinh động tinh vực cấp bảy, cấp tám. Phá Thiên Tông cấp chín cử Lý Thiến Mai (Toái Niết hậu kỳ) truy tìm kẻ đoạt ngọc giản ở tinh vực cấp năm.","anchor":"Ngọc giản Tư Mã Mặc xuất hiện, ngươi hãy đi đến những tinh vực cấp năm truy tìm kẻ đoạt được ngọc giản"}]},"nguon":["@c1090"]},{"id":"ngoc-gian-dau-an-tu-ma-mac","name":"Ngọc giản (dấu ấn Tư Mã Mặc)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chứa dấu ấn / lệnh bài của Tư Mã Mặc, đại đệ tử Phá Thiên Tông. Mang về Phá Thiên Tông sẽ được chưởng môn thu làm đệ tử.","detail":"Tìm thấy cùng chỗ với mảnh xương thú đan phương Niết Không Đan. Không ghi thần thông hay công pháp, chỉ chứa dấu ấn của Tư Mã Mặc. Chưởng môn Phá Thiên Tông để lại truyền thừa vài vạn năm: ai mang lệnh bài này trở về sẽ được thu làm đệ tử. Vương Lâm nhận định ngọc giản sẽ có tác dụng rất lớn cho tương lai.","congNang":["Lệnh bài nhập môn Phá Thiên Tông — mang về sẽ được chưởng môn thu làm đệ tử"],"chuSoHuu":[{"ten":"Tư Mã Mặc","tuChuong":"","denChuong":"","cachCoDuoc":"Sở hữu gốc","trangThai":"mat-tich"},{"ten":"Vương Lâm","tuChuong":"@c1091","denChuong":"","cachCoDuoc":"Tìm được cùng mảnh xương thú","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1091","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm dò xét và xác định lai lịch","text":"Vương Lâm dùng thần thức dò xét ngọc giản, kết hợp ký ức Sưu Hồn từ Độc Bà Tử xác định đây là dấu ấn / lệnh bài Tư Mã Mặc, đại đệ tử Phá Thiên Tông 10 vạn 8 ngàn năm trước.","anchor":"Sau này nếu người nào mang lệnh bài của Tư Mã Mặc về Phá Thiên Tông thì sẽ được chưởng môn thu làm đệ tử"}]},"nguon":["@c1091"]},{"id":"ly-hon-dan-cap-tam-moi","name":"Ly Hồn Đan cấp 8 (Vương Lâm luyện)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp 8","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ly Hồn Đan cấp 8 do Vương Lâm luyện từ thú hồn mãnh thú cấp 8, thất bại 3 lần mới thành công. Thú hồn tiêu tán quá nửa nên hiệu quả giảm.","detail":"Vương Lâm dùng hồn phách mãnh thú cấp 8 luyện Ly Hồn Đan, thất bại 3 lần mới thành. Do thú hồn đã tiêu tán hơn nửa nên hiệu quả bị giảm. Là viên đan cuối cùng còn lại khi hắn tỉnh dậy sau cảm ngộ, chưa nuốt.","congNang":["Cảm ngộ pháp tắc thiên địa khi nuốt (suy đoán từ đan cấp thấp hơn)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1091","denChuong":"","cachCoDuoc":"Tự luyện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1091","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện thành sau 3 lần thất bại","text":"Vương Lâm dùng thú hồn mãnh thú cấp 8 luyện Ly Hồn Đan, thất bại 3 lần mới thành. Thú hồn tiêu tán quá nửa nên hiệu quả giảm. Chưa nuốt.","anchor":"Sau ba lần thất bại, cuối cùng hắn cũng đã đem hồn phách này dung hợp vào đan dược tạo thành một Ly Hồn Đan cấp tám"}]},"nguon":["@c1091"]},{"id":"ngu-tinh-thao","name":"Ngư Tinh Thảo","cn":"","category":"nguyen-lieu","categoryLabel":"Dược thảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Loại cỏ độc chỉ sinh trưởng ở sào huyệt mãnh thú cấp sáu, không thể sống ở nơi khác.","detail":"Cỏ độc đặc biệt chỉ sinh trưởng ở sào huyệt mãnh thú cấp sáu, không thể sống ở bất kỳ nơi nào khác. Trừu Hải phát hiện mùi Ngư Tinh Thảo rất mới trên người Tôn Vân, truy vấn nguồn gốc. Lữ Yến Phỉ giải thích do sư thúc tổ (Vương Lâm) mang về. Manh mối cho thấy Vương Lâm đã vào sào huyệt mãnh thú cấp sáu.","congNang":["Dược thảo có tính độc, chỉ mọc ở sào huyệt mãnh thú cấp sáu"],"tabs":{"tienTrinh":[{"chuong":"@c1092","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phát hiện trên người Tôn Vân","text":"Trừu Hải phát hiện mùi Ngư Tinh Thảo trên người Tôn Vân, truy vấn nguồn gốc. Lữ Yến Phỉ nói do sư thúc tổ mang về.","anchor":"Loại cỏ độc này chỉ sinh trưởng ở sào huyệt của mãnh thú xấp sáu, không thể sống ở bất kỳ nơi nào khác"}]},"nguon":["@c1092"]},{"id":"ong-sao-xanh-biec","name":"Ống sáo xanh biếc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo/vật phẩm","phamCap":"không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"đang được Lý Thiến Mai cầm theo","blurb":"Ống sáo xanh biếc Lý Thiến Mai cầm khi xuất hiện chặn đường Tử Đạo Tông.","detail":"Khi Lý Thiến Mai đứng trên Linh long lam sắc, nàng cầm một ống sáo xanh biếc trong tay. Chương này chỉ cho thấy hình dáng và người cầm, chưa nêu công năng hay phẩm cấp.","phanLoaiPhu":"sáo","hinhDang":"ống sáo xanh biếc","chuHienThoi":"Lý Thiến Mai","chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1094","denChuong":"","cachCoDuoc":"cầm theo khi xuất hiện","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1094","loai":"xuất hiện","importance":"normal","giaiDoan":"Lý Thiến Mai chặn đường Tử Đạo Tông","text":"Ống sáo xanh biếc xuất hiện trong tay Lý Thiến Mai khi nàng cưỡi Linh long lam sắc chặn đường đoàn Tử Đạo Tông.","anchor":"Đôi bàn tay nàng trắng sáng như ngọc, nàng cầm theo một ống sáo xanh biếc"}]},"capNhatToi":"@c1094","nguon":["@c1094"]},{"id":"cuc-tai-dan","name":"Cực Tài Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"cấp mười, bán thành phẩm","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Cực Tài Đan là đan dược bán thành phẩm cấp mười do Lý Thiến Mai trao cho Vương Lâm. Đan này dùng để chữa thương và cần luyện hóa thêm mới thành đan dược chân chính.","detail":"Lý Thiến Mai dùng Cực Tài Đan để đổi lấy lời giải đáp câu hỏi thứ nhất của Vương Lâm. Đây là đan dược cấp cao nhất trên người nàng lúc đó, không phải Ly Hồn Đan mà là đan chữa thương ở dạng bán thành phẩm.","phanLoaiPhu":"đan dược chữa thương","congNang":["Dùng để chữa thương @c1096"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1096","denChuong":"@c1096","cachCoDuoc":"sở hữu trước khi trao đổi","trangThai":"đã trao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1096","denChuong":"","cachCoDuoc":"nhận từ Lý Thiến Mai để đổi lấy lời giải đáp câu hỏi thứ nhất","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1096","loai":"đổi chủ","importance":"normal","giaiDoan":"Trao đổi hỏi đạo","text":"Lý Thiến Mai trao Cực Tài Đan bán thành phẩm cấp mười cho Vương Lâm để đổi lấy lời giải đáp câu hỏi thứ nhất.","phamCap":"cấp mười, bán thành phẩm","anchor":"Đan dược cao nhất là cấp mười nhưng không phải Ly Hồn Đan mà chỉ là Cực Tài Đan dùng để chữa thương mà thôi"}]},"capNhatToi":"@c1096","nguon":["@c1096"]},{"id":"ngoc-gian-luyen-dan-cua-ly-thien-mai","name":"Ngọc giản luyện đan của Lý Thiến Mai","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lý Thiến Mai","Vương Lâm"],"trangThai":"Vương Lâm nhận từ Lý Thiến Mai","blurb":"Ngọc giản do Lý Thiến Mai trao cho Vương Lâm sau cuộc luận đạo tại Mạc La đại lục.","detail":"Trong ngọc giản ghi rõ đan dược bán thành phẩm chứa linh hồn mãnh thú cấp mười, các loại dược thảo và phương pháp luyện đan liên quan.","phanLoaiPhu":"ngọc giản luyện đan","chuHienThoi":"Vương Lâm","congNang":["Ghi lại phương pháp luyện đan, dược thảo và thông tin về đan dược bán thành phẩm có chứa linh hồn mãnh thú cấp mười."],"chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1097","denChuong":"@c1097","cachCoDuoc":"người trao vật","trangThai":"đã trao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1097","denChuong":"","cachCoDuoc":"được Lý Thiến Mai trao sau khi luận đạo","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1097","loai":"xuất hiện","importance":"normal","giaiDoan":"Trao ngọc giản","text":"Lý Thiến Mai trao cho Vương Lâm ngọc giản ghi phương pháp luyện đan và thông tin về đan dược bán thành phẩm chứa linh hồn mãnh thú cấp mười.","anchor":"đan dược bán thành phẩm có chứa linh hồn của mãnh thú cấp mười, những loại dược thảo và phương pháp luyện đan đều được ghi rõ trong ngọc giản"}]},"capNhatToi":"@c1097","nguon":["@c1097"]},{"id":"ban-do-tinh-cau","name":"Bản đồ tinh cầu","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Quý hiếm tại Vân Hải tinh vực","soHuu":[],"trangThai":"được Vương Lâm tìm kiếm","blurb":"Bản đồ tinh cầu là vật chỉ đường cực quý trong Vân Hải tinh vực, nơi sương mù khiến việc di chuyển vô cùng khó khăn. Vương Lâm đến Bồng Lai một phần vì muốn tìm loại bản đồ này.","detail":"Bản đồ tinh cầu thường là bí mật của tông phái, chế tạo tốn nhiều tâm huyết và phải nghiệm chứng thật giả. Việc giao dịch bản đồ ngày càng ít vì dễ bị lừa bằng bản đồ giả hoặc vị trí nguy hiểm.","congNang":["Chỉ dẫn đường đi trong sương mù Vân Hải tinh vực @c1098"],"dacDiem":"Thường được tông phái giữ kín, khó mua bán công khai và dễ bị làm giả.","chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c1098","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu tại Bồng Lai","text":"Vương Lâm đồng ý đến Bồng Lai vì đặt hy vọng tìm được bản đồ tinh cầu, loại vật giúp đi lại trong sương mù Vân Hải.","anchor":"bản đồ tinh cầu thường là những vật tuyệt mật của môn phái"}]},"capNhatToi":"@c1098","nguon":["@c1098"]},{"id":"nguyen-tinh","name":"Nguyên tinh","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm đặc biệt","phamCap":"không rõ","soHuu":[],"trangThai":"đang lưu thông","blurb":"Nguyên tinh là vật phẩm đặc biệt của Vân Hải tinh vực, được tu sĩ Đệ Nhị Bộ ưa thích vì có thể nhanh chóng hồi phục nguyên lực và hỗ trợ tu luyện. Trong khu chợ Bồng Lai, một lão già rao đổi một khối nguyên tinh lấy bảy mươi khối tiên ngọc.","detail":"Nguyên tinh hình thành từ mãnh thú cấp mười hai sau khi hóa thân vào sương mù và cần thời gian sinh trưởng rất lâu. Nó có thể giúp hấp thu hồi phục nguyên lực nhanh, tăng tốc tu luyện, đồng thời dùng tế luyện pháp bảo và trận pháp để tăng uy lực; chỉ các tông phái cấp tám trở lên mới có thực lực tạo ra.","phanLoaiPhu":"vật phẩm tu luyện","nguonGoc":"Vân Hải tinh vực","congNang":["Hấp thu để hồi phục nguyên lực nhanh và tăng tốc tu luyện @c1099","Dùng tế luyện pháp bảo hoặc trận pháp để tăng uy lực @c1099"],"tabs":{"tienTrinh":[]},"nguon":["@c1099"]},{"id":"huyet-tinh-kiem","name":"Huyết Tinh Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Được Đạo Dã Tử khai quang","soHuu":["Thiếu phụ áo hoa"],"trangThai":"đã bán cho Thiếu phụ áo hoa","blurb":"Huyết Tinh Kiếm là thanh kiếm trong suốt có tơ máu, được Thương Tùng Tử đưa ra giao dịch. Kiếm được luyện từ máu hàng ngàn hung thú cấp tám, có kịch độc hại nguyên thần.","detail":"Thanh kiếm này do Thương Tùng Tử mang ra trong buổi tụ họp tư nhân, được giới thiệu là dùng máu tươi của hàng ngàn hung thú cấp tám để luyện thành và từng được Đạo Dã Tử khai quang để tăng uy lực. Bên trong kiếm ẩn chứa kịch độc có thể gây hại cả nguyên thần, sau đó được thiếu phụ áo hoa mua bằng truyền âm.","phanLoaiPhu":"phi kiếm","hinhDang":"thanh kiếm trong suốt có tơ máu","nguonGoc":"luyện từ máu hàng ngàn hung thú cấp tám","uyLuc":"Ẩn chứa kịch độc có thể hại nguyên thần và được Đạo Dã Tử khai quang tăng uy lực.","dacDiem":"Trong suốt, có tơ máu, chuyên sát thương và gây độc nguyên thần.","chuHienThoi":"Thiếu phụ áo hoa","capNhatToi":"@c1102","congNang":["Gây sát thương bằng phi kiếm và kịch độc có thể hại cả nguyên thần @c1102"],"chuSoHuu":[{"ten":"Thiếu phụ áo hoa","tuChuong":"@c1102","denChuong":"","cachCoDuoc":"mua từ Thương Tùng Tử bằng truyền âm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1102","loai":"đổi chủ","importance":"normal","giaiDoan":"Được đưa ra giao dịch","text":"Thương Tùng Tử giới thiệu Huyết Tinh Kiếm là kiếm luyện từ máu hung thú cấp tám và đã được Đạo Dã Tử khai quang. Thiếu phụ áo hoa xem xét rồi mua thanh kiếm này bằng truyền âm.","anchor":"thanh kiếm này lão phu đã giết hàng ngàn hung thú cấp tám rồi dùng tất cả máu tươi để luyện thành","phamCap":"Được Đạo Dã Tử khai quang"}]},"nguon":["@c1102"]},{"id":"bo-tan-giap","name":"Bộ tàn giáp","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Giáp / vật liệu","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Bộ tàn giáp là mảnh giáp vỡ tràn đầy khí tức tang thương, được Thương Tùng Tử lấy ra trong buổi tụ họp. Vật này có chất liệu giống xương nhưng không phải xương, bên trên còn ghi thần thông tàn khuyết.","detail":"Thương Tùng Tử đưa bộ tàn giáp ra không hẳn để bán mà muốn mọi người xem có nhận ra lai lịch của nó hay không. Không ai hỏi mua, Vương Lâm ra giá một trăm tiên ngọc nhưng được Thương Tùng Tử tặng miễn phí; hắn chú ý đến chất liệu kỳ lạ của giáp hơn là thần thông tàn khuyết khắc trên đó.","phanLoaiPhu":"giáp vỡ / vật liệu lạ","hinhDang":"mảnh giáp vỡ tràn đầy khí tức tang thương","vatLieu":"giống xương nhưng nhìn kỹ lại không giống","uyLuc":"Chưa rõ uy lực trực tiếp, giá trị nằm ở chất liệu lạ và thần thông tàn khuyết ghi bên trên.","dacDiem":"Có thần thông tàn khuyết không thể tu luyện trọn vẹn, chất liệu khiến Vương Lâm đặc biệt chú ý.","chuHienThoi":"Vương Lâm","capNhatToi":"@c1102","congNang":["Mang một bộ thần thông tàn khuyết khắc trên giáp @c1102"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1102","denChuong":"@c1102","cachCoDuoc":"đem ra trong buổi tụ họp","trangThai":"đã tặng"},{"ten":"Vương Lâm","tuChuong":"@c1102","denChuong":"","cachCoDuoc":"được Thương Tùng Tử tặng miễn phí","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1102","loai":"đổi chủ","importance":"normal","giaiDoan":"Được tặng cho Vương Lâm","text":"Bộ tàn giáp được Thương Tùng Tử đưa ra để mọi người nhận định lai lịch. Khi Vương Lâm tỏ ý muốn mua, Thương Tùng Tử tặng luôn cho hắn.","anchor":"Mảnh giáp này giống như được làm từ xương nhưng nhìn kỹ lại thấy không giống","phamCap":"không rõ"}]},"nguon":["@c1102"]},{"id":"hon-nguyen-dan","name":"Hỗn Nguyên Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"cực cao, giá năm vạn tiên ngọc","soHuu":["Thanh niên văn sĩ cầm quạt lông"],"trangThai":"đã bán cho Thanh niên văn sĩ cầm quạt lông","blurb":"Hỗn Nguyên Đan là viên đan dược đen kịt không có mùi thuốc, được Thương Tùng Tử đưa ra giao dịch. Nó có thể uy hiếp tu sĩ Toái Niết, nhưng một viên đơn lẻ bị lão già áo đen nhận xét là uy lực chưa đủ.","detail":"Viên đan dược đen có dao động bên trong, ban đầu được văn sĩ trung niên trả giá năm trăm tiên ngọc, nhưng Thương Tùng Tử đòi giá gấp trăm lần. Sau khi được xác nhận là Hỗn Nguyên Đan, nó được mua với giá năm vạn tiên ngọc.","phanLoaiPhu":"đan dược công kích","hinhDang":"viên đan dược đen kịt không có mùi thuốc","uyLuc":"Có thể uy hiếp tu sĩ Toái Niết, nhưng một viên đơn lẻ chưa đủ tạo uy lực trọn vẹn.","dacDiem":"Không có mùi thuốc, bên trong có dao động.","chuHienThoi":"Thanh niên văn sĩ cầm quạt lông","capNhatToi":"@c1102","congNang":["Có thể uy hiếp tu sĩ Toái Niết @c1102"],"chuSoHuu":[{"ten":"Thanh niên văn sĩ cầm quạt lông","tuChuong":"@c1102","denChuong":"","cachCoDuoc":"mua từ Thương Tùng Tử với giá năm vạn tiên ngọc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1102","loai":"đổi chủ","importance":"normal","giaiDoan":"Được bán giá cao","text":"Hỗn Nguyên Đan được Thương Tùng Tử đưa ra giao dịch và được thanh niên văn sĩ mua với giá năm vạn tiên ngọc.","anchor":"viên đan dược này lại thật sự là Hỗn Nguyên Đan có thể uy hiếp tu sĩ Toái Niết","phamCap":"cực cao, giá năm vạn tiên ngọc"}]},"nguon":["@c1102"]},{"id":"long-chu-tuoc","name":"Lông Chu Tước","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Linh vật","phamCap":"không rõ","soHuu":["Lão già áo đen tay vuốt ưng"],"trangThai":"đang được rao giao dịch","blurb":"Lông Chu Tước là sợi lông chim đỏ tươi do lão già áo đen tay vuốt ưng lấy ra giao dịch. Vật này tỏa ngọn lửa nồng đậm hiếm thấy, khiến Vương Lâm chấn động trong lòng.","detail":"Lão già áo đen tay vuốt ưng giới thiệu vật đầu tiên của mình là lông Chu Tước năm xưa, tuy khó phân biệt thật giả nhưng hỏa diễm trên đó rất nồng đậm. Vương Lâm nhìn thấy sợi lông thì tâm thần chấn động, song vẫn che giấu hoàn hảo.","phanLoaiPhu":"linh vật hỏa hệ","hinhDang":"sợi lông chim màu đỏ tươi","dacDiem":"Mang ngọn lửa nồng đậm hiếm thấy, thật giả khó phân biệt.","chuHienThoi":"Lão già áo đen tay vuốt ưng","capNhatToi":"@c1102","congNang":["Chứa ngọn lửa nồng đậm liên quan đến Chu Tước @c1102"],"chuSoHuu":[{"ten":"Lão già áo đen tay vuốt ưng","tuChuong":"@c1102","denChuong":"","cachCoDuoc":"mang ra trong buổi tụ họp để giao dịch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1102","loai":"xuất hiện","importance":"normal","giaiDoan":"Được đưa ra giao dịch","text":"Lão già áo đen tay vuốt ưng lấy lông Chu Tước ra giao dịch, khiến Vương Lâm chấn động nhưng không để lộ phản ứng.","anchor":"Vật đầu tiên chính là lông của Chu Tước năm xưa, dù khó phân biệt thật giả nhưng ngọn lửa bên trên lại nồng đậm hiếm thấy","phamCap":"không rõ"}]},"nguon":["@c1102"]},{"id":"linh-hon-hung-thu-cap-12-nua-hoa-suong","name":"Linh hồn hung thú cấp 12 nửa hóa sương","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Thú hồn","phamCap":"hung thú cấp mười hai","soHuu":["Lão già áo đen tay vuốt ưng"],"trangThai":"đang được rao giao dịch","blurb":"Linh hồn hung thú cấp 12 nửa hóa sương là thú hồn bị nhốt trong bọt khí to như đầu người. Nửa trên của nó có hình rồng, nửa dưới hóa thành sương mù, khiến Ngô Thanh tiếc rằng chưa hoàn toàn hóa sương.","detail":"Lão già áo đen tay vuốt ưng lấy thú hồn này ra sau lông Chu Tước. Nó là linh hồn hung thú cấp mười hai đã có một nửa hóa sương, đang gầm rống trong bọt khí; khi Ngô Thanh tiếc rẻ, lão đáp rằng nếu là mãnh thú hóa sương hoàn toàn thì đã không đem ra giao dịch.","phanLoaiPhu":"thú hồn","hinhDang":"nửa trên hình rồng, nửa dưới hóa sương mù, bị nhốt trong bọt khí","dacDiem":"Chỉ mới một nửa hóa sương, chưa đạt trạng thái hoàn toàn hóa sương.","chuHienThoi":"Lão già áo đen tay vuốt ưng","capNhatToi":"@c1102","congNang":["Là thú hồn cấp mười hai đã nửa hóa sương @c1102"],"chuSoHuu":[{"ten":"Lão già áo đen tay vuốt ưng","tuChuong":"@c1102","denChuong":"","cachCoDuoc":"mang ra trong buổi tụ họp để giao dịch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1102","loai":"xuất hiện","importance":"normal","giaiDoan":"Được đưa ra giao dịch","text":"Lão già áo đen tay vuốt ưng trưng bày linh hồn hung thú cấp mười hai nửa hóa sương và nói rằng nếu hoàn toàn hóa sương thì ông đã không đem ra giao dịch.","anchor":"linh hồn hung thú cấp mười hai đã có một nửa hóa sương","phamCap":"hung thú cấp mười hai"}]},"nguon":["@c1102"]},{"id":"thu-hon-manh-thu-cap-muoi-hai","name":"Thú hồn mãnh thú cấp mười hai","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh vật","phamCap":"cấp 12","soHuu":["Bà lão áo xanh"],"trangThai":"đã đổi chủ","blurb":"Thú hồn mãnh thú cấp mười hai đã nhuyên nhân hóa sương, có giá trị rất cao trong buổi tụ hội. Bà lão áo xanh mua được bằng ngọc giản, bản đồ tinh cầu và mười vạn tiên ngọc.","detail":"Lão già hắc y gầy khô đưa thú hồn này ra giao dịch, nhiều tu sĩ động tâm nhưng giá quá cao. Bà lão áo xanh cuối cùng dùng vật trao đổi cộng thêm mười vạn tiên ngọc để lấy nó.","congNang":["Thú hồn mãnh thú có thể dùng cho tu luyện hoặc nuôi thú @c1103"],"chuSoHuu":[{"ten":"Lão già hắc y gầy khô","tuChuong":"@c1103","denChuong":"@c1103","cachCoDuoc":"Đem ra giao dịch trong buổi tụ hội","trangThai":"đã chuyển đi"},{"ten":"Bà lão áo xanh","tuChuong":"@c1103","denChuong":"","cachCoDuoc":"Đổi bằng ngọc giản, bản đồ tinh cầu và mười vạn tiên ngọc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1103","loai":"đổi chủ","importance":"normal","giaiDoan":"Giao dịch thú hồn","text":"Thú hồn mãnh thú cấp mười hai được bà lão áo xanh mua từ lão già hắc y gầy khô với giá rất cao.","anchor":"mãnh thú cấp mười hai cũng động tâm, nhưng giá trị của nó quá xa xỉ","phamCap":"cấp 12"}]},"capNhatToi":"@c1103","nguon":["@c1103"]},{"id":"long-vu-chu-tuoc","name":"Lông vũ Chu Tước","cn":"","aliases":["chiếc lông vũ màu đỏ"],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Ngô Thanh","Vương Lâm","Đỗ Đức"],"trangThai":"Đã dung nhập vào mắt trái Vương Lâm @c1105","blurb":"Lông vũ mang danh Chu Tước được đưa ra đấu giá trong buổi tụ hội, nhưng không phải chính phẩm vì lông thật của Chu Tước sẽ bốc cháy khi Chu Tước chết. Ngô Thanh cố ý nâng giá rồi mua được món này.","detail":"Vương Lâm coi lông vũ này là vật cần thiết nhưng nhận ra Ngô Thanh cố ý thăm dò tài lực nên từ bỏ. Ngô Thanh lấy được với giá năm vạn năm ngàn tiên ngọc.","dacDiem":"Không phải chính phẩm; lông vũ thật của Chu Tước sẽ bốc cháy khi Chu Tước chết.","chuHienThoi":"Ngô Thanh","chuSoHuu":[{"ten":"Lão già hắc y gầy khô","tuChuong":"@c1103","denChuong":"@c1103","cachCoDuoc":"Đem ra đấu giá công khai","trangThai":"đã chuyển đi"},{"ten":"Ngô Thanh","tuChuong":"@c1103","denChuong":"","cachCoDuoc":"Mua với giá năm vạn năm ngàn tiên ngọc sau khi nâng giá","trangThai":"đang giữ"},{"ten":"Đỗ Đức","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Đoạt được từ Man Hoang đại lục tinh vực cấp sáu","trangThai":"không còn giữ"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Thu được từ túi trữ vật sau biến cố Ngô Thanh","trangThai":"đã dung nhập mắt trái"}],"tabs":{"tienTrinh":[{"chuong":"@c1103","loai":"đổi chủ","importance":"normal","giaiDoan":"Đấu giá lông vũ","text":"Lông vũ Chu Tước bị nhiều người tranh mua, cuối cùng rơi vào tay Ngô Thanh sau khi lão cố ý nâng giá khiến Vương Lâm bỏ cuộc.","anchor":"Năm xưa khi Chu Tước chết thì lông vũ khắp toàn thân đều bốc cháy, lông vũ trước mặt rõ ràng cũng không phải là chính phẩm","phamCap":"không rõ"},{"chuong":"@c1105","loai":"khai phong","importance":"normal","giaiDoan":"Dung nhập mắt trái","text":"Lông vũ Chu Tước hóa thành ngọn lửa hình Chu Tước và dung nhập vào mắt trái Vương Lâm, nhưng chưa đủ để Chu Tước thức tỉnh lần thứ ba.","anchor":"chiếc lông lập tức hóa thành một ngọn lửa. Lúc này ngọn lửa lại có hình dáng như Chu Tước"}]},"capNhatToi":"@c1103","nguon":["@c1103","@c1105"],"congNang":["Dung nhập vào mắt trái Vương Lâm và hỗ trợ tuyến Chu Tước thức tỉnh lần thứ ba @c1105"]},{"id":"ban-do-tinh-cau-cap-sau-ban-that","name":"Bản đồ tinh cầu cấp sáu bản thật","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"cấp sáu","soHuu":["Vương Lâm"],"trangThai":"đang được giữ","blurb":"Bản đồ tinh cầu cấp sáu thật do bà lão áo xanh tặng Vương Lâm sau buổi tụ hội. Bà nói bản đồ bán trước đó chỉ là giả.","detail":"Bản đồ này chứa ít nhất ba phần tinh vực cấp sáu và vài Man Hoang đại lục. Việc bà lão chủ động tặng bản thật đi kèm lời cảnh báo về Ngô Thanh.","congNang":["Ghi chép tinh vực cấp sáu và Man Hoang đại lục @c1103"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Bà lão áo xanh","tuChuong":"@c1103","denChuong":"@c1103","cachCoDuoc":"Sưu tập từ trước","trangThai":"đã tặng đi"},{"ten":"Vương Lâm","tuChuong":"@c1103","denChuong":"","cachCoDuoc":"Được bà lão áo xanh tặng sau buổi tụ hội","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1103","loai":"đổi chủ","importance":"normal","giaiDoan":"Tặng bản đồ thật","text":"Bà lão áo xanh nói bản đồ tinh cầu đã bán trước đó là giả rồi tặng Vương Lâm bản thật và cảnh báo hắn chú ý Ngô Thanh.","anchor":"Bản đồ tinh cầu trước đó chỉ là giả, đây mới là đồ thật","phamCap":"cấp sáu"}]},"capNhatToi":"@c1103","nguon":["@c1103"]},{"id":"cach-hon-dan-cap-bay","name":"Cách Hồn Đan cấp bảy","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp bảy","soHuu":["Vương Lâm","Trương Kỳ"],"trangThai":"Vương Lâm nhận được từ Trương Kỳ @c1105","blurb":"Cách Hồn Đan cấp bảy là đan dược Trương Kỳ dâng lên Vương Lâm để bồi thường. Lô này có tổng cộng bốn mươi sáu viên.","detail":"Trương Kỳ lấy ra bình đan dược chứa toàn bộ Cách Hồn Đan cấp bảy, dùng làm một phần lễ cầu hòa với Vương Lâm sau vụ Ngô Thanh gây họa cho Ma Tùng Đạo.","congNang":["Công dụng cụ thể chưa lộ @c1105"],"chuSoHuu":[{"ten":"Trương Kỳ","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Mang theo để bồi thường","trangThai":"đã giao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Nhận từ Trương Kỳ","trangThai":"đang giữ"}],"capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"đổi chủ","importance":"normal","giaiDoan":"Bồi thường Ma Tùng Đạo","text":"Trương Kỳ dâng bốn mươi sáu viên Cách Hồn Đan cấp bảy cho Vương Lâm để cầu hòa.","anchor":"Trong đó tất cả đều là Cách Hồn Đan cấp bảy, tổng cộng có bốn mươi sáu hạt"}]},"nguon":["@c1105"]},{"id":"cach-hon-dan-cap-tam","name":"Cách Hồn Đan cấp tám","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp tám","soHuu":["Vương Lâm","Trương Kỳ"],"trangThai":"Vương Lâm nhận được từ Trương Kỳ @c1105","blurb":"Cách Hồn Đan cấp tám là đan dược bồi thường Trương Kỳ giao cho Vương Lâm. Số lượng được nêu rõ là chín viên.","detail":"Sau bình Cách Hồn Đan cấp bảy, Trương Kỳ tiếp tục lấy ra bình Cách Hồn Đan cấp tám để bày tỏ thái độ cầu hòa của Ma Tùng Đạo trước Vương Lâm.","congNang":["Công dụng cụ thể chưa lộ @c1105"],"chuSoHuu":[{"ten":"Trương Kỳ","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Mang theo để bồi thường","trangThai":"đã giao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Nhận từ Trương Kỳ","trangThai":"đang giữ"}],"capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"đổi chủ","importance":"normal","giaiDoan":"Bồi thường Ma Tùng Đạo","text":"Trương Kỳ dâng chín viên Cách Hồn Đan cấp tám cho Vương Lâm.","anchor":"Trong đây có chín viên Cách Hồn Đan cấp tám"}]},"nguon":["@c1105"]},{"id":"ngoc-gian-man-hoang-dai-luc","name":"Ngọc giản Man Hoang đại lục","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"Chưa rõ","soHuu":["Vương Lâm","Đỗ Đức"],"trangThai":"Vương Lâm nhận được từ Đỗ Đức @c1105","blurb":"Ngọc giản Man Hoang đại lục chứa thông tin về nơi Đỗ Đức từng đoạt được lông vũ Chu Tước. Đây là manh mối dẫn tới vùng có mãnh thú hệ hỏa cấp cao.","detail":"Đỗ Đức trao ngọc giản này cho Vương Lâm khi nói về nguồn gốc lông vũ Chu Tước. Nội dung liên quan đến Man Hoang đại lục tinh vực cấp sáu, nơi có mãnh thú am hiểu thần thông hệ hỏa và tồn tại mãnh thú cấp mười một.","congNang":["Cung cấp thông tin về Man Hoang đại lục tinh vực cấp sáu @c1105"],"chuSoHuu":[{"ten":"Đỗ Đức","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Nắm giữ thông tin về Man Hoang đại lục","trangThai":"đã giao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Nhận từ Đỗ Đức","trangThai":"đang giữ"}],"capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"đổi chủ","importance":"normal","giaiDoan":"Đỗ Đức trao manh mối","text":"Đỗ Đức trao ngọc giản chứa thông tin Man Hoang đại lục cho Vương Lâm và khuyên không nên xâm nhập sâu.","anchor":"Nếu Lữ đạo hữu cảm thấy hứng thú thì có thể đi vào đó xem xét, nhưng cũng đừng nên xâm nhập"}]},"nguon":["@c1105"]},{"id":"ban-do-tinh-cau-nhieu-ban","name":"Bản đồ tinh cầu nhiều bản","cn":"","aliases":[],"category":"khac","categoryLabel":"Bản đồ","phamCap":"Chưa rõ","soHuu":["Vương Lâm","Thương Tùng Tử"],"trangThai":"Vương Lâm nhận được từ Thương Tùng Tử @c1105","blurb":"Bản đồ tinh cầu nhiều bản là số bản đồ Thương Tùng Tử cho người thu mua trong khu chợ Bồng Lai rồi tặng Vương Lâm. Chúng có giá trị tra cứu nhưng khó phân biệt thật giả.","detail":"Khi biết Vương Lâm cần bản đồ tinh cầu, Thương Tùng Tử đã sai người thu mua sạch bản đồ trong chợ và mang đến tặng. Vương Lâm vẫn cần phân biệt phần thật giả trong số bản đồ này.","congNang":["Cung cấp thông tin bản đồ tinh cầu, nhưng cần phân biệt thật giả @c1105"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Cho người thu mua trong khu chợ Bồng Lai","trangThai":"đã tặng Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Nhận từ Thương Tùng Tử","trangThai":"đang giữ"}],"capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"đổi chủ","importance":"normal","giaiDoan":"Thương Tùng Tử tặng bản đồ","text":"Thương Tùng Tử thu mua nhiều bản đồ tinh cầu trong chợ để tặng Vương Lâm, nhưng số bản đồ này khó phân biệt thật giả.","anchor":"bản đồ tinh cầu lại rất khó phân biệt thật giả, muốn biết được trong này có bao nhiêu thứ là thật"}]},"nguon":["@c1105"]},{"id":"ngoc-gian-noi-bi-an-thuong-tung-tu","name":"Ngọc giản nơi bí ẩn Thương Tùng Tử","cn":"","aliases":["Ngọc giản nơi bí ẩn"],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"Chưa rõ","soHuu":["Vương Lâm","Thương Tùng Tử"],"trangThai":"Vương Lâm nhận được từ Thương Tùng Tử @c1105","blurb":"Ngọc giản nơi bí ẩn do Thương Tùng Tử đưa cho Vương Lâm, chứa thông tin về địa điểm mà lão chuẩn bị suốt ngàn năm. Đây là cơ sở cho lời mời hợp tác giữa hai người.","detail":"Thương Tùng Tử dùng ngọc giản này để giới thiệu một nơi bí ẩn mà lão tin có thể khiến tu vi tăng mạnh. Lão mời Vương Lâm cùng đi, chấp nhận thù lao hai vạn nguyên tinh và giao trước một nửa.","congNang":["Cung cấp thông tin về nơi bí ẩn mà Thương Tùng Tử muốn tiến vào @c1105"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1105","denChuong":"@c1105","cachCoDuoc":"Chuẩn bị cho kế hoạch tiến vào nơi bí ẩn","trangThai":"đã đưa cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1105","denChuong":"","cachCoDuoc":"Nhận từ Thương Tùng Tử","trangThai":"đang giữ"}],"capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở lời hợp tác","text":"Thương Tùng Tử đưa ngọc giản về nơi bí ẩn cho Vương Lâm và dùng nó làm cơ sở mời hợp tác.","anchor":"Lão phu biết được một nơi rất bí ẩn, chỗ đó chắc chắn sẽ tạo ra cảm hứng cho Lữ đạo hữu"}]},"nguon":["@c1105"]},{"id":"hai-bao-vat-hac-quang-cua-vuong-lam","name":"Hai bảo vật hắc quang của Vương Lâm","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm đấu giá","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"đem đấu giá @c1106","blurb":"Hai vật phẩm bí ẩn bị hắc quang bao phủ do Vương Lâm đem ra đấu giá để đổi nguyên tinh. Công dụng và lai lịch chưa được nêu rõ.","detail":"Vương Lâm lấy hai vật này từ khe nứt trữ vật, bên ngoài bị hắc quang bao phủ và có cấm chế che giấu. Hắn giao chúng cho Tào trưởng lão để đưa vào phiên đấu giá của Bảo Ngọc Tông.","phanLoaiPhu":"vật phẩm bí ẩn","hinhDang":"bị hắc quang bao phủ","dacDiem":"Có cấm chế che giấu, chưa lộ công dụng cụ thể.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1106","denChuong":"","cachCoDuoc":"đã có trong khe nứt trữ vật trước khi đem đấu giá","trangThai":"đem đấu giá"}],"tabs":{"tienTrinh":[{"chuong":"@c1106","loai":"xuất hiện","importance":"normal","giaiDoan":"Gửi đấu giá","text":"Vương Lâm lấy hai vật bị hắc quang bao phủ từ khe nứt trữ vật và giao cho Tào trưởng lão đưa vào đấu giá để đổi nguyên tinh.","anchor":"từ trong đó bay ra hai vật bị hắc quang bao phủ xung quanh"}]},"capNhatToi":"@c1106","nguon":["@c1106"]},{"id":"buc-tranh-song-nuoc","name":"Bức tranh sóng nước","cn":"","aliases":[],"category":"khac","categoryLabel":"Bảo vật đấu giá","phamCap":"chưa rõ","soHuu":["Lý Thiến Mai"],"trangThai":"đã đổi chủ @c1106","blurb":"Bức tranh sóng nước là vật phẩm đấu giá vẽ hồ nước cuồn cuộn sóng như thật, được Vương Lâm mua trong buổi đấu giá tại Bồng Lai rồi tặng lại cho Lý Thiến Ma trước lúc nàng rời đi.","detail":"Bức tranh sóng nước xuất hiện với tư cách vật phẩm đấu giá thứ ba trong buổi đấu giá tại quảng trường trung tâm Bồng Lai. Điểm khác biệt của nó là không vẽ núi mà vẽ hồ nước cuồn cuộn, mang lại cảm giác sóng nước sống động như thật. Trong buổi đấu giá, sau khi Vương Lâm lên tiếng muốn lấy thì không ai dám tranh đoạt, nhờ đó hắn mua được bức tranh. Về sau, Vương Lâm đem tặng lại cho Lý Thiến Ma trước lúc nàng rời đi (@c1106).","phanLoaiPhu":"tranh bảo vật","hinhDang":"bức tranh vẽ hồ nước cuồn cuộn sóng","dacDiem":"Sóng nước trong tranh sống động như thật.","chuHienThoi":"Lý Thiến Mai","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1106","denChuong":"@c1106","cachCoDuoc":"đấu giá thành công trong buổi đấu giá Bồng Lai","trangThai":"đã tặng cho Lý Thiến Mai"},{"ten":"Lý Thiến Mai","tuChuong":"@c1106","denChuong":"","cachCoDuoc":"được Vương Lâm tặng trước khi rời Bồng Lai","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1106","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm tặng Lý Thiến Mai","text":"Vương Lâm mua bức tranh sóng nước trong buổi đấu giá, không ai dám tranh với hắn, rồi tặng lại cho Lý Thiến Mai.","anchor":"đây là một bức tranh không vẽ núi mà vẽ một hồ nước cuồn cuộn sóng như thật"}]},"capNhatToi":"@c1106","nguon":["@c1106"]},{"id":"than-ma-giap","name":"Thần Ma Giáp","cn":"","aliases":["Thần Tông ma giáp","tứ phẩm Thần Ma Giáp"],"category":"phap-bao","categoryLabel":"Khôi giáp","phamCap":"tứ phẩm","soHuu":["Vương Lâm"],"trangThai":"đang đấu giá","blurb":"Thần Ma Giáp là khôi giáp đen kịt tứ phẩm liên quan tới Thần Tông, khi giải cấm chế bùng ra ma khí ngập trời. Sự xuất hiện của nó khiến toàn trường đấu giá chấn động và đẩy giá lên tới ba vạn nguyên tinh.","detail":"Thần Ma Giáp là bộ khôi giáp được đưa ra đấu giá. Khi cấm chế được mở, hắc khí tràn ra ngưng tụ thành giáp đen, ma khí dày đặc khiến bầu trời hiện vòng xoáy đen khổng lồ. Chúng tu sĩ nhận ra đây là tứ phẩm Thần Ma Giáp, loại vật trong truyền thuyết chỉ người Thần Tông mới có được, và sự lộ diện của nó khơi dậy hứng thú của Vương Lâm với Thần Tông tại Vân Hải tinh vực @c1107.","phanLoaiPhu":"khôi giáp","hinhDang":"bộ giáp đen kịt","uyLuc":"Khi mở cấm chế, ma khí ngập trời bùng ra và làm xuất hiện vòng xoáy đen khổng lồ trên bầu trời.","dacDiem":"Khôi giáp đen kịt, tứ phẩm; trong truyền thuyết chỉ người Thần Tông mới có được.","chuHienThoi":"Vương Lâm","capNhatToi":"@c1107","congNang":["Bộ giáp phòng hộ chứa ma khí cực dày @c1107","Khi mở cấm chế, bùng ra ma khí ngập trời làm xuất hiện vòng xoáy đen khổng lồ trên bầu trời @c1107"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1107","denChuong":"","cachCoDuoc":"Đã nằm trong vật phẩm của Vương Lâm trước khi đưa ra đấu giá","trangThai":"đang đưa ra đấu giá"}],"tabs":{"tienTrinh":[{"chuong":"@c1107","loai":"xuất hiện","importance":"major","giaiDoan":"Đấu giá tại Bồng Lai","text":"Thần Ma Giáp được mở cấm chế, lộ ma khí ngập trời và thân phận tứ phẩm liên quan Thần Tông, khiến cuộc đấu giá sôi sục và leo thang tới ba vạn nguyên tinh.","anchor":"Trong truyền thuyết chỉ có người Thần Tông mới có được Thần Ma Giáp, ma khí này dày vô cùng, chắc là tứ phẩm Thần Ma Giáp","phamCap":"tứ phẩm"}]},"nguon":["@c1107"]},{"id":"nui-da-tu-tien-gioi","name":"Núi đá từ Tiên giới","cn":"","aliases":["Núi đá","Ngọn núi đá không hoàn chỉnh"],"category":"phap-bao","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm","Trưởng lão đạo môn"],"trangThai":"đã bán cho trưởng lão đạo môn","blurb":"Ngọn núi đá không hoàn chỉnh từng thuộc Vương Lâm, được đưa ra đấu giá sau khi mở cấm chế. Vật này có tiên khí, liên quan Sưu Hồn bị tổn hại và cuối cùng được trưởng lão đạo môn mua.","detail":"Núi đá từ Tiên giới là vật Vương Lâm nhớ lại từ trận chiến trên La Thiên, về sau trở thành bảo vật vứt đi trong túi trữ vật. Khi mở cấm chế, nó tỏa khí tức tang thương và dấu vết năm tháng; thiếu phụ xinh đẹp nhận ra có Sưu Hồn nhưng đã tổn hại, còn người đàn ông văn sĩ áo trắng nhận xét trên mặt đá có tiên khí và có thể được luyện hóa từ vật lấy ở Tiên giới. Vật phẩm được bán cho trưởng lão đạo môn với giá một nghìn nguyên tinh.","phanLoaiPhu":"núi đá không hoàn chỉnh","nguonGoc":"có thể được lấy từ Tiên giới và luyện hóa thành","uyLuc":"Có thể giúp tu sĩ tiểu bối cảm ngộ thần thông, nhưng Sưu Hồn bên trong đã bị tổn hại.","dacDiem":"Tỏa khí tức tang thương, có dấu vết năm tháng và tiên khí trên mặt đá.","chuHienThoi":"Trưởng lão đạo môn","capNhatToi":"@c1107","congNang":["Chứa dấu vết Sưu Hồn đã bị tổn hại @c1107","Có thể giúp tu sĩ tiểu bối cảm ngộ thần thông @c1107"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1107","denChuong":"@c1107","cachCoDuoc":"Vật còn lại từ trận chiến trên La Thiên trong túi trữ vật của Vương Lâm","trangThai":"đã bán"},{"ten":"Trưởng lão đạo môn","tuChuong":"@c1107","denChuong":"","cachCoDuoc":"Mua trong buổi đấu giá với giá một nghìn nguyên tinh","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1107","loai":"đổi chủ","importance":"normal","giaiDoan":"Đấu giá tại Bồng Lai","text":"Núi đá được mở cấm chế, lộ khí tức tang thương, tiên khí và dấu vết Sưu Hồn bị tổn hại, rồi được trưởng lão đạo môn mua với giá một nghìn nguyên tinh.","anchor":"vật này có thể được lấy từ Tiên giới, sau đó lại được luyện hóa thành","phamCap":"không rõ"}]},"nguon":["@c1107"]},{"id":"vong-ngoc-xanh-biec-ly-thien-mai","name":"Vòng ngọc xanh biếc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai","Vương Lâm"],"trangThai":"Vương Lâm thu giữ sau khi rơi vào đường đi của hắn @c1108","blurb":"Pháp bảo phòng hộ màu xanh biếc từng được Lý Thiến Mai đeo trên tay phải. Nàng tặng Vương Lâm nhưng bị từ chối, sau đó vật tình cờ rơi đúng đường hắn đi và được hắn thu lại.","detail":"Lý Thiến Mai dùng vòng ngọc này để đền đáp vấn đề thứ ba, nói rõ đây là bảo vật phòng hộ cho Vương Lâm phòng thân. Vương Lâm thấy vật quá quý trọng nên trả lại, Lý Thiến Mai ném vào sương mù, nhưng sau đó vòng lại xuất hiện trên tuyến đường hắn phải đi theo bản đồ tinh cầu.","phanLoaiPhu":"Pháp bảo phòng hộ","hinhDang":"Vòng ngọc xanh biếc","dacDiem":"Từng đeo trên tay Lý Thiến Mai và còn giữ hơi ấm cơ thể nàng khi được trao ra.","chuHienThoi":"Vương Lâm","congNang":["Dùng để phòng thân, thuộc loại bảo vật phòng hộ @c1108"],"chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1108","denChuong":"@c1108","cachCoDuoc":"Từng đeo trên tay phải trước khi đem tặng Vương Lâm","trangThai":"da-roi"},{"ten":"Vương Lâm","tuChuong":"@c1108","denChuong":"","cachCoDuoc":"Nhặt lại trên đường sau khi Lý Thiến Mai ném vào sương mù","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1108","loai":"đổi chủ","importance":"normal","giaiDoan":"Từ Lý Thiến Mai sang Vương Lâm","text":"Lý Thiến Mai tặng vòng ngọc phòng hộ cho Vương Lâm, sau khi bị từ chối thì ném đi, nhưng vòng lại rơi đúng đường Vương Lâm và được hắn thu giữ.","anchor":"đây là một bảo vật phòng hộ, huynh giữ lại phòng thân đi"}]},"capNhatToi":"@c1108","nguon":["@c1108"]},{"id":"cay-but-bao-vat-tien-gioi","name":"Cây bút bảo vật Tiên giới","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật Tiên giới","soHuu":["Vương Lâm","Lý Thiến Mai"],"trangThai":"Lý Thiến Mai mang đi @c1108","blurb":"Cây bút bảo vật Tiên giới do Vương Lâm lấy ra từ khe nứt trữ vật để tặng Lý Thiến Mai. Khi phối hợp ký hiệu và tu vi, nó có thể tạo uy lực rất lớn.","detail":"Vương Lâm dùng cây bút viết lên hư không các ký hiệu phức tạp rồi để lại cho Lý Thiến Mai như một món đáp lễ. Cây bút có kim quang bao quanh, được chính Vương Lâm nói là bảo vật Tiên giới.","phanLoaiPhu":"Bút pháp bảo","hinhDang":"Cây bút có kim quang bao quanh","nguonGoc":"Bảo vật Tiên giới trong khe nứt trữ vật của Vương Lâm","uyLuc":"Phối hợp ký hiệu và tu vi có uy lực rất lớn.","dacDiem":"Cần phối hợp với các ký hiệu do Vương Lâm viết ra để phát huy uy lực.","chuHienThoi":"Lý Thiến Mai","congNang":["Phối hợp những ký hiệu phức tạp và tu vi để tạo uy lực lớn @c1108"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1108","denChuong":"@c1108","cachCoDuoc":"Lấy từ khe nứt trữ vật","trangThai":"da-tang"},{"ten":"Lý Thiến Mai","tuChuong":"@c1108","denChuong":"","cachCoDuoc":"Được Vương Lâm tặng khi chia tay trong sương mù","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1108","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm tặng Lý Thiến Mai","text":"Vương Lâm lấy cây bút bảo vật Tiên giới ra, viết ký hiệu trên hư không rồi để lại cho Lý Thiến Mai sử dụng.","anchor":"Bút này là bảo vật Tiên giới, khi thi triển phối hợp với những ký hiệu này, dùng với tu vi sẽ có uy lực rất lớn"}]},"capNhatToi":"@c1108","nguon":["@c1108"]},{"id":"hoi-dan","name":"Hồi đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Chưa rõ","soHuu":[],"trangThai":"không hoàn chỉnh","blurb":"Đan dược được Thương Tùng Tử tiết lộ là có tại mục tiêu chuyến đi. Vương Lâm nhận ra Hồi đan có thể không phải trọng điểm thật sự của Thương Tùng Tử.","detail":"Thương Tùng Tử nói trước đây lão từng thấy một khối Hồi đan ở bên ngoài nơi bí ẩn nhưng không thể lấy được vì có Giao Long hóa sương cấp mười hai canh giữ. Lời tiết lộ này khiến nhóm lão quái chú ý, nhưng Vương Lâm cho rằng đan dược này không phải mục tiêu cốt lõi của Thương Tùng Tử.","phanLoaiPhu":"Đan dược","hinhDang":"Một khối","dacDiem":"Nằm tại khu vực có mãnh thú cấp mười hai canh giữ.","congNang":["Công năng cụ thể chưa được nói rõ trong chương @c1109","Giúp người nuốt vào quay về ký ức để tìm kiếm thiên đạo @c1112","Mùi thuốc khiến nguyên thần chấn động và ký ức như quay ngược @c1112"],"chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c1109","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Thương Tùng Tử tiết lộ","text":"Thương Tùng Tử nói mục tiêu chuyến đi có Hồi đan, nhưng trước đây lão không lấy được vì có Giao Long hóa sương cấp mười hai canh giữ.","anchor":"trước đó lão phu không tiến vào được bên trong, nhưng ở bên ngoài cũng được thấy một khối Hồi đan"},{"chuong":"@c1112","loai":"xuất hiện","importance":"major","giaiDoan":"Bên hài cốt","text":"Hồi đan xuất hiện bên hài cốt trên con đường hẹp và được Thương Tùng Tử giải thích là đan dược thượng cổ liên quan trực tiếp tới Nhật Nguyệt Hồi Đạo của Đoan Mộc.","anchor":"Viên thuốc này có uy lực thiên địa, người nuốt vào có thể quay người không gian thời gian trở về tìm kiếm thiên đạo"}]},"capNhatToi":"@c1109","nguon":["@c1109","@c1112"]},{"id":"thanh-truong-kiem-cua-doan-moc-dong-tu","name":"Thanh trường kiếm của Đoan Mộc đồng tử","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Đoan Mộc đồng tử"],"trangThai":"Đang được Đoan Mộc đồng tử sử dụng","blurb":"Trường kiếm lớn đi cùng Đoan Mộc đồng tử khi hắn tới nơi tụ hội. Thanh kiếm có hình thái nổi bật, kiếm quang ác liệt và được dùng để phi hành.","detail":"Thanh trường kiếm dài bảy xích, rộng bằng hai ngón tay, toàn thân trắng bạc, lưu quang như thủy ngân và có tua kiếm vàng. Nó cắm xuống đất rồi sinh ra sóng rung động để Đoan Mộc đồng tử bước ra từ trong kiếm quang.","phanLoaiPhu":"Phi kiếm","hinhDang":"Trường kiếm dài bảy xích, rộng hai ngón tay, toàn thân trắng bạc, tua kiếm vàng","dacDiem":"Có kiếm quang ác liệt, hàn khí và lưu quang như thủy ngân.","congNang":["Dùng làm phi kiếm để Đoan Mộc đồng tử xuyên sương mù tới nơi tụ hội @c1109"],"chuSoHuu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1109","denChuong":"","cachCoDuoc":"Đã sở hữu khi xuất hiện","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1109","loai":"xuất hiện","importance":"normal","giaiDoan":"Đoan Mộc tới nơi tụ hội","text":"Thanh trường kiếm chở Đoan Mộc đồng tử xuyên sương mù tới nơi tụ hội rồi cắm xuống đất để hắn bước ra.","anchor":"Đây là một thanh trường kiếm màu đỏ dài bảy xích, kiếm rộng bằng hai ngón tay, khắp toàn thân đều có màu trắng bạc"}]},"capNhatToi":"@c1109","nguon":["@c1109"]},{"id":"thanh-thiet-kiem-ri-set-cua-van-hon-tu","name":"Thanh thiết kiếm rỉ sét của Vân Hồn Tử","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"không rõ","soHuu":["Vân Hồn Tử"],"trangThai":"đang được Vân Hồn Tử sử dụng","blurb":"Thanh thiết kiếm bề ngoài loang lỗ rỉ sét nhưng ẩn chứa lực lượng kinh thiên động địa.","detail":"Vân Hồn Tử vung ra thanh kiếm này ở khoảnh khắc cuối khi Vương Lâm tiến vào vết nứt bảy màu, dùng nó để tập kích Vương Lâm.","dinhDanh":"goc","hinhDang":"Thiết kiếm loang lỗ vết rỉ sét.","uyLuc":"Có lực lượng kinh thiên động địa dù bề ngoài cũ nát.","dacDiem":"Bề ngoài rỉ sét che giấu sức mạnh cực lớn.","chuHienThoi":"Vân Hồn Tử","congNang":["Dùng làm vũ khí tấn công trong đòn tập kích Vương Lâm @c1110"],"chuSoHuu":[{"ten":"Vân Hồn Tử","tuChuong":"@c1110","denChuong":"","cachCoDuoc":"Đã sở hữu khi ra tay tập kích Vương Lâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1110","loai":"dùng","importance":"normal","giaiDoan":"Tập kích ngoài vết nứt","text":"Vân Hồn Tử gọi ra thanh thiết kiếm rỉ sét chứa lực lượng kinh thiên động địa để tập kích Vương Lâm khi tiến vào vết nứt bảy màu.","anchor":"lóe lên một thanh thiết kiếm, trên thân kiếm loang lỗ những vết rỉ sét nhưng lại có được lực lượng kinh thiên động địa"}]},"capNhatToi":"@c1110","nguon":["@c1110"]},{"id":"nguyen-tinh-trong-suong-mu","name":"Nguyên tinh trong sương mù","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"được yêu cầu trước trận","blurb":"Tài nguyên trong sương mù của thế giới bảy màu, gắn với khu vực Giao Long hóa sương canh giữ.","detail":"Thương Tùng Tử từng lấy nguyên tinh từ thế giới bảy màu. Khi phân chia lợi ích trước trận đánh Giao Long hóa sương, Vương Lâm yêu cầu toàn bộ nguyên tinh trong sương mù.","nguon":["@c1112"],"chuHienThoi":"Vương Lâm","congNang":["Là tài nguyên trong sương mù của thế giới bảy màu mà Vương Lâm nhắm tới @c1112"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1112","denChuong":"","cachCoDuoc":"Yêu cầu toàn bộ nguyên tinh trong sương mù khi phân chia lợi ích trước trận đánh Giao Long hóa sương.","trangThai":"đang yêu cầu"}],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"đổi chủ","importance":"normal","giaiDoan":"Phân chia lợi ích","text":"Vương Lâm yêu cầu toàn bộ nguyên tinh trong sương mù trước khi đoàn người vây công Giao Long hóa sương.","anchor":"Ta muốn tất cả nguyên tinh trong sương mù!"}]}},{"id":"may-van-phi-kiem-cua-thuong-tung-tu","name":"Mấy vạn phi kiếm của Thương Tùng Tử","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang dùng","blurb":"Số lượng lớn phi kiếm do Thương Tùng Tử hóa ra trong trận vây công Giao Long hóa sương.","detail":"Khi giao chiến, Thương Tùng Tử vung tay huyễn hóa mấy vạn thanh phi kiếm, tạo thành thế mưa kiếm phóng về phía Giao Long.","nguon":["@c1112"],"phanLoaiPhu":"Phi kiếm số lượng lớn","uyLuc":"Tạo thành mưa kiếm dày đặc công kích Giao Long hóa sương.","chuHienThoi":"Thương Tùng Tử","congNang":["Huyễn hóa thành mưa kiếm số lượng lớn để công kích mục tiêu @c1112"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1112","denChuong":"","cachCoDuoc":"Thi triển trong trận vây công Giao Long hóa sương.","trangThai":"đang dùng"}],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"dùng","importance":"normal","giaiDoan":"Mưa kiếm","text":"Thương Tùng Tử hóa ra mấy vạn thanh phi kiếm như mưa kiếm đánh vào Giao Long hóa sương.","anchor":"mấy vạn thanh phi kiếm đột nhiên huyễn hóa ra rồi phóng về phía Giao Long giống như cơn mưa kiếm"}]}},{"id":"phi-kiem-cua-doan-moc","name":"Phi kiếm của Đoan Mộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Đoan Mộc"],"trangThai":"Đang sử dụng","blurb":"Phi kiếm được Đoan Mộc dùng trong trận vây công Giao Long hóa sương cấp mười hai.","detail":"Trong lúc phong ấn còn hạn chế được Giao Long, Đoan Mộc điều phi kiếm gào thét phóng tới, đâm xuyên thân thể mãnh thú và mang theo kiếm khí công kích mạnh vào thân thể nó.","nguon":["@c1113"]},{"id":"lo-cau-cua-lao-gia-ho-bang","name":"Lô cầu của lão giả họ Bàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Lão giả họ Bàng"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo dạng lô cầu của lão giả họ Bàng, dùng để nện xuống Giao Long trong trận vây công.","detail":"Lão giả họ Bàng sử dụng lô cầu đánh xuống thân thể Giao Long, góp phần vào đợt hợp kích cùng phi kiếm của Đoan Mộc, kiếm trận của Thương Tùng Tử và huyền băng của lão bà áo xanh.","nguon":["@c1113"]},{"id":"ngoc-gian-duoi-bo-hai-cot","name":"Ngọc giản dưới bộ hài cốt","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"Đã được Vương Lâm thu lấy","blurb":"Ngọc giản Vương Lâm lấy được dưới một bộ hài cốt sau trận chiến với Giao Long.","detail":"Sau khi Giao Long bị hạ, Vương Lâm phát hiện và thu lấy ngọc giản nằm dưới bộ hài cốt. Khi thần thức đảo qua, hắn trở nên ngưng trọng vì bên trong ghi lại một chuyện có liên quan đến thế giới bảy màu, nhưng nội dung cụ thể chưa kịp sáng tỏ thì dị biến cuối chương xuất hiện.","nguon":["@c1113"]},{"id":"ngoc-gian-ban-do-cua-thuong-tung-tu","name":"Ngọc giản bản đồ của Thương Tùng Tử","cn":"","category":"khac","categoryLabel":"Ngọc giản bản đồ","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang có","blurb":"Ngọc giản bản đồ giúp Thương Tùng Tử xác định cửa đường xuyên núi trong thế giới bảy màu.","detail":"Ngọc giản này chỉ ra rằng tại vách núi đường cụt có cửa của con đường xuyên qua núi, nhờ vậy đoàn người không chọn lối vượt qua đỉnh núi có bảy hung thú cấp mười hai.","congNang":["Chỉ đường tới cửa đường xuyên núi trong thế giới bảy màu @c1115"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1115","denChuong":"","cachCoDuoc":"Đã có từ trước khi dẫn đoàn tới vách núi","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"nhắc tới","importance":"normal","giaiDoan":"Chỉ cửa xuyên núi","text":"Thương Tùng Tử nói ngọc giản bản đồ chỉ ra tại vách núi có cửa của con đường xuyên qua núi.","anchor":"Sau đó lão phu mới phát hiện được một ngọc giản bản đồ"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"bo-ban-do-don-gian-cua-thuong-tung-tu","name":"Bộ bản đồ đơn giản của Thương Tùng Tử","cn":"","category":"khac","categoryLabel":"Bản đồ","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang có","blurb":"Bộ bản đồ đơn giản ghi lộ tuyến từ con đường hẹp đi sâu về phía trước trong thế giới bảy màu.","detail":"Thương Tùng Tử dựa vào bộ bản đồ này để dẫn đoàn tiếp tục tiến sâu, dù bản thân lão chưa từng đi qua đoạn đường ấy trước đây.","congNang":["Định hướng lộ tuyến từ con đường hẹp tiến sâu về phía trước @c1115"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1115","denChuong":"","cachCoDuoc":"Đã có từ trước khi dẫn đoàn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"nhắc tới","importance":"normal","giaiDoan":"Dẫn lộ tuyến","text":"Thương Tùng Tử có một bộ bản đồ đơn giản cho đoạn từ con đường hẹp đi về phía trước.","anchor":"Lão có một bộ bản đồ đơn giản khi từ con đường hẹp này đi về phía trước"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"khong-gian-tru-vat-cua-lao-gia-ho-bang","name":"Không gian trữ vật của lão già họ Bàng","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đổi chủ","blurb":"Không gian trữ vật của lão già họ Bàng là vật chứa dùng để cất giữ tài sản cùng vật phẩm tu luyện của lão. Đến mốc mới nhất, vật chứa này bị Vương Lâm ép mở và đoạt lấy toàn bộ sau trận phản sát.","detail":"Đây là không gian trữ vật thuộc về lão già họ Bàng, bên trong chứa tiên ngọc, nguyên tinh, ngọc giản, địa đồ, khẩu quyết cùng nhiều vật phẩm khác. Trong trận phản sát, Vương Lâm buộc lão Bàng mở không gian trữ vật, rồi dùng Thiết kiếm chặt đứt liên hệ giữa lão và vật chứa để thu trọn số chiến lợi phẩm bên trong @c1117.","chuHienThoi":"Vương Lâm","congNang":["Cất giữ tiên ngọc, nguyên tinh, ngọc giản, địa đồ, khẩu quyết và nhiều vật phẩm khác của lão Bàng @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"vốn sở hữu trước khi bị đoạt","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"ép mở rồi chặt đứt liên hệ chủ cũ","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Vương Lâm đoạt","text":"Vương Lâm chặt đứt liên hệ giữa lão Bàng và không gian trữ vật rồi lấy sạch vật phẩm bên trong.","anchor":"Thiết kiếm trong tay Vương Lâm lại được vung lên, hắn chặt đứt sự liên lạc giữa lão già họ Bàng và không gian trữ vật."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"tien-ngoc-va-nguyen-tinh-cua-lao-gia-ho-bang","name":"Tiên ngọc và nguyên tinh của lão già họ Bàng","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị thu lấy","blurb":"Lượng lớn tài nguyên tu luyện trong không gian trữ vật của lão Bàng.","detail":"Chiến lợi phẩm gồm hơn mười vạn tiên ngọc và năm sáu vạn nguyên tinh, được Vương Lâm thu từ không gian trữ vật của lão Bàng.","congNang":["Dùng làm tài nguyên tu luyện và giao dịch trong thế giới bảy màu @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"vốn cất trong không gian trữ vật","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"thu từ không gian trữ vật của lão Bàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"đổi chủ","importance":"normal","giaiDoan":"Thành chiến lợi phẩm","text":"Vương Lâm thu lượng lớn tiên ngọc và nguyên tinh từ không gian trữ vật của lão Bàng.","anchor":"Chỉ tính riêng tiên ngọc đã có hơn mười vạn, đặc biệt là nguyên tinh cũng có năm sáu vạn."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"hai-tam-dia-do-the-gioi-bay-mau","name":"Hai tấm địa đồ thế giới bảy màu","cn":"","category":"khac","categoryLabel":"Địa đồ","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị thu lấy","blurb":"Hai địa đồ liên quan đến đường đi và dấu hiệu trong thế giới bảy màu.","detail":"Vương Lâm tìm thấy hai tấm địa đồ trong đống ngọc giản của lão Bàng; trên đó có dấu hiệu đánh dấu đường đi và thông tin liên quan thế giới bảy màu.","congNang":["Dẫn đường và ghi dấu hiệu trong thế giới bảy màu @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"vốn cất trong không gian trữ vật","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"thu từ ngọc giản của lão Bàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"xuất hiện","importance":"normal","giaiDoan":"Địa đồ lộ diện","text":"Hai địa đồ thế giới bảy màu được Vương Lâm phát hiện trong ngọc giản của lão Bàng.","anchor":"Hai tấm bản đồ này đều có liên quan đến thế giới bảy màu, mặt trên bản đồ cũng có một số dấu hiệu để đánh dấu đường đi."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"an-ky-khau-quyet-roi-khoi-noi-day","name":"Ấn ký khẩu quyết rời khỏi nơi đây","cn":"","category":"khac","categoryLabel":"Khẩu quyết ấn ký","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị thu lấy","blurb":"Ấn ký khẩu quyết dùng để rời khỏi không gian hiện tại.","detail":"Vương Lâm phát hiện phần ấn ký khẩu quyết này trong đống ngọc giản thu từ lão Bàng, cùng với hai tấm địa đồ thế giới bảy màu.","congNang":["Cung cấp khẩu quyết và ấn ký để rời khỏi nơi đây @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"vốn cất trong ngọc giản","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"thu từ ngọc giản của lão Bàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"xuất hiện","importance":"normal","giaiDoan":"Khẩu quyết rời đi","text":"Vương Lâm tìm được ấn ký khẩu quyết dùng để rời khỏi không gian hiện tại.","anchor":"trong đống ngọc giản hắn phát hiện hai tấm địa đồ và một phần ấn ký khẩu quyết để rời khỏi nơi đây."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"thanh-doan-kiem-phong-an","name":"Thanh đoản kiếm phong ấn","cn":"","category":"phap-bao","categoryLabel":"Kiếm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị phong ấn","blurb":"Đoản kiếm lấy từ bộ xương thú hình nai trong thạch thất thứ ba, mang khí tức quen thuộc nhưng chưa giải phong ấn.","detail":"Thanh đoản kiếm do lão Bàng lấy từ bộ xương thú hình nai trong thạch thất thứ ba rồi lọt vào tay Vương Lâm. Trên kiếm có phong ấn nên chưa thể biết rõ uy lực, nhưng khí tức khiến Vương Lâm cảm thấy quen thuộc.","hinhDang":"đoản kiếm","dacDiem":"Có khí tức quen thuộc và còn phong ấn chưa mở.","congNang":["Chưa rõ uy lực vì phong ấn chưa được giải @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"lấy từ bộ xương thú trong thạch thất thứ ba","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"thu sau khi phản sát lão Bàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"xuất hiện","importance":"normal","giaiDoan":"Đoản kiếm phong ấn","text":"Vương Lâm chú ý thanh đoản kiếm vì nó có khí tức quen thuộc nhưng còn bị phong ấn.","anchor":"Chỉ có điều trên thanh đoản kiếm lại có phong ấn, nếu không mở ra phong ấn thì không thể biết được cụ thể uy lực của nó."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"chiec-nhan-chin-tang-phong-an","name":"Chiếc nhẫn chín tầng phong ấn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã mở đến tầng tám","blurb":"Chiếc nhẫn chín tầng phong ấn là bảo vật phòng ngự của lão Bàng, vốn đoạt được trong thế giới bảy màu. Sau khi rơi vào tay Vương Lâm, phong ấn tầng thứ tám bị phá, khiến năm luồng cầu vồng phòng ngự xuất hiện quanh thân.","detail":"Chiếc nhẫn vốn là bảo vật tốt nhất mà lão Bàng đoạt được trong thế giới bảy màu, mang chín tầng phong ấn. Sau khi Vương Lâm xóa thần thức của chủ cũ, hắn dùng cấm chế phá nốt tầng phong ấn thứ tám (@c1117), kích hoạt năm luồng cầu vồng phòng ngự bao quanh thân người sử dụng. Tính tới mốc mới nhất, phong ấn đã được phá đến tầng tám.","phanLoaiPhu":"pháp bảo phòng ngự","uyLuc":"Năm luồng cầu vồng tạo thành vòng phòng thủ chặt chẽ, có thể ngăn cản thần thông.","dacDiem":"Có chín tầng phong ấn, tính tới mốc mới nhất đã được phá đến tầng tám.","congNang":["Kích hoạt năm luồng cầu vồng phòng ngự quanh thân người sử dụng @c1117","Ngăn cản thần thông khi năm luồng cầu vồng xoay tròn @c1117"],"chuSoHuu":[{"ten":"Lão già họ Bàng","tuChuong":"@c1117","denChuong":"@c1117","cachCoDuoc":"bảo vật tốt nhất đoạt được trong thế giới bảy màu","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"nhặt từ vũng máu sau khi phản sát lão Bàng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"khai phong","importance":"major","giaiDoan":"Mở tầng tám","text":"Vương Lâm phá tầng phong ấn thứ tám của chiếc nhẫn và kích hoạt năm luồng cầu vồng phòng ngự.","anchor":"Năm luồng cầu vồng này tạo thành một vòng phòng thủ cực kỳ chặt chẽ, trong lúc xoay tròn có thể ngăn cản được tất cả thần thông.","phamCap":"không rõ"}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"tan-ma-khoi-giap","name":"Tán Ma khôi giáp","cn":"","category":"phap-bao","categoryLabel":"Khôi giáp","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang bị truy dấu","blurb":"Tán Ma khôi giáp là bộ khôi giáp mà Vương Lâm khẳng định thuộc về mình, người khác không thể mặc được. Sau khi rời động phủ, y dựa vào cảm ứng kỳ dị với khôi giáp để lần theo dấu vết trong thế giới bảy màu.","detail":"Tán Ma khôi giáp xuất hiện khi Vương Lâm rời động phủ. Dựa vào một cảm ứng kỳ dị phát ra từ khôi giáp, y lần theo tuyến đường mà Thương Tùng Tử và lão bà áo xanh đã đi qua trong thế giới bảy màu. Vương Lâm khẳng định bộ khôi giáp này là vật của riêng mình, người khác không thể mặc được @c1117.","chuHienThoi":"Vương Lâm tuyên bố sở hữu","congNang":["Cho phép Vương Lâm cảm ứng dấu vết để lần theo trong thế giới bảy màu @c1117"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1117","denChuong":"","cachCoDuoc":"khẳng định là khôi giáp của mình và lần theo cảm ứng","trangThai":"dang-truy-dau"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"nhắc tới","importance":"major","giaiDoan":"Bị Vương Lâm truy theo","text":"Vương Lâm rời động phủ, dựa vào cảm ứng kỳ dị để lần theo Tán Ma khôi giáp.","anchor":"- Tán Ma khôi giáp của Vương mỗ, người khác há có thể mặc được sao?"}]},"capNhatToi":"@c1117","nguon":["@c1117"],"dacDiem":"Là vật của riêng Vương Lâm, người khác không thể mặc được @c1117"},{"id":"pho-tuong-da-nam-tu-dau-an-tia-chop","name":"Pho tượng đá nam tử dấu ấn tia chớp","cn":"","aliases":[],"category":"khac","categoryLabel":"Tượng đá","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Pho tượng đá nam tử dấu ấn tia chớp nằm trong vùng sương mù đen sau dãy núi. Dấu ấn trên mi tâm tượng khiến lão bà áo xanh biến sắc.","detail":"Thương Tùng Tử và lão bà áo xanh thấy một pho tượng đá cao gần trăm trượng trong sương mù. Tượng có hình nam tử ngẩng đầu nhìn trời, trong mắt lộ vẻ trầm ngâm, trên mi tâm có dấu ấn như tia chớp khiến lão bà áo xanh chú ý mạnh.","phanLoaiPhu":"Tượng đá","hinhDang":"Tượng nam tử cao gần trăm trượng, ngẩng đầu nhìn trời, mi tâm có dấu ấn như tia chớp.","dacDiem":"Dấu ấn tia chớp trên mi tâm khiến lão bà áo xanh biến sắc.","congNang":["Gợi ra bí mật chưa rõ trong vùng sương mù của thế giới bảy màu @c1118"],"tabs":{"tienTrinh":[{"chuong":"@c1118","loai":"xuất hiện","importance":"normal","giaiDoan":"Gặp trong sương mù","text":"Thương Tùng Tử và lão bà áo xanh gặp tượng đá nam tử cao gần trăm trượng trong sương mù, trên mi tâm tượng có dấu ấn như tia chớp.","anchor":"trên mi tâm có một dấu ấn như tia chớp"}]},"capNhatToi":"@c1118","nguon":["@c1118"]},{"id":"dao-kinh","name":"Đạo Kinh","cn":"","aliases":[],"category":"khac","categoryLabel":"Bảo vật hoặc truyền thừa chưa rõ","phamCap":"chưa rõ","soHuu":[],"trangThai":"nằm trong vùng phong ấn @c1119","blurb":"Đạo Kinh là mục tiêu thật sự của Thương Tùng Tử trong chuyến đi vào vùng phong ấn.","detail":"Thương Tùng Tử nói rõ linh hồn mãnh thú không phải trọng tâm, thứ lão thật sự nhắm tới là Đạo Kinh. Việc nơi đây có nhiều Minh Chí Giả khiến lão bà áo xanh nhận định Đạo Kinh không đơn giản.","dacDiem":"Được đặt lên trên giá trị của linh hồn mãnh thú và gắn với lời lưu truyền về khai sáng.","congNang":["Là mục tiêu khiến Thương Tùng Tử chuẩn bị nhiều bảo vật quý để phá cấm @c1119"],"tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu thật","text":"Thương Tùng Tử công khai thừa nhận Đạo Kinh mới là mục tiêu thật sự khi tiến vào vùng phong ấn.","anchor":"Thứ lão phu thật sự nghĩ tới chính là Đạo Kinh"}]},"nguon":["@c1119"]},{"id":"pha-cam-truy","name":"Phá Cấm Trùy","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Thượng cổ kỳ bảo","phamCap":"chưa rõ","soHuu":["Thương Tùng Tử"],"trangThai":"tiêu tán hoặc vỡ khi phá cấm @c1119","blurb":"Phá Cấm Trùy là thượng cổ kỳ bảo do Thương Tùng Tử lấy ra để phá Tuế Nguyệt Cấm.","detail":"Thương Tùng Tử lấy ra bốn cây Phá Cấm Trùy giao cho lão bà áo xanh họ Triệu. Bà dung hợp cấm chế, hắc khí và máu tươi vào từng cây rồi đóng lên màn Tuế Nguyệt Cấm, khiến màn cấm chế hỗn loạn nhưng các trùy lần lượt tiêu tán hoặc vỡ.","congNang":["Dùng để phá cấm, có thể dung hợp cấm chế và máu tươi rồi đóng vào màn phong ấn @c1119"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1119","denChuong":"@c1119","cachCoDuoc":"đã mang theo từ trước","trangThai":"đã dùng để phá cấm"}],"tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"dùng","importance":"normal","giaiDoan":"Đóng vào Tuế Nguyệt Cấm","text":"Bốn cây Phá Cấm Trùy được lão bà áo xanh dung hợp cấm chế và máu tươi rồi đóng lên màn Tuế Nguyệt Cấm.","anchor":"Thượng cổ kỳ bảo Phá Cấm Trùy"}]},"nguon":["@c1119"]},{"id":"khoi-go-mau-den-hac-moc","name":"Khối gỗ màu đen","cn":"","aliases":["Hắc Mộc"],"category":"khac","categoryLabel":"Vật phẩm phá cấm","phamCap":"chưa rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đã tự hủy @c1119","blurb":"Khối gỗ màu đen là vật phẩm mang khí tức hùng mạnh được Thương Tùng Tử dùng để công kích Tuế Nguyệt Cấm.","detail":"Khi lấy ra, vật này tạo khí tức mạnh và vòng xoáy trong sương mù, từng khiến người khác liên tưởng tới Thứ Không Niết Bảo. Theo yêu cầu của lão bà áo xanh, Thương Tùng Tử ném Hắc Mộc ra để nó tan vỡ, phóng lực công kích xuống màn cấm chế.","hinhDang":"khối gỗ màu đen","uyLuc":"Tự vỡ thành nhiều mảnh và phóng lực công kích mạnh xuống cấm chế.","congNang":["Tự hủy để tạo lực công kích phá cấm @c1119"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1119","denChuong":"@c1119","cachCoDuoc":"đã mang theo từ trước","trangThai":"đã tự hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"dùng","importance":"normal","giaiDoan":"Tự hủy phá cấm","text":"Khối gỗ màu đen được ném ra và tan vỡ để tạo lực công kích đánh vào Tuế Nguyệt Cấm.","anchor":"khối gỗ đã hóa thành rất nhiều mảnh vụn"}]},"nguon":["@c1119"]},{"id":"tinh-thach-ruc-ro-an-giau-mau-tuoi","name":"Tinh thạch rực rỡ ẩn giấu máu tươi","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm phá cấm","phamCap":"chưa rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đã tự hủy @c1119","blurb":"Tinh thạch rực rỡ ẩn giấu máu tươi là vật phẩm được Thương Tùng Tử dùng sau Hắc Mộc để phá Tuế Nguyệt Cấm.","detail":"Thương Tùng Tử lấy ra tinh thạch này sau khối gỗ đen. Khi tới sát màn cấm chế, nó nổ tung thành cơn bão mạnh, được cấm chế của cô gái áo xanh dẫn xuống khiến màn cấm xuất hiện vết nứt ngắn ngủi.","uyLuc":"Nổ tung thành cơn bão mạnh, khiến Tuế Nguyệt Cấm xuất hiện vết nứt.","congNang":["Tự nổ để tạo cơn bão công kích màn cấm chế @c1119"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1119","denChuong":"@c1119","cachCoDuoc":"đã mang theo từ trước","trangThai":"đã tự hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"dùng","importance":"normal","giaiDoan":"Nổ tung mở vết nứt","text":"Tinh thạch được ném vào màn cấm chế rồi nổ tung, tạo vết nứt ngắn ngủi trên Tuế Nguyệt Cấm.","anchor":"tinh thạch tới sát bên tấm màn cấm chế thì nổ tung"}]},"nguon":["@c1119"]},{"id":"ngoc-boi-thu-khong-niet-bao-cua-thuong-tung-tu","name":"Ngọc bội Thứ Không Niết Bảo của Thương Tùng Tử","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Thứ Không Niết Bảo","phamCap":"Thứ Không Niết Bảo","soHuu":["Thương Tùng Tử"],"trangThai":"đã tự hủy @c1119","blurb":"Ngọc bội Thứ Không Niết Bảo của Thương Tùng Tử là pháp bảo thật sự được lão đau lòng tự hủy để mở lỗ hổng trên Tuế Nguyệt Cấm.","detail":"Sau khi khối gỗ đen và tinh thạch chỉ tạo được vết nứt ngắn ngủi, Thương Tùng Tử lấy ra ngọc bội thật sự là Thứ Không Niết Bảo. Vật này bị lão chủ động tự hủy, tạo lực lượng vượt xa hai món trước và mở một lỗ hổng mười trượng trên màn cấm chế.","phanLoaiPhu":"ngọc bội","uyLuc":"Sức nổ vượt xa khối gỗ đen và tinh thạch, đủ mở lỗ hổng mười trượng trên Tuế Nguyệt Cấm.","dacDiem":"Là Thứ Không Niết Bảo thật, bị tiêu hao trong canh bạc phá cấm.","congNang":["Tự hủy để mở lỗ hổng mười trượng trên Tuế Nguyệt Cấm @c119"],"chuHienThoi":"không còn","chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1119","denChuong":"@c1119","cachCoDuoc":"đã mang theo từ trước","trangThai":"đã tự hủy"}],"capNhatToi":"@c1119","tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Tự hủy mở lỗ hổng","text":"Thương Tùng Tử tự hủy ngọc bội Thứ Không Niết Bảo thật để mở lỗ hổng mười trượng trên Tuế Nguyệt Cấm.","anchor":"Ngọc bội kia phóng thẳng về phía vết nứt"}]},"nguon":["@c1119"]},{"id":"con-lac-mau-trang-hinh-tia-chop","name":"Con lắc màu trắng hình tia chớp","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo mở cửa","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang thuộc Thương Tùng Tử","blurb":"Pháp bảo màu trắng hình tia chớp do Thương Tùng Tử lấy ra từ không gian trữ vật. Nó cộng hưởng với đồ đằng tia chớp trên cửa đá và mở động phủ phong ấn thú hồn.","detail":"Thương Tùng Tử ném con lắc vào cửa đá khắc đồ đằng tia chớp, khiến cánh cửa mở ra và tiếng thú hồn gào thét truyền ra. Vật này là chìa khóa để lão lừa Triệu đạo hữu bước vào động phủ.","hinhDang":"Con lắc màu trắng hình tia chớp","chuHienThoi":"Thương Tùng Tử","congNang":["Mở cửa đá có đồ đằng tia chớp @c1120"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1120","denChuong":"","cachCoDuoc":"Lấy từ không gian trữ vật của mình","trangThai":"đang giữ"}],"capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"dùng","importance":"normal","giaiDoan":"Mở cửa động phủ thú hồn","text":"Thương Tùng Tử dùng con lắc màu trắng hình tia chớp để mở cửa đá khắc đồ đằng tia chớp.","anchor":"trong không gian trữ vật lập tức bay ra một con lắc màu trắng"}]},"nguon":["@c1120"]},{"id":"binh-ngoc-duoi-bo-hai-cot","name":"Bình ngọc dưới bộ hài cốt","cn":"","aliases":["Bình ngọc trong tay Thương Tùng Tử","Bình ngọc"],"category":"khac","categoryLabel":"Vật phẩm trọng yếu","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"bị Thương Tùng Tử lấy khỏi trận pháp","blurb":"Vật phẩm trọng yếu nằm dưới xương sống bộ hài cốt màu đen trong không gian tấm bia. Đây là mục tiêu thật của Thương Tùng Tử, quan trọng hơn Đạo Kinh và thú hồn trong mưu đồ của lão.","detail":"Bình ngọc đặt ở trung tâm trận pháp ngục tù dưới bộ hài cốt. Khi Thương Tùng Tử chạm tới, bình hút bạch khí từ thân lão; lão liền tung hơn một ngàn nguyên thần bị phong ấn để bình hấp thu, rồi dùng bốn tiểu kiếm phá trận và nhấc bình lên.","chuHienThoi":"Thương Tùng Tử","congNang":["Hấp thu bạch khí và nguyên thần bị phong ấn @c1120"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1120","denChuong":"","cachCoDuoc":"Hy sinh hơn một ngàn nguyên thần bị phong ấn và dùng bốn tiểu kiếm phá trận để nhấc khỏi trận pháp","trangThai":"đang giữ"}],"capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"đổi chủ","importance":"major","giaiDoan":"Bị lấy khỏi trận pháp","text":"Bình ngọc dưới bộ hài cốt hút bạch khí và gần một ngàn nguyên thần bị phong ấn trước khi bị Thương Tùng Tử nhấc khỏi trận pháp.","anchor":"mục đích chính thức của lão chính là bình ngọc bên dưới bộ hài cốt"}]},"nguon":["@c1120"]},{"id":"hon-mot-ngan-nguyen-than-bi-phong-an","name":"Hơn một ngàn nguyên thần bị phong ấn","cn":"","aliases":[],"category":"khac","categoryLabel":"Nguồn hiến tế","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"gần như tiêu tán","blurb":"Các nguyên thần bị Thương Tùng Tử chuẩn bị sẵn và phong ấn bằng dây nối. Lão dùng chúng làm vật thay thế để bình ngọc hấp thu bạch khí.","detail":"Khi bình ngọc bắt đầu hút bạch khí từ thân Thương Tùng Tử, lão tung hơn một ngàn nguyên thần bị phong ấn ra. Trong khoảng mười hơi thở, gần như một ngàn nguyên thần tiêu tán quỷ dị thành bạch khí bị bình ngọc hấp thu.","chuHienThoi":"Thương Tùng Tử","congNang":["Làm vật hiến tế cho bình ngọc hấp thu @c1120"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1120","denChuong":"@c1120","cachCoDuoc":"Đã được lão chuẩn bị và phong ấn từ trước","trangThai":"đã dùng hiến tế"}],"capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"dùng","importance":"normal","giaiDoan":"Hiến tế cho bình ngọc","text":"Thương Tùng Tử tung hơn một ngàn nguyên thần bị phong ấn để bình ngọc hấp thu thay cho bạch khí từ thân mình.","anchor":"Sau khoảnh khắc đã có hơn một ngàn luồng nguyên thần bay ra"}]},"nguon":["@c1120"]},{"id":"bon-thanh-tieu-kiem-kim-quang","name":"Bốn thanh tiểu kiếm kim quang","cn":"","aliases":["Bốn tiểu kiếm kim quang"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang thuộc Thương Tùng Tử","blurb":"Bốn thanh kiếm nhỏ phát kim quang từ miệng Thương Tùng Tử bay ra. Chúng được dùng để phá trận lấy bình ngọc và tấn công người phụ nữ áo xanh họ Triệu.","detail":"Bốn thanh tiểu kiếm cắm quanh trận pháp giúp Thương Tùng Tử nhấc bình ngọc khỏi vị trí trấn giữ. Khi đối đầu người phụ nữ trung niên áo xanh họ Triệu, chúng tan thành chất lỏng vàng xuyên qua vòng xoáy cấm chế và lao thẳng tới nàng.","hinhDang":"Bốn thanh kiếm nhỏ như bàn tay, phát kim quang","chuHienThoi":"Thương Tùng Tử","congNang":["Phá trận quanh bình ngọc @c1120","Hóa thành chất lỏng vàng xuyên qua vòng xoáy cấm chế @c1120"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1120","denChuong":"","cachCoDuoc":"Từ miệng lão bay ra khi phá trận","trangThai":"đang dùng"}],"capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"dùng","importance":"normal","giaiDoan":"Phá trận và đánh chặn","text":"Bốn tiểu kiếm kim quang được Thương Tùng Tử dùng để phá trận quanh bình ngọc rồi hóa lỏng xuyên qua cấm chế của người phụ nữ áo xanh.","anchor":"trong miệng lão cũng bay ra bốn luồng kim quang rồi hóa thành bốn thanh kiếm nhỏ như bàn tay"}]},"nguon":["@c1120"]},{"id":"hai-cay-dinh-bay-mau","name":"Hai cây đinh bảy màu","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phong ấn","phamCap":"không rõ","soHuu":[],"trangThai":"đang đóng giữ hài cốt","blurb":"Hai cây đinh bảy màu đóng hai tay nửa bộ hài cốt màu đen vào tấm bia. Chúng là một phần bố trí trấn áp trong không gian bảy màu.","detail":"Trong không gian tấm bia, nửa bộ hài cốt màu đen bị hai cây đinh bảy màu đóng sâu vào tấm bia ở hai tay. Chi tiết này cho thấy hài cốt bị cố định và trấn áp trong bố cục quanh Đạo Kinh và bình ngọc.","congNang":["Đóng giữ hai tay hài cốt vào tấm bia @c1120"],"capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"xuất hiện","importance":"normal","giaiDoan":"Đóng giữ hài cốt","text":"Hai cây đinh bảy màu đóng hai tay bộ hài cốt màu đen thật sâu vào tấm bia.","anchor":"hai tay tách ra rồi bị hai cây đinh bảy màu đóng vào thật sâu trên tấm bia"}]},"nguon":["@c1120"]},{"id":"chen-mau-dong-cua-lao-ba-ao-xanh","name":"Chén màu đồng của lão bà áo xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão bà áo xanh"],"trangThai":"hong","blurb":"Pháp bảo dạng chén màu đồng của lão bà áo xanh, dùng để trùm bắt nguyên anh hình người.","detail":"Lão bà áo xanh ném chén màu đồng để bao phủ nguyên anh hình người của Thương Tùng Tử, nhưng vật kỳ dị kia phá vỡ chiếc chén thành nhiều mảnh.","nguon":["@c1121"],"congNang":["Bao phủ và trấn áp mục tiêu dạng nguyên anh hoặc thần hồn @c1121"],"chuSoHuu":[{"ten":"Lão bà áo xanh","tuChuong":"@c1121","denChuong":"@c1121","cachCoDuoc":"Đã sở hữu khi giao chiến với Thương Tùng Tử","trangThai":"hư hỏng"}],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị nguyên anh hình người phá vỡ","text":"Chén màu đồng bị nguyên anh hình người phá vỡ thành nhiều mảnh khi đang cố bao phủ nó.","anchor":"chén màu đồng lập tức vỡ tan thành rất nhiều mảnh nhỏ."}]},"capNhatToi":"@c1121"},{"id":"nguyen-anh-hinh-nguoi-cua-thuong-tung-tu","name":"Nguyên anh hình người của Thương Tùng Tử","cn":"","category":"khac","categoryLabel":"Vật thần hồn kỳ dị","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"bi phong ấn","blurb":"Vật kỳ dị giống nguyên anh bay ra từ thiên linh Thương Tùng Tử nhưng được nói rõ không phải nguyên anh.","detail":"Vật này bay ra từ thiên linh Thương Tùng Tử, có hình dạng như nguyên anh nhưng không phải nguyên anh. Nó phá chén màu đồng, lao vào lão bà áo xanh rồi bị lão phụ nhân áo xanh nắm lấy và phong ấn.","nguon":["@c1121"],"dacDiem":"Giống nguyên anh nhưng tuyệt đối không phải nguyên anh","congNang":["Phá vỡ chén màu đồng và công kích lão bà áo xanh @c1121"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1121","denChuong":"@c1121","cachCoDuoc":"Từ thiên linh của Thương Tùng Tử bay ra","trangThai":"bị lão phụ nhân áo xanh phong ấn"}],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"xuất hiện","importance":"normal","giaiDoan":"Từ thiên linh Thương Tùng Tử bay ra","text":"Nguyên anh hình người xuất hiện, phá chén màu đồng rồi bị lão phụ nhân áo xanh phong ấn.","anchor":"nhưng nếu nhìn kỹ thì có thể phát hiện được vật này tuyệt đối không phải là nguyên anh."}]},"capNhatToi":"@c1121"},{"id":"khien-tu-quang-cua-lao-phu-nhan","name":"Khiên tử quang của lão phụ nhân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"Không rõ","soHuu":["Lão phụ nhân áo xanh"],"trangThai":"dang-co","blurb":"Khiên tử quang lão phụ nhân áo xanh huyễn hóa để chống bảy thanh trường kiếm của Thương Tùng Tử.","detail":"Chiếc khiên tử quang hiện ra trước người lão phụ nhân, mang khí tức tang thương và mơ hồ ma khí, dùng để phòng ngự trước thế công bảy trường kiếm.","nguon":["@c1121"],"congNang":["Phòng ngự trước bảy thanh trường kiếm màu sắc khác nhau @c1121"],"chuSoHuu":[{"ten":"Lão phụ nhân áo xanh","tuChuong":"@c1121","denChuong":"","cachCoDuoc":"Huyễn hóa trong lúc giao chiến","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"dùng","importance":"normal","giaiDoan":"Chống bảy trường kiếm","text":"Lão phụ nhân huyễn hóa khiên tử quang trước người để chống thế công của Thương Tùng Tử.","anchor":"một chiếc khiên tử quang đột nhiên huyễn hóa ra trước người."}]},"capNhatToi":"@c1121"},{"id":"hat-chau-nghich-hanh-gia","name":"Hạt châu Nghịch Hành Giả","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo triệu hồi","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"dang-co","blurb":"Hạt châu Nghịch Hành Giả là pháp bảo được Thương Tùng Tử dùng để gọi Nghịch Hành Giả, có khả năng hấp thu ánh sáng bảy màu trên bầu trời và dẫn ra công kích đặc thù. Tính tới mốc mới nhất, hạt châu đã lộ hai lối vận dụng: phóng thẳng lực lượng bảy màu và ngưng tụ ánh sáng thành Thiên Vận Nhất Chỉ.","detail":"Hạt châu do Thương Tùng Tử sử dụng, khi ném ra sẽ gọi Nghịch Hành Giả, khiến ánh sáng bảy màu trên bầu trời kéo tới. Trong lần đầu vận dụng, hạt châu vỡ ra rồi phóng lực lượng bảy màura công kích @c1121. Ở lần vận dụng khác, thay vì phóng thẳng lực lượng, hạt châu dẫn ánh sáng bảy màu ngưng tụ lại thành chiêu thức Thiên Vận Nhất Chỉ @c1121.","nguon":["@c1121"],"congNang":["Hấp thu ánh sáng bảy màu và phóng ra lực lượng bảy màu @c1121","Dẫn ánh sáng bảy màu ngưng tụ thành Thiên Vận Nhất Chỉ @c1121","Gọi Nghịch Hành Giả @c1121"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1121","denChuong":"","cachCoDuoc":"Đã sở hữu khi giao chiến trong thế giới bảy màu","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"dùng","importance":"major","giaiDoan":"Triệu gọi Nghịch Hành Giả và Thiên Vận Nhất Chỉ","text":"Thương Tùng Tử dùng hạt châu để hấp thu ánh sáng bảy màu, gọi Nghịch Hành Giả và sau đó dẫn ra Thiên Vận Nhất Chỉ.","anchor":"Khoảnh khắc này tất cả luồng sáng bảy màu trên bầu trời lập tức kéo đến"}]},"capNhatToi":"@c1121"},{"id":"hai-tam-phu-cua-vuong-lam","name":"Hai tấm phù của Vương Lâm","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hai tấm phù Vương Lâm dán trong lúc bị truy đuổi để tăng mạnh tốc độ.","detail":"Sau khi đoạt bình ngọc và lao qua sương mù, Vương Lâm dán hai tấm phù lên người, khiến tốc độ tăng mạnh và kéo giãn khoảng cách với lão phụ nhân áo xanh.","nguon":["@c1121"],"congNang":["Tăng mạnh tốc độ trong lúc bỏ chạy @c1121"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1121","denChuong":"@c1121","cachCoDuoc":"Đã có sẵn khi bị truy đuổi","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"dùng","importance":"normal","giaiDoan":"Tăng tốc thoát truy sát","text":"Vương Lâm dán hai tấm phù để tăng tốc và kéo giãn khoảng cách với lão phụ nhân.","anchor":"nhưng khi Vương Lâm dán hai tấm phù lên thì tốc độ đã tăng mạnh"}]},"capNhatToi":"@c1121"},{"id":"kiem-trong-suot-cua-thuong-tung-tu","name":"Kiếm trong suốt của Thương Tùng Tử","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phi kiếm/Thứ Không Niết Bảo","phamCap":"Thứ Không Niết Bảo","soHuu":["Thương Tùng Tử"],"trangThai":"đang được Thương Tùng Tử sử dụng","blurb":"Thanh kiếm trong suốt như thủy tinh được Thương Tùng Tử lấy ra khi giao chiến trực diện với Vương Lâm.","detail":"Thương Tùng Tử mở không gian trữ vật lấy ra thanh kiếm trong suốt, trên đó bùng lên khí tức Thứ Không Niết Bảo, dùng để đẩy trận chiến với Vương Lâm lên mức nguy hiểm hơn.","phanLoaiPhu":"phi kiếm","hinhDang":"Toàn thân trong suốt như thủy tinh.","uyLuc":"Tỏa khí tức Thứ Không Niết Bảo khi được Thương Tùng Tử dùng tấn công Vương Lâm.","chuHienThoi":"Thương Tùng Tử","congNang":["Dùng làm phi kiếm cấp Thứ Không Niết Bảo trong giao chiến trực diện @c1122"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1122","denChuong":"","cachCoDuoc":"Lấy ra từ không gian trữ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1122","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ khí tức Thứ Không Niết Bảo","text":"Thương Tùng Tử lấy thanh kiếm trong suốt từ không gian trữ vật, khiến khí tức Thứ Không Niết Bảo bùng lên.","anchor":"một luồng khí tức Thứ Không Niết Bảo đột nhiên bùng lên"}]},"capNhatToi":"@c1122","nguon":["@c1122"]},{"id":"tinh-kiem","name":"Tinh Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thứ Không Niết Bảo","soHuu":["Thương Tùng Tử"],"trangThai":"bị Tam Xoa Kích thôn phệ @c1123","blurb":"Bảo vật cao cấp của Thương Tùng Tử, có hình như thủy tinh và phẩm cấp Thứ Không Niết Bảo. Nó được dùng để chém giết Vương Lâm thật nhanh nhưng bị Hắc Long của Tam Xoa Kích thôn phệ.","detail":"Tinh Kiếm là một loại bảo vật tương đối cao của Thương Tùng Tử, được lão tung ra trong trận huyết chiến nhằm nhanh chóng chém giết Vương Lâm. Kiếm khí của nó chém trời đất, nhưng về sau bị Hắc Long do Tam Xoa Kích biến thành thôn phệ và khắc dấu lên thân kích.","hinhDang":"thanh kiếm như thủy tinh","uyLuc":"Kiếm khí có thể chém trời đất trong trận chiến.","chuHienThoi":"Thương Tùng Tử","congNang":["Phóng kiếm khí công kích mục tiêu @c1123"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1123","denChuong":"@c1123","cachCoDuoc":"bảo vật cao cấp sẵn có","trangThai":"bị thôn phệ"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"dùng","importance":"normal","giaiDoan":"bị Tam Xoa Kích nuốt","text":"Tinh Kiếm được Thương Tùng Tử dùng để nhanh chóng chém giết Vương Lâm, nhưng bị Hắc Long của Tam Xoa Kích thôn phệ và khắc vào thân kích.","anchor":"Thanh kiếm như thủy tinh này chính là một loại bảo vật tương đối cao của Thương Tùng Tử","phamCap":"Thứ Không Niết Bảo"}]},"capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"ba-hat-chau-trieu-hoi-nghich-hanh-gia","name":"Ba hạt châu triệu hồi Nghịch Hành Giả","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm triệu hồi","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đã tiêu hao @c1123","blurb":"Ba hạt châu được Thương Tùng Tử tiêu hao để triệu hồi các hình thái Nghịch Hành Giả. Mỗi hạt vỡ ra tạo một tầng công kích gồm hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ.","detail":"Trong trận với Vương Lâm, Thương Tùng Tử không tiếc tiêu hao ba hạt châu để hình thành thế sát chiêu nhiều tầng. Các hạt châu lần lượt triệu hồi hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ nhằm vây giết Vương Lâm thật nhanh.","chuHienThoi":"Thương Tùng Tử","congNang":["Triệu hồi hư ảnh kiếm uy, người đá trăm trượng và La Bàn khổng lồ @c1123"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1123","denChuong":"@c1123","cachCoDuoc":"lấy từ khe nứt không gian trữ vật","trangThai":"đã tiêu hao"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"dùng","importance":"normal","giaiDoan":"triệu hồi Nghịch Hành Giả","text":"Thương Tùng Tử lấy ra ba hạt châu và tiêu hao chúng để triệu hồi ba hình thái công kích của Nghịch Hành Giả nhằm vây giết Vương Lâm.","anchor":"lão muốn giết Vương Lâm thật nhanh","phamCap":"không rõ"}]},"capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"la-ban-khong-lo","name":"La Bàn khổng lồ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo/huyễn hóa triệu hồi","phamCap":"không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"đang truy kích Vương Lâm @c1123","blurb":"La Bàn khổng lồ do hạt châu thứ ba nổ tan, hào quang bảy màu ngưng tụ thành. Nó phát ra uy áp đáng sợ, bị Tam Xoa Kích và Diệt Thần Thương công kích nhưng cuối chương vẫn tiếp tục đuổi theo Vương Lâm.","detail":"La Bàn khổng lồ là một hình thái công kích được triệu hồi trong trận Thương Tùng Tử vây giết Vương Lâm. Dù bị Tam Xoa Kích và hư ảnh Diệt Thần Thương chống lại, La Bàn chưa bị giải quyết; khi Vương Lâm rút lui, nó vẫn chậm rãi chuyển động truy theo hắn.","hinhDang":"La Bàn khổng lồ","uyLuc":"Phát ra uy áp đáng sợ và có khả năng tiếp tục truy kích sau khi chủ nhân trọng thương bỏ chạy.","congNang":["Tạo uy áp và truy kích mục tiêu @c1123"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1123","denChuong":"","cachCoDuoc":"triệu hồi từ hạt châu thứ ba","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"xuất hiện","importance":"normal","giaiDoan":"truy kích chưa dứt","text":"La Bàn khổng lồ được hạt châu thứ ba triệu hồi, chịu công kích của Tam Xoa Kích và Diệt Thần Thương nhưng cuối chương vẫn chuyển động đuổi theo Vương Lâm.","anchor":"hóa thành một La Bàn khổng lồ","phamCap":"không rõ"}]},"capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"cay-dinh-bay-mau","name":"Cây đinh bảy màu","cn":"","aliases":["Chiếc đinh bảy màu","Đinh bảy màu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thứ Không Niết Bảo","soHuu":["Thương Tùng Tử"],"trangThai":"khong-ro","blurb":"Cây đinh bảy màu là pháp bảo Thứ Không Niết Bảo của Thương Tùng Tử, có hình dạng giống những cây đinh đóng trên hài cốt Đạo Kinh. Nó từng đánh gãy Thiết Kiếm rồi ghim vào vai phải Vương Lâm như ghim chặt nguyên thần, và về sau lộ ra rằng Tư Mã Đặc cũng bị chính loại đinh này đâm vào cơ thể khi cứu Tứ sư thúc ở vị trí sâu nhất.","detail":"Cây đinh bảy màu mang uy lực Thứ Không Niết Bảo, được Thương Tùng Tử cất trong không gian trữ vật và lấy ra trong khoảnh khắc quyết liệt. Trong lần dùng đầu tiên, nó đánh gãy Thiết Kiếm của Vương Lâm và cắm vào vai phải hắn, tạo thương thế nghiêm trọng cho thân Cổ Thần, tựa như ghim chặt nguyên thần (@c1123). Về sau, ngọc giản tiết lộ Tư Mã Đặc cũng từng bị cây đinh bảy màu đâm vào cơ thể khi cứu Tứ sư thúc ở vị trí sâu nhất (@c1127), cho thấy pháp bảo này gắn với những biến cố hiểm nghèo.","hinhDang":"cây đinh bảy màu","uyLuc":"Đánh gãy Thiết Kiếm và ghim vào vai phải Vương Lâm, như ghim chặt nguyên thần.","dacDiem":"Có hình dạng giống đinh đóng trên hài cốt Đạo Kinh.","chuHienThoi":"Thương Tùng Tử","congNang":["Đánh gãy kiếm của mục tiêu rồi ghim chặt nguyên thần @c1123","Hòa tan vào cơ thể, gây ý niệm điên cuồng muốn giết sạch sinh linh @c127"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1123","denChuong":"","cachCoDuoc":"lấy từ không gian trữ vật trong trận chiến","trangThai":"đã dùng lên Vương Lâm"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"dùng","importance":"normal","giaiDoan":"ghim vai Vương Lâm","text":"Cây đinh bảy màu được Thương Tùng Tử lấy ra, đánh gãy Thiết Kiếm rồi ghim lên vai phải Vương Lâm, khiến hắn chịu thương thế nặng.","anchor":"rõ ràng là uy lực của pháp bảo Thứ Không Niết Bảo","phamCap":"Thứ Không Niết Bảo"},{"chuong":"@c1127","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ qua ngọc giản Tư Mã Đặc và liên hệ Thanh Thủy","text":"Ngọc giản tiết lộ: Tư Mã Đặc bị cây đinh bảy màu đâm vào cơ thể khi cứu Tứ sư thúc ở vị trí sâu nhất, đinh lập tức hòa tan, gây ý niệm điên cuồng. Vương Lâm liên hệ sự điên cuồng của Thanh Thủy trước khi Tiên giới tan vỡ và tại Liên Minh Tu Chân cũng giống hiệu ứng này.","anchor":"Bị một cây đinh bảy màu đâm vào trong cơ thể… Cây đinh này rất quỷ dị, khi tiến vào trong cơ thể thì lập tức hòa tan"}]},"capNhatToi":"@c1123","nguon":["@c1123","@c1127"]},{"id":"diet-than-thuong","name":"Diệt Thần Thương","cn":"","aliases":[],"category":"than-khi","categoryLabel":"Cổ Thần khí/hư ảnh","phamCap":"Cổ Thần khí","soHuu":["Vương Lâm"],"trangThai":"hư ảnh được ngưng hình @c1123","blurb":"Cổ Thần khí được nhắc như vật có thể sánh ngang Tam Xoa Kích khi dùng cho phân thân. Trong trận này, Vương Lâm ngưng tụ tia chớp thành hư ảnh Diệt Thần Thương và ném vào La Bàn khổng lồ.","detail":"Diệt Thần Thương được nhắc trong so sánh với Tam Xoa Kích và xuất hiện dưới dạng hư ảnh do Vương Lâm ngưng tụ từ tia chớp. Hư ảnh này được hắn chụp lấy rồi ném mạnh về phía trước để công kích La Bàn khổng lồ.","phanLoaiPhu":"hư ảnh Cổ Thần khí","uyLuc":"Hư ảnh từ tia chớp được dùng để công kích La Bàn khổng lồ.","chuHienThoi":"Vương Lâm","congNang":["Ngưng hình từ tia chớp để công kích vật cản mạnh @c1123"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1123","denChuong":"","cachCoDuoc":"ngưng tụ hư ảnh trong chiến đấu","trangThai":"đã thi triển hư ảnh"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"dùng","importance":"normal","giaiDoan":"hư ảnh công kích La Bàn","text":"Vương Lâm ngưng tụ tia chớp thành hình bóng Diệt Thần Thương, chụp lấy rồi ném vào La Bàn khổng lồ.","anchor":"Đây chính là hình bóng của Diệt Thần Thương","phamCap":"Cổ Thần khí"}]},"capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"chiec-dinh-bay-mau","name":"Chiếc đinh bảy màu","cn":"七彩钉","aliases":["Cây đinh bảy màu","Đinh bảy màu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực cao)","soHuu":["Thương Tùng Tử"],"trangThai":"mat","blurb":"Chiếc đinh bảy màu là pháp bảo mạnh nhất của Thương Tùng Tử, được lão coi là đòn sát thủ bảo mệnh cấp cao nhất. Trong trận chiến với Vương Lâm, lão đã lấy ra sử dụng nhưng không giết được đối phương, còn khiến bản thân suýt chết và mất đi chiếc đinh.","detail":"Chiếc đinh bảy màu là đòn sát thủ bảo mệnh mà Thương Tùng Tử coi là lá bài cuối cùng, pháp bảo mạnh nhất trong tay lão. Khi lão lấy ra sử dụng trong trận đối đầu với Vương Lâm, chẳng những không giết được đối phương mà bản thân cũng tan vỡ suýt chết. Việc mất chiếc đinh bảy màu là đả kích lớn nhất đối với Thương Tùng Tử.","congNang":["Đòn sát thủ bảo mệnh cấp cao nhất của Thương Tùng Tử @c1124"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1124","denChuong":"@c1124","cachCoDuoc":"Sở hữu từ trước","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1124","loai":"đổi chủ","importance":"major","giaiDoan":"Mất trong trận với Vương Lâm","text":"Thương Tùng Tử sử dụng chiếc đinh bảy màu — đòn sát thủ bảo mệnh — trong trận chiến nhưng không giết được Vương Lâm, bản thân suýt chết, mất đinh. Đây là đả kích lớn nhất của lão.","anchor":"còn có chiếc đinh bảy màu, đây mới chính là đả kích lớn nhất của Thương Tùng Tử"}]},"nguon":["@c1124"]},{"id":"thuy-tinh-kiem","name":"Thủy Tinh Kiếm","cn":"水晶剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thương Tùng Tử"],"trangThai":"ton-hai","blurb":"Pháp bảo của Thương Tùng Tử, bị tổn hại trong trận chiến với Vương Lâm khiến lão đau lòng.","detail":"Thanh kiếm pháp bảo bị tổn hại nặng trong trận chiến, Thương Tùng Tử cảm thấy lòng đau như cắt khi nghĩ đến.","tabs":{"tienTrinh":[{"chuong":"@c1124","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị tổn hại trong trận chiến","text":"Thủy Tinh Kiếm bị tổn hại trong trận chiến với Vương Lâm, Thương Tùng Tử đau lòng.","anchor":"Trong số đó còn có Thủy Tinh Kiếm, đây cũng là thức làm Thương Tùng Tử cảm thấy lòng đau như cắt"}]},"nguon":["@c1124"]},{"id":"binh-ngoc-chat-long-den","name":"Bình ngọc chứa chất lỏng đen","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sở hữu","blurb":"Mục tiêu cuối cùng của Thương Tùng Tử khi vào thế giới bảy màu. Bên trong chứa chất lỏng màu đen giống máu nhưng không mùi tanh, suy đoán liên quan đến tu vi.","detail":"Bình ngọc được Vương Lâm thu lấy sau trận chiến trong thế giới bảy màu. Bên trong chứa chất lỏng màu đen giống máu nhưng không có mùi tanh. Đây là mục tiêu cuối cùng khiến Thương Tùng Tử mạo hiểm vào thế giới bảy màu. Vương Lâm suy đoán nó liên quan đến tu vi, quyết định chờ bắt được nguyên thần Thương Tùng Tử mới tra rõ công dụng.","congNang":["Chưa rõ, suy đoán liên quan đến tu vi"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1125","denChuong":"","cachCoDuoc":"Thu lấy trong thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1125","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm thu lấy","text":"Vương Lâm lấy bình ngọc, tản thần thức vào phát hiện chất lỏng đen giống máu nhưng không tanh, suy đoán liên quan tu vi, cất vào lồng ngực chờ tra rõ.","anchor":"trong bình có một chất lỏng màu đen giống như máu, nhưng lại không có mùi tanh"}]},"nguon":["@c1125"]},{"id":"thanh-doan-kiem-xuong-nai","name":"Thanh đoản kiếm trên bộ xương nai","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Chưa mở được","blurb":"Thanh đoản kiếm lấy từ bộ xương nai trong động phủ, với tu vi Toái Niết trung kỳ của Vương Lâm vẫn không thể mở ra.","detail":"Vương Lâm lấy ra kiểm tra nhưng với tu vi hiện tại không thể mở được, thu lại chờ tu vi cao hơn.","nguon":["@c1126"]},{"id":"nguyen-anh-huyet-sac","name":"Nguyên anh huyết sắc hình người","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang tế luyện","blurb":"Nguyên anh huyết sắc hình người là một pháp bảo có hình dáng giống nguyên anh nhưng bản chất là pháp bảo quỷ dị. Nguyên thuộc về Thương Tùng Tử, về sau bị Vương Lâm đoạt lấy và tế luyện để xóa ký hiệu.","detail":"Pháp bảo mang hình dáng giống nguyên anh, vẻ mặt ủ rũ, mắt lóe hung ác, thỉnh thoảng gầm nhẹ. Vốn thuộc về Thương Tùng Tử, tại mốc @c1126 bị Vương Lâm phun nguyên khí bao bọc rồi đặt vào nguyên thần tế luyện nhằm xóa đi ký hiệu của chủ cũ. Công năng cụ thể của pháp bảo tính tới mốc này vẫn chưa được lộ rõ.","congNang":["Bản chất quỷ dị, giống nguyên anh nhưng là pháp bảo, công năng chưa rõ"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"","denChuong":"@c1126","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1126","denChuong":"","cachCoDuoc":"Đoạt từ Thương Tùng Tử","trangThai":"dang-te-luyen"}],"tabs":{"tienTrinh":[{"chuong":"@c1126","loai":"doi-chu","importance":"major","giaiDoan":"Đổi chủ từ Thương Tùng Tử sang Vương Lâm","text":"Vương Lâm phun nguyên khí bao bọc nguyên anh huyết sắc hình người của Thương Tùng Tử, đặt vào nguyên thần tế luyện xóa ký hiệu.","anchor":"Vật này giống như nguyên anh nhưng lại là pháp bảo, đúng là có chút quỷ dị"}]},"nguon":["@c1126"],"dacDiem":"Hình dáng giống nguyên anh, vẻ mặt ủ rũ, mắt lóe hung ác, gầm nhẹ; bản chất là pháp bảo quỷ dị."},{"id":"ba-ngoc-gian-dong-phu-tu-ma-mac","name":"Ba ngọc giản trong động phủ Tư Mã Mặc","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"","soHuu":["Tư Mã Mặc"],"trangThai":"Mới đọc 1/3","blurb":"Ba khối ngọc giản đặt trước bộ hài cốt Tư Mã Mặc trong động phủ, lưu giữ ký ức và di ngôn của hắn. Vương Lâm đọc khối đầu tiên và biết về khe nứt không gian bảy màu cùng một tồn tại đáng sợ (@c1126).","detail":"Ba ngọc giản được tìm thấy trước hài cốt Tư Mã Mặc, ghi lại lời kể của chủ nhân. Ngọc giản thứ nhất thuật lại việc Tư Mã Mặc thuộc tinh vực Vân Hải, cùng sư thúc và đồng môn theo yêu cầu của một người bí ẩn mà tìm được khe nứt không gian tràn ngập ánh sáng bảy màu; sư muội trong nhóm thích cầu vồng. Khi tiến vào sâu nhất, họ phát hiện một tồn tại đáng sợ cùng bí mật khổng lồ khiến tu chân giới khiếp sợ, rồi tai họa ập xuống khiến bị mắc kẹt cả đời. Hai ngọc giản còn lại chưa được đọc. Trong truyện, ngọc giản đóng vai trò manh mối hé lộ bí mật khe nứt không gian bảy màu khi Vương Lâm khám phá động phủ (@c1126).","tabs":{"tienTrinh":[{"chuong":"@c1126","loai":"xuat-hien","importance":"major","giaiDoan":"Phát hiện và đọc ngọc giản thứ nhất","text":"Vương Lâm phát hiện ba ngọc giản trước bộ hài cốt Tư Mã Mặc và đọc khối đầu tiên, biết về khe nứt không gian bảy màu và bí mật khổng lồ.","anchor":"Không ngờ ta lại có thể quay về nơi này… Năm đó, ta và sư thúc còn có rất nhiều đồng môn theo yêu cầu của người mà tìm được một khe nứt không gian cực kỳ thần bí"}]},"nguon":["@c1126"],"dacDiem":"Ba khối ngọc giản đặt trước bộ hài cốt Tư Mã Mặc trong động phủ; mới chỉ khối thứ nhất được đọc, hai khối còn lại chưa mở.","congNang":["Lưu giữ ký ức và di ngôn của Tư Mã Mặc, có thể đọc để biết nội dung ghi lại (@c1126)","Ngọc giản thứ nhất tiết lộ bí mật về khe nứt không gian bảy màu và tồn tại đáng sợ bên trong (@c1126)"]},{"id":"hat-chau-mo-phong-thien-nghich","name":"Hạt châu mô phỏng Thiên Nghịch","cn":"","aliases":["thạch châu cổ quái"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Hơn mười mấy hạt châu do người xưa tế luyện nhằm mô phỏng Thiên Nghịch để tạo Tiên Nghịch, bên trong đều phong ấn thần thông. Chúng bị coi là sản phẩm thất bại, bị vứt lại trong động phủ (@c1128).","detail":"Hạt châu mô phỏng Thiên Nghịch giống hệt Thiên Nghịch thật về độ lớn, khối lượng, khí tức và thiên đạo, chỉ khác ở chỗ không có đồ án ngũ hành mà chỉ mang những ký hiệu mơ hồ. Bên trong mỗi hạt đều có con sóng dao động thần thông bị phong ấn. Vương Lâm phát hiện hơn mười mấy hạt trong động phủ và xác định đây là bản mô phỏng, đồng thời suy đoán kẻ chế tạo từng tận mắt thấy hoặc nắm giữ Thiên Nghịch thật (@c1128).","congNang":["Phong ấn thần thông bên trong, mỗi hạt chứa một con sóng dao động thần thông bị phong ấn"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1128","denChuong":"","cachCoDuoc":"Thu từ động phủ trong thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1128","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và thu","text":"Vương Lâm phát hiện hơn mười mấy hạt châu giống hệt Thiên Nghịch trong động phủ, xác định là bản mô phỏng do người xưa tế luyện nhằm tạo Tiên Nghịch, bên trong phong ấn thần thông. Để dấu ấn rồi thu vào trữ vật.","anchor":"bên trong hạt châu đều có những con sóng dao động thần thông"}]},"nguon":["@c1128"],"dacDiem":"Giống hệt Thiên Nghịch về độ lớn, khối lượng, khí tức và thiên đạo, chỉ khác không có đồ án ngũ hành mà chỉ có ký hiệu mơ hồ"},{"id":"dan-duoc-cap-muoi-mot","name":"Đan dược cấp mười một","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp mười một","soHuu":["Vương Lâm"],"trangThai":"đang luyện hóa","blurb":"Ba viên đan đỏ từ di vật Tư Mã Mặc, chỉ tu sĩ Toái Niết trung kỳ mới nuốt trực tiếp được, Vương Lâm phải luyện hóa lại để phân tán lực lượng.","detail":"Ba viên đan màu đỏ trong bình thứ nhất, thú hồn dao động khi mở nắp. Tu sĩ Tịnh Niết sơ kỳ không thể nuốt trực tiếp, cần luyện hóa lại trong lò để phân tán lực lượng.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1128","denChuong":"","cachCoDuoc":"Đoạt từ động phủ thứ ba trong thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1128","loai":"xuất hiện","importance":"normal","giaiDoan":"Đoạt được và bắt đầu luyện hóa","text":"Vương Lâm đoạt từ động phủ thứ ba bằng trận pháp hình thoi, xác nhận là đan cấp mười một. Bắt đầu luyện hóa lại trong lò vì cảnh giới hiện tại chỉ Tịnh Niết sơ kỳ.","anchor":"Đan dược cấp mười một?"}]},"nguon":["@c1128"]},{"id":"vu-hon-dan","name":"Vụ Hồn Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp mười hai","soHuu":["Vương Lâm"],"trangThai":"đang giữ","blurb":"Hai viên đan luyện từ mãnh thú hóa sương cấp mười hai, cực hiếm ở Vân Hải tinh vực, sương đen trắng vờn quanh.","detail":"Luyện từ mãnh thú hóa sương cấp mười hai, có sương đen trắng vờn quanh bên ngoài. Cực hiếm ở Vân Hải tinh vực vì ít ai chịu bỏ lợi ích nguyên tinh để luyện chế.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1128","denChuong":"","cachCoDuoc":"Đoạt từ động phủ thứ ba trong thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1128","loai":"xuất hiện","importance":"normal","giaiDoan":"Đoạt được","text":"Vương Lâm đoạt hai viên Vụ Hồn Đan từ bình thứ hai trong động phủ thứ ba, xác nhận luyện từ mãnh thú hóa sương cấp mười hai.","anchor":"Vụ Hồn Đan dùng mãnh thú hóa sương cấp mười hai luyện chế ra"}]},"nguon":["@c1128"]},{"id":"dan-duoc-cap-muoi-ba","name":"Đan dược cấp mười ba","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cấp mười ba","soHuu":["Vương Lâm"],"trangThai":"đang giữ","blurb":"Viên đan dược cấp mười ba đựng trong bình thứ ba, uy lực vượt xa mãnh thú cấp mười hai, là di vật quý nhất Tư Mã Mặc để lại cho đồng môn. Khi Vương Lâm mở bình, viên đan bùng phát tiếng gầm rống kinh thiên động địa khiến hắn phải lập tức đóng nút.","detail":"Đan dược cấp mười ba là món quý nhất trong ba bình đan dược mà Tư Mã Mặc để lại.Ở mốc @c1128, khi Vương Lâm mở bình thứ ba, viên đan phát ra tiếng gầm rống kinh thiên động địa vượt xa mãnh thú cấp mười hai, uy thế lớn đến mức khiến Vương Lâm tái mặt và phải đóng nút bình ngay lập tức.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1128","denChuong":"","cachCoDuoc":"Đoạt từ động phủ thứ ba trong thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1128","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện","text":"Vương Lâm mở bình thứ ba, bùng tiếng gầm kinh thiên động địa vượt xa mãnh thú cấp mười hai, tái mặt đóng nút ngay, xác định là đan cấp mười ba quý nhất trong di vật Tư Mã Mặc.","anchor":"Đan dược cấp mười ba!"}]},"nguon":["@c1128"],"uyLuc":"Uy lực vượt xa mãnh thú cấp mười hai, tiếng gầm khi mở bình khiến Vương Lâm tái mặt phải đóng nút ngay @c1128","dacDiem":"Di vật quý nhất trong ba bình đan dược Tư Mã Mặc để lại, đựng trong bình thứ ba","congNang":["Khi mở bình bùng phát tiếng gầm rống kinh thiên động địa vượt xa mãnh thú cấp mười hai @c1128"]},{"id":"lo-luyen-dan-dong-phu-thu-hai","name":"Lò luyện đan (động phủ thứ hai)","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Lò luyện đan khổng lồ chiếm hơn nửa động phủ thứ hai, Vương Lâm dùng để luyện hóa lại đan cấp mười một.","detail":"Lò khổng lồ chiếm hơn phân nửa khoảng không trong động phủ, phủ đầy bụi. Vương Lâm dung nhập ánh lửa mắt trái vào lò, mặt lò huyễn ra ký hiệu xoay chuyển, dùng để luyện hóa phân tán lực lượng đan cấp cao cho phù hợp cảnh giới thấp hơn.","congNang":["Luyện hóa phân tán lực lượng đan cấp cao"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1128","denChuong":"","cachCoDuoc":"Tìm thấy trong động phủ thứ hai thế giới bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1128","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng luyện đan","text":"Vương Lâm phát hiện lò luyện đan khổng lồ trong động phủ thứ hai, dùng ánh lửa mắt trái dung nhập và bắt đầu luyện hóa lại đan cấp mười một.","anchor":"Một lò luyện đan khổng lồ chiếm giữ hơn phân nửa khoảng không trong động phủ"}]},"nguon":["@c1128"]},{"id":"dan-duoc-chat-long-mau-vang","name":"Đan dược chất lỏng màu vàng","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Đan dược luyện từ thú hồn trong lò luyện đan hai ngày, thu vào ba bình nhỏ, giúp người uống cảm ngộ minh ngộ thiên địa của thú hồn để chứng ngộ đạo niệm.","detail":"Vương Lâm luyện hóa thú hồn trong lò luyện đan suốt hai ngày thành chất lỏng màu vàng, thu vào ba chiếc bình nhỏ. Uống vào hóa thành khí tươi mát vận chuyển toàn thân, bên tai mơ hồ vang tiếng gầm mãnh thú, giúp cảm ngộ minh ngộ của thú hồn đối với thiên địa. Vương Lâm dùng đan dược này không phải để tăng tu vi mà để chứng minh thật-giả đạo niệm bản thân.","congNang":["Truyền minh ngộ thiên địa của thú hồn cho người uống","Hỗ trợ chứng ngộ đạo niệm thật-giả"],"nguonGoc":"Vương Lâm tự luyện từ thú hồn trong lò luyện đan tại động phủ Tư Mã Đặc","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1129","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1129","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện chế và sử dụng","text":"Vương Lâm luyện hóa thú hồn hai ngày thành chất lỏng màu vàng thu vào ba bình nhỏ rồi uống hết để chứng ngộ đạo niệm thật-giả.","anchor":"chất lỏng màu vàng bay bổng giữa không trung"}]},"capNhatToi":"@c1129","dinhDanh":"goc","nguon":["@c1129"]},{"id":"tam-bia-da-khong-chu","name":"Tấm bia đá không chữ (ngọn núi thứ nhất)","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ (giống pháp khí)","soHuu":[],"trangThai":"dang-co","blurb":"Tấm bia đá không ghi chữ nào nằm trong ngọn núi thứ nhất bị Tuế Nguyệt Cấm bao quanh, toát khí tức tang thương rồi tiêu tán, trong mắt Vương Lâm giống một kiện pháp khí.","detail":"Nằm cô độc trong ngọn núi thứ nhất ẩn sau sương mù dãy núi vòng cung. Không có chữ viết nào trên bia, nhưng bùng lên luồng khí tức tang thương rồi nhanh chóng tiêu tán. Vương Lâm nhận định nó giống một kiện pháp khí.","congNang":["Toát khí tức tang thương (chưa rõ công dụng cụ thể)"],"tabs":{"tienTrinh":[{"chuong":"@c1130","loai":"xuất hiện","importance":"normal","giaiDoan":"Được tâm thần Vương Lâm phát hiện","text":"Tâm thần Vương Lâm xuyên qua Tuế Nguyệt Cấm vào ngọn núi thứ nhất, phát hiện tấm bia đá không chữ toát khí tức tang thương giống pháp khí.","anchor":"chỉ có duy nhất một tấm bia đá không được ghi chữ nào, nhưng trong mắt Vương Lâm lại bùng lên một luồng khí tức tang thương"}]},"nguon":["@c1130"]},{"id":"nua-bo-hai-cot-dong-phu-thu-tam","name":"Nửa bộ hài cốt (động phủ thứ tám)","aliases":["Nửa bộ hài cốt trên bia đá"],"category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Nửa bộ hài cốt bí ẩn ẩn giấu trong không gian bí mật của ngọn núi thứ hai thuộc động phủ thứ tám, bị hai cây đinh bảy màu ghim xuống, trên khung xương khắc chữ viết dày đặc với nội dung dâng tặng Tu Chân Hành.","detail":"Nằm trong không gian ẩn giấu bên trong ngọn núi thứ hai bị Tuế Nguyệt Cấm bao quanh, nửa bộ hài cốt bị hai cây đinh bảy màu ghim lên. Trên khung xương khắc dày đặc chữ viết, nội dung chính là dâng tặng Tu Chân Hành. Những lời này chính là âm thanh từng vang vọng trong tâm thần Vương Lâm trước đây, khiến tâm thần hắn chấn động dữ dội khi phát hiện ra không gian ẩn giấu này (@c1130).","congNang":["Chứa thông điệp dâng tặng Tu Chân Hành khắc dày đặc trên khung xương","Nội dung khắc trên xương trùng khớp với âm thanh từng vang vọng trong tâm thần Vương Lâm, khiến tâm thần hắn chấn động khi phát hiện @c1130"],"tabs":{"tienTrinh":[{"chuong":"@c1130","loai":"xuất hiện","importance":"major","giaiDoan":"Được tâm thần Vương Lâm phát hiện","text":"Tâm thần Vương Lâm phát hiện không gian ẩn giấu trong ngọn núi thứ hai, bên trong có nửa bộ hài cốt bị hai cây đinh bảy màu ghim, trên xương khắc chữ dâng tặng Tu Chân Hành — trùng khớp âm thanh từng vang vọng trong tâm thần hắn, gây chấn động mãnh liệt.","anchor":"những chữ viết bên trên giống như khắc sâu vào tận tâm can. Những lời nói này đều là âm thanh trước đây vang vọng trong tâm thần Vương Lâm, dâng tặng Tu Chân Hành"}]},"nguon":["@c1130"],"dacDiem":"Bị hai cây đinh bảy màu ghim xuống, khung xương khắc chữ viết dày đặc, ẩn giấu trong không gian bí mật của ngọn núi thứ hai."},{"id":"thu-hon-phong-an-ngon-nui-thu-hai","name":"Thú hồn phong ấn trong ngọn núi thứ hai","category":"khac","categoryLabel":"Kho vật phẩm","phamCap":"Cấp 7 đến cấp 13","soHuu":[],"trangThai":"dang-co","blurb":"Từng mảng hào quang trôi nổi bên trong cửa đá ký hiệu tia chớp ở ngọn núi thứ hai, mỗi luồng hào quang phong ấn một thú hồn, thấp nhất cấp bảy, cao nhất cấp mười ba.","detail":"Nằm bên trong cửa đá cực lớn có ký hiệu hình tia chớp ở ngọn núi thứ hai trong sương mù. Từng mảng hào quang trôi nổi, mỗi luồng phong ấn một thú hồn. Dải cấp bậc rất rộng từ cấp bảy đến cấp mười ba. Liên quan đến Thiên Lôi Tộc (cửa đá có ký hiệu tia chớp).","congNang":["Kho thú hồn phong ấn đa cấp bậc"],"tabs":{"tienTrinh":[{"chuong":"@c1130","loai":"xuất hiện","importance":"normal","giaiDoan":"Được tâm thần Vương Lâm phát hiện","text":"Tâm thần Vương Lâm nhìn vào bên trong cửa đá ký hiệu tia chớp, thấy từng mảng hào quang phong ấn thú hồn từ cấp bảy đến cấp mười ba.","anchor":"trong mỗi một luồng hào quang đều được phong ấn một thú hồn. Những thú hồn này thấp nhất là cấp bảy và cao nhất là cấp mười ba"}]},"nguon":["@c1130"]},{"id":"khoi-tinh-thach-den","name":"Khối tinh thạch đen (đạo niệm ngưng tụ)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Sánh pháp bảo cực mạnh","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối tinh thạch đen là pháp bảo do Vương Lâm ngưng tụ từ những đạo niệm hỗn tạp bị vứt bỏ trong quá trình cảm ngộ ý cảnh tại thế giới bảy màu. Uy lực của nó nhắm vào đạo tâm tu sĩ Toái Niết, có thể khiến đạo tâm tan vỡ.","detail":"Khối tinh thạch đen hình thành từ những đạo niệm hỗn tạp bị tách ra và vứt bỏ khi Vương Lâm cảm ngộ ý cảnh tại thế giới bảy màu. Tại mốc xuất hiện, Vương Lâm dùng ngón tay phải triệu hồi toàn bộ đạo niệm đã vứt bỏ, ngưng tụ chúng thành vòng sáng đen rồi nén lại thành một khối tinh thạch màu đen (@c1131). Nếu nổ tung đánh trúng tu sĩ Toái Niết thì đạo tâm của đối phương sẽ tan vỡ.","nguonGoc":"Đạo niệm bị vứt bỏ trong quá trình cảm ngộ ý cảnh tại thế giới bảy màu","hinhDang":"Khối tinh thạch màu đen","congNang":["Ngưng tụ từ toàn bộ đạo niệm đã vứt bỏ trong thế giới bảy màu, nén thành khối tinh thạch đen @c1131","Nổ tung phá đạo tâm tu sĩ Toái Niết"],"uyLuc":"Nổ tung đánh trúng tu sĩ Toái Niết khiến đạo tâm tan vỡ.","dacDiem":"Hình thành từ đạo niệm hỗn tạp bị vứt bỏ, màu đen.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1131","denChuong":"","cachCoDuoc":"Tự ngưng tụ đạo niệm đã vứt bỏ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1131","loai":"xuất hiện","importance":"major","giaiDoan":"Hình thành","text":"Vương Lâm triệu hồi toàn bộ đạo niệm đã vứt bỏ trong thế giới bảy màu, ngưng tụ nén thành khối tinh thạch đen, uy lực sánh pháp bảo cực mạnh.","anchor":"vật này là những đạo niệm tách ra từ bên trong đan dược, nó cũng có thể so sánh với một pháp bảo cực mạnh"}]},"capNhatToi":"@c1131","nguon":["@c1131"]},{"id":"hat-huyet-chau-thuong-tung-tu","name":"Hạt huyết châu","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tàn dư lực lượng Thương Tùng Tử sau khi chết bởi cây đinh bảy màu, ngưng tụ thành hạt châu huyết sắc.","detail":"Thương Tùng Tử phát cuồng chết, toàn thân héo rũ tiêu tán hóa thành hạt châu huyết sắc bùng huyết quang, phóng lên trời. Bị Vương Lâm chụp lấy, giãy giụa kéo Vương Lâm lên trời trước khi bị khống chế nhờ phản ứng Nghịch Thiên Châu.","congNang":["Chứa tàn dư sinh cơ và lực lượng Thương Tùng Tử"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1132","denChuong":"","cachCoDuoc":"Chụp lấy sau khi giết Thương Tùng Tử","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1132","loai":"xuất hiện","importance":"normal","giaiDoan":"Thương Tùng Tử hóa huyết châu","text":"Thương Tùng Tử chết trong điên cuồng, thân thể héo rũ tiêu tán hóa thành hạt châu huyết sắc bay lên trời, bị Vương Lâm chụp lấy.","anchor":"thân thể lão đã héo rũ và tiêu tán rồi hóa thành một hạt châu huyết sắc"}]},"nguon":["@c1132"]},{"id":"ngoc-gian-truyen-am-vuong-lam-tran-thien-quan","name":"Ngọc giản truyền âm (Vương Lâm đưa Trần Thiên Quân)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Trần Thiên Quân"],"trangThai":"dang-co","blurb":"Khối ngọc giản Vương Lâm đưa cho Trần Thiên Quân để liên lạc sau khi thu nguyên tinh.","detail":"Vương Lâm đưa cho Trần Thiên Quân một khối ngọc giản truyền âm để liên lạc khi hoàn thành thu thập nguyên tinh từ mãnh thú hóa sương.","congNang":["Truyền âm liên lạc"],"chuSoHuu":[{"ten":"Trần Thiên Quân","tuChuong":"@c1132","denChuong":"","cachCoDuoc":"Được Vương Lâm đưa","trangThai":"dang-co"}],"nguon":["@c1132"]},{"id":"ngoc-gian-cung-dien-thai-co-tinh-vuc","name":"Ngọc giản trong cung điện Thái Cổ tinh vực","cn":"","category":"khac","categoryLabel":"Bí vật","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Các khối ngọc giản khắc tên nằm trong cung điện bí ẩn ở cấm địa Thái Cổ tinh vực, liên kết sinh mệnh những người được khắc tên. Khi một người chết, ngọc giản mang tên ngườiấy vỡ tan rồi thời gian nghịch chuyển tái ngưng tụ, đổi sang một cái tên mới.","detail":"Nhiều khối ngọc giản nằm trong luồng sáng bảy màu bên trong cung điện, khắc tên Thanh Thủy, Thiên Vận Tử, Trọng Huyền Tử, Thủy Đạo Tử, Tư Mã Mặc và Thương Tùng Tử. Khi Thương Tùng Tử chết, ngọc giản mang tên lão vỡ tan, sau đó thời gian nghịch chuyển tái ngưng tụ và đổi tên thành Vương Lâm (@c1132). Các khối ngọc giản phản ánh con mồi tiếp theo của thế lực bí ẩn trong cung điện.","congNang":["Liên kết sinh mệnh người được khắc tên","Nghịch chuyển thời gian tái ngưng tụ khi vỡ, đổi sang tên mới @c1132"],"tabs":{"tienTrinh":[{"chuong":"@c1132","loai":"xuất hiện","importance":"major","giaiDoan":"Ngọc giản Thương Tùng Tử vỡ, đổi tên Vương Lâm","text":"Ngọc giản mang tên Thương Tùng Tử vỡ tan khi lão chết, thời gian nghịch chuyển tái ngưng tụ đổi tên thành Vương Lâm. Giọng nói bí ẩn thì thào về việc cần linh hồn Vương Lâm để thành đạo.","anchor":"Ngọc giản đã vở tan lập tức xuất hiện nghịch biến, lại được ngưng tụ giống như tất cả tình cảnh xuất hiện vừa rồi chưa từng được xảy ra"}]},"nguon":["@c1132"],"dacDiem":"Nằm trong luồng sáng bảy màu, khắc tên người là mục tiêu của thế lực bí ẩn trong cung điện Thái Cổ tinh vực."},{"id":"nua-bo-hai-cot-phan-duoi","name":"Nửa bộ hài cốt phần dưới (động phủ thứ tám)","cn":"","aliases":[],"category":"khac","categoryLabel":"Dị vật","phamCap":"Không rõ","soHuu":[],"trangThai":"phong-an","blurb":"Phần dưới của hài cốt bị tách khỏi bia đá, được phong ấn trong động phủ thứ tám. Trên khung xương phủ kinh văn đen, tỏa ra lực hút tâm thần cực mạnh, riêng đùi phải có một vết nứt rất sâu.","detail":"Nửa bộ hài cốt phần dưới bị trận pháp phong ấn trong động phủ thứ tám ở sơn cốc thế giới bảy màu, chính là nguyên nhân khiến một tấm bia đá mất đi nửa bộ hài cốt. Trên khung xương khắc rất nhiều kinh văn đen, tỏa ra lực hút khổng bố muốn hấp thu tâm thần kẻ tiếp cận. Trên đùi phải có vết nứt rất sâu, và Vương Lâm dung nhập tâm thần qua vết nứt này để cảm ngộ. Khi Vương Lâm mở cấm chế bình thường tiến vào động phủ thứ tám, hắn phát hiện ra nửa bộ hài cốt đang bị trận pháp phong ấn (@c1133).","congNang":["Kinh văn đen trên xương là thần thông hóa thành, có thể chuyển hóa đạo thành đạo tủy","Lực hút tâm thần khổng bố, hấp thu tâm thần người tiếp cận"],"tabs":{"tienTrinh":[{"chuong":"@c1133","loai":"xuat-hien","importance":"major","giaiDoan":"Phát hiện trong động phủ thứ tám","text":"Vương Lâm mở cấm chế bình thường vào động phủ thứ tám, phát hiện nửa bộ hài cốt phần dưới bị trận pháp phong ấn, kinh văn đen trên khung xương, lực hút tâm thần khổng bố. Đây là nguyên nhân một tấm bia đá mất nửa bộ hài cốt. Hắn liều mạng dung nhập tâm thần vào vết nứt trên đùi phải hài cốt để cảm ngộ.","anchor":"Nửa bộ hài cốt này chính là phần bên dưới, bên trên khung xương có rất nhiều kinh văn"}]},"nguon":["@c1133"],"dacDiem":"Khung xương phủ kinh văn đen, đùi phải có vết nứt rất sâu; bị trận pháp phong ấn trong động phủ thứ tám."},{"id":"chu-chien-hu-ao","name":"Chữ Chiến hư ảo","cn":"","category":"phap-bao","categoryLabel":"Bảo vật / Di sản","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Chữ Chiến hư ảo chứa chiến ý và di ngôn của Chiến Tinh Dã, dung hợp kim quang từ nửa bộ hài cốt rồi nhập vào mi tâm Vương Lâm, khiến ý cảnh y bắt đầu dung nhập chiến ý.","detail":"Chữ Chiến hư ảo bùng kim quang, được Vương Lâm lấy ra từ không gian trữ vật. Khi tiếp cận nửa bộ hài cốt bị đinh bảy màu ghim trên bia đá, kim quang từ hài cốt phóng ra dung hợp vào chữ Chiến, khiến toàn bộ trời đất bao phủ kim quang. Sau đó chữ Chiến phóng thẳng vào mi tâm Vương Lâm, truyền di ngôn và chiến ý của Chiến Tinh Dã, khiến ý cảnh Vương Lâm bắt đầu dung nhập chiến ý với biến hóa kinh người (@c1136).","congNang":["Truyền thừa chiến ý và di ngôn Chiến Tinh Dã @c1136","Dung hợp kim quang từ nửa bộ hài cốt @c1136","Thay đổi ý cảnh người tiếp nhận khi dung nhập, gây biến hóa kinh người @c1136"],"chuSoHuu":[{"ten":"Chiến Tinh Dã","tuChuong":"","denChuong":"@c1136","cachCoDuoc":"Chủ nhân gốc","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1136","denChuong":"","cachCoDuoc":"Dung hợp nhập mi tâm","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1136","loai":"đổi chủ","importance":"major","giaiDoan":"Dung hợp nhập mi tâm Vương Lâm","text":"Chữ Chiến dung hợp kim quang từ nửa bộ hài cốt rồi nhập vào mi tâm Vương Lâm, truyền di ngôn và chiến ý Chiến Tinh Dã.","anchor":"chữ chiến hư ảo đang bùng ra kim quang từ trong khe nứt trữ vật bay ra"}]},"nguon":["@c1136"],"dacDiem":"Hư ảo, bùng phát kim quang bao phủ trời đất khi dung hợp hài cốt @c1136"},{"id":"tam-bia-da-khong-lo","name":"Tấm bia đá khổng lồ (không gian kỳ dị)","cn":"","category":"khac","categoryLabel":"Vật thể","phamCap":"","soHuu":[],"trangThai":"","blurb":"Bia đá trong không gian kỳ dị, vật liệu quen mắt nhưng Vương Lâm không nhớ ra. Nửa bộ hài cốt Chiến Tinh Dã bị ghim chặt trên đó.","detail":"Tấm bia đá khổng lồ nằm trong không gian kỳ dị bên trong khe nứt. Bao phủ khí tức tang thương, ẩn chứa dấu vết năm tháng. Vương Lâm cảm thấy vật liệu của bia đá có vẻ quen mắt nhưng không nhớ ra đã gặp ở đâu. Nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt trên bia đá này.","tabs":{"tienTrinh":[{"chuong":"@c1136","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm phát hiện","text":"Vương Lâm tiến vào không gian kỳ dị, nhìn thấy tấm bia đá khổng lồ với nửa bộ hài cốt bị ghim chặt.","anchor":"hắn cũng cảm giác được vật liệu này vó vẻ quen mắt, nhưng hắn cũng không nghĩ ra"}]},"nguon":["@c1136"]},{"id":"toc-linh-hoa-tuoc-toc","name":"Tộc linh Hỏa Tước Tộc (chim lửa đen)","cn":"","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Hỏa Tước Tộc"],"trangThai":"mat","blurb":"Linh vật bộ tộc Hỏa Tước, con chim lửa đen khổng lồ được triệu hoán từ nguyên thần tan vỡ của tộc nhân. Bị Chu Tước thật của Vương Lâm thôn phệ hoàn toàn.","detail":"Toàn thân màu đen, thoạt nhìn giống chim lửa hơn là Chu Tước, không phải Chu Tước thật mà chỉ là bản sao yếu hơn. Được triệu hoán bằng bí thuật Triệu hoán Tộc linh khi tộc nhân hy sinh nguyên thần. Bị Chu Tước thật (trắng) của Vương Lâm khinh thường rồi thôn phệ hoàn toàn cả ngọn lửa lẫn linh hồn.","congNang":["Linh vật bộ tộc Hỏa Tước, được triệu hoán để chiến đấu thay tộc nhân"],"tabs":{"tienTrinh":[{"chuong":"@c1137","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện và bị tiêu diệt","text":"Được người Hỏa Tước Tộc triệu hoán bằng nguyên thần tan vỡ, xuất hiện dưới dạng chim lửa đen khổng lồ nhưng bị Chu Tước thật thôn phệ hoàn toàn.","anchor":"Thoạt nhìn thì không giống Chu Tước mà giống hệt như một con chim lửa khổng lồ"}]},"nguon":["@c1137"]},{"id":"chin-pho-tuong-co-than-nguyet-phe-toc","name":"Chín pho tượng Cổ Thần (cấm địa Nguyệt Phệ tộc)","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm / Tượng khổng lồ","phamCap":"Không rõ","soHuu":["Nguyệt Phệ tộc"],"trangThai":"hong","blurb":"Chín pho tượng Cổ Thần khổng lồ được dựng trong cấm địa Nguyệt Phệ tộc, dùng để cưỡng chế chứa đựng và hấp thu lực lượng Cổ Thần. Đến khi Vương Lâm xóa quy ước Thái Cổ, chín pho tượng đồng loạt nứt vỡ và lực lượng Cổ Thần tiêu tán trong trời đất.","detail":"Chín pho tượng Cổ Thần là những pho tượng khổng lồ đặt tại cấm địa của Nguyệt Phệ tộc, giữ vai trò chứa đựng và hấp thu lực lượng Cổ Thần cho tộc này. Khi Vương Lâm xóa bỏ quy ước Thái Cổ, chín pho tượng đồng loạt lâm vào cảnh tan vỡ: pho tượng đầu tiên sụp đổ ầm ầm, pho thứ hai hóa thành bụi, bảy pho còn lại xuất hiện dấu hiệu tan vỡ, kéo theo lực lượng Cổ Thần tiêu tán trong trời đất (@c1139).","congNang":["Chứa và hấp thu lực lượng Cổ Thần cho Nguyệt Phệ tộc @c1139"],"tabs":{"tienTrinh":[{"chuong":"@c1139","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Sụp đổ do quy ước Thái Cổ bị xóa","text":"Pho tượng đầu tiên sụp đổ ầm ầm, pho thứ hai hóa bụi, bảy pho còn lại xuất hiện dấu hiệu tan vỡ. Lực lượng Cổ Thần tiêu tán trong trời đất.","anchor":"pho tương Cổ Thần đầu tiên đã sụp đổ ầm ầm, lực lượng Cổ Thần tiêu tán trong trời đất"}]},"capNhatToi":"@c1139","nguon":["@c1139"],"dacDiem":"Chín pho tượng khổng lồ đặt trong cấm địa Nguyệt Phệ tộc"},{"id":"chin-khoi-xuong-thu","name":"Chín khối xương thú (của lão già tóc trắng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lão già tóc trắng (ngọn núi thế giới bảy màu)"],"trangThai":"dang-dung","blurb":"Chín khối xương thú vờn quanh thân lão già tóc trắng, dùng để chiến đấu và mở đường trong biển lửa, nhưng gần tới hạn chịu đựng trước lửa lam sắc của Vương Lâm.","detail":"Vờn quanh thân lão già tóc trắng, giúp ép ngọn lửa lam sắc mở đường. Khi tiếp cận biển lửa vạn trượng phát ra tiếng nổ ầm ầm, sắp không chịu nổi nhiệt lượng mà tan vỡ.","congNang":["Vờn quanh thân chủ, mở đường trong lửa, nhưng gần tới hạn chịu đựng trước lửa lam sắc"],"chuSoHuu":[{"ten":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","tuChuong":"@c1141","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1141","loai":"dùng","importance":"normal","giaiDoan":"Chiến đấu với Vương Lâm","text":"Chín khối xương thú vờn quanh thân lão già, ép lửa lam sắc mở đường nhưng phát tiếng nổ, sắp không chịu nổi nhiệt lượng biển lửa vạn trượng.","anchor":"Chín khối xương thú quanh thân thể lão già đột nhiên phát ra những tiếng nổ ầm ầm"}]},"nguon":["@c1141"]},{"id":"phap-bao-ton-gia-ban","name":"Pháp bảo do Tôn giả ban tặng (cho lão già tóc trắng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lão già tóc trắng (ngọn núi thế giới bảy màu)"],"trangThai":"chua-lo-dien","blurb":"Pháp bảo do Tôn giả ban cho lão già tóc trắng, lão tự tin lửa lam sắc của Vương Lâm không thể phá nổi. Chưa lộ diện cụ thể.","detail":"Lão già tóc trắng tự tin khẳng định lửa Vương Lâm không phá được pháp bảo này. Chưa lộ hình dạng hay công năng cụ thể trong chương.","congNang":["Được cho là miễn nhiễm lửa lam sắc của Vương Lâm"],"chuSoHuu":[{"ten":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","tuChuong":"@c1141","denChuong":"","cachCoDuoc":"Tôn giả ban tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1141","loai":"nhắc tới","importance":"normal","giaiDoan":"Lão già tóc trắng đề cập khi đối đầu Vương Lâm","text":"Lão già tóc trắng tự tin tuyên bố lửa Vương Lâm không phá được pháp bảo do Tôn giả ban tặng.","anchor":"Ngọn lửa của ngươi không phá được pháp bảo này đâu"}]},"nguon":["@c1141"]},{"id":"xich-sat-den-tam-soi","name":"Xích sắt đen (tám sợi)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thanh Long Thánh Hoàng"],"trangThai":"da-dung","blurb":"Tám sợi xích sắt đen khoá chặt Thanh Long Thánh Hoàng trong mật thất, ghim vào bốn vách tường, dùng để trấn áp nội hoạ. Tiêu tán sau khi lão xuất quan.","detail":"Tám sợi xích sắt đen khoá chặt Thanh Long Thánh Hoàng trên hai vai, hai chân, hai tay, trước sau ngực, ghim vào bốn vách tường trong mật thất đại điện Thanh Long. Tiêu tán khi lão xuất quan.","nguon":["@c1141"]},{"id":"bo-giap-chu-tuoc-lam-sac","name":"Bộ giáp Chu Tước lam sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Bộ giáp Chu Tước lam sắc là khôi giáp hình Chu Tước toàn thân lam sắc, xuất hiện bên ngoài cơ thể Vương Lâm khi Chu Tước thức tỉnh lần ba dung nhập mi tâm. Bộ giáp hấp thu lửa lam ngưng tụ từ thiên địa tuôn vào mi tâm, biến chủ nhân thành dạng Chu Tước chiến đấu.","detail":"Bộ giáp Chu Tước lam sắc sinh ra khi Chu Tước thức tỉnh lần ba dung nhập mi tâm Vương Lâm (@c1142). Khi ấy bên ngoài cơ thể Vương Lâm xuất hiện bộ giáp có hình dạng Chu Tước, toàn thân lam sắc, khiến ông trông giống một Chu Tước cực kỳ cao quý. Bộ giáp hấp thu và tuần hoàn lửa lam ngưng tụ từ thiên địa rồi tuôn vào mi tâm, biến chủ nhân thành dạng Chu Tước chiến đấu.","phanLoaiPhu":"Khôi giáp chiến đấu","hinhDang":"Hình dạng Chu Tước toàn thân lam sắc","nguonGoc":"Sinh ra khi Chu Tước thức tỉnh lần ba dung nhập mi tâm","congNang":["Hấp thu và tuần hoàn lửa lam từ thiên địa, tuôn vào mi tâm chủ nhân @c1142","Biến chủ nhân thành dạng Chu Tước chiến đấu @c1142"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1142","denChuong":"","cachCoDuoc":"Tự sinh khi Chu Tước thức tỉnh lần ba","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1142","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Xuất hiện bên ngoài cơ thể Vương Lâm khi Chu Tước lam sắc dung nhập mi tâm, hấp thu lửa lam thiên địa tuôn vào mi tâm.","anchor":"một bộ giáp có hình dạng của Chu Tước, toàn thân đều có màu lam"}]},"nguon":["@c1142"],"dacDiem":"Khôi giáp hình Chu Tước toàn thân lam sắc, khiến chủ nhân trông giống một Chu Tước cực kỳ cao quý"},{"id":"bay-cay-hoa-bay-mau","name":"Bảy cây hoa bảy màu","cn":"","category":"khac","categoryLabel":"Thực vật thần bí / trọng bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Bảy cây thực vật hình hoa, mỗi cây một màu, cao khoảng trăm trượng, mọc ở trung tâm đại trận tinh không. Chúng là nguồn sống duy trì toàn bộ tinh vực, được nuôi dưỡng từ thượng cổ bằng hệ thống Loại Đạo với đạo niệm cùng sinh linh chết trên Phong giới. Tính tới thời điểm linh hồn Vương Lâm xuyên vào tinh không, cây hoa đỏ máu đã kết Đạo quả đầu tiên, sáu cây còn lại cũng sắp kết.","detail":"Bảy cây hoa bảy màu nằm ở trung tâm đại trận tinh vực, mỗi cây một màu, cao khoảng trăm trượng. Bên trong mỗi cây có một bộ hài cốt khoanh chân ngồi khắc kinh văn, bùng ra hắc quang bị cây hoa hấp thu (@c1146). Toàn bộ tinh không và trận pháp bên trong đều nhờ bảy cây hoa cung cấp dưỡng chất mà tồn tại. Chúng được nuôi dưỡng từ thượng cổ bằng hệ thống Loại Đạo, do người nuôi hoa chăm sóc theo lời Chưởng Tôn, hấp thu đạo niệm và sinh linh chết trên Phong giới để kết Đạo quả. Khi linh hồn Vương Lâm xuyên vào tinh không, cây hoa đỏ máu đã kết Đạo quả đầu tiên, sáu cây còn lại cũng sắp kết.","congNang":["Hấp thu đạo niệm và sinh linh để kết Đạo quả (@c1146)","Cung cấp dưỡng chất duy trì toàn bộ tinh không và trận pháp bên trong"],"hinhDang":"Hình hoa, mỗi cây một màu trong bảy màu, cao khoảng trăm trượng","dacDiem":"Mỗi cây một màu, cao khoảng trăm trượng; bên trong mỗi cây chứa một bộ hài cốt khoanh chân ngồi khắc kinh văn, tồn tại từ thượng cổ","nguonGoc":"Được nuôi bằng hệ thống Loại Đạo từ thượng cổ, do người nuôi hoa chăm sóc theo lời Chưởng Tôn","tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện và kết Đạo quả đầu tiên","text":"Linh hồn Vương Lâm xuyên vào tinh không, lộ ra bảy cây hoa bảy màu ở trung tâm đại trận. Cây hoa đỏ máu hấp thu linh hồn và hài cốt bên trong, trải qua 98 năm kết thành Đạo quả đỏ — cây đầu tiên trong bảy cây kết quả.","anchor":"Toàn bộ tinh không, tất cả trận pháp bên trong đều được bảy cây hoa kia cung cấp cho dưỡng chất mà tồn tại"}]},"nguon":["@c1146"]},{"id":"dao-qua-mau-do","name":"Đạo quả màu đỏ","cn":"","category":"khac","categoryLabel":"Đạo quả","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Quả kết thành từ cây hoa đỏ máu sau khi hấp thu linh hồn và nguyên thần Vương Lâm cùng đạo niệm, trải qua 98 năm ngưng tụ, đẹp như máu tươi.","detail":"Đạo quả đỏ máu ngưng tụ từ cây hoa đỏ máu — cây hoa đầu tiên trong bảy cây kết quả. Được tạo thành từ linh hồn, nguyên thần Vương Lâm cùng hài cốt khắc kinh văn bên trong cây hoa, tất cả hóa thành chất lỏng đỏ. Trải qua chín mươi tám năm, chất lỏng dần cạn kiệt, Đạo quả lớn lên đẹp như máu tươi. Công năng cụ thể chưa rõ.","congNang":["Chưa rõ"],"dacDiem":"Tạo thành từ linh hồn, đạo niệm, hài cốt, 98 năm ngưng tụ, đẹp như máu tươi","nguonGoc":"Kết thành từ cây hoa đỏ máu trong đại trận tinh vực bảy cây hoa","tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"major","giaiDoan":"Kết thành","text":"Linh hồn Vương Lâm bị hút vào cây hoa đỏ, cùng hài cốt hóa chất lỏng đỏ, trải qua 98 năm ngưng tụ thành Đạo quả đỏ máu — Đạo quả đầu tiên trong bảy cây hoa.","anchor":"Dần dần có một quả màu đỏ máu chậm rãi ngưng tụ"}]},"nguon":["@c1146"]},{"id":"ngoc-gian-cua-dong-nham-thach","name":"Ngọc giản trong cửa động (chứa đạo niệm)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Nhiều ngọc giản lơ lửng trong cửa động nham thạch, bên trong phong ấn đạo niệm, phát ra tiếng rên rỉ. Tất cả tan vỡ khi linh hồn Vương Lâm phóng vào.","detail":"Các ngọc giản treo lơ lửng trong cửa động đầy nham thạch nóng chảy, bên trong mỗi ngọc giản phong ấn một luồng đạo niệm. Nham thạch bên dưới khắc nhiều ký hiệu hấp thu đạo niệm từ ngọc giản. Khi linh hồn hồng quang của Vương Lâm phóng vào, tất cả ngọc giản tan vỡ, hài cốt trên khóa sắt nổ tung hóa chất lỏng đen dung hợp vào nham thạch, ký hiệu bị hòa tan.","tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"normal","giaiDoan":"Tan vỡ","text":"Linh hồn Vương Lâm phóng vào cửa động, tất cả ngọc giản phong ấn đạo niệm tan vỡ, hài cốt hóa chất lỏng đen dung nhập nham thạch.","anchor":"bên trong mỗi ngọc giản đều phong ấn một luồng đạo niệm"}]},"nguon":["@c1146"]},{"id":"hat-chau-tien-nghich","name":"Hạt châu Tiên Nghịch","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Cực phẩm (biến đổi quy luật càn khôn)","soHuu":["Vương Lâm"],"trangThai":"moi-hinh-thanh","blurb":"Hạt châu Tiên Nghịch hình thành bên trong Đạo quả của cây bảy màu, khi một luồng thần thức hấp thu lực lượng kỳ dị mà ngưng tụ thành. Sự xuất hiện của nó đủ làm càn khôn rung chuyển và đánh thức Vương Lâm sau trăm năm hôn mê.","detail":"Trong Đạo quả của cây bảy màu xuất hiện một luồng thần thức, hấp thu lực lượng kỳ dị bên trong Đạo quả mà tạo thành hạt châu Tiên Nghịch (@c1147). Biến đổi này đủ sức làm thay đổi quy luật vận chuyển vạn vật ở cả Nội giới lẫn Ngoại giới, khiến Vương Lâm đang chìm trong trăm năm hôn mê được thức tỉnh. Người nuôi hoa không hề phát hiện ra biến đổi diễn ra bên trong Đạo quả.","nguonGoc":"Hình thành trong Đạo quả cây bảy màu","congNang":["Đánh thức Vương Lâm sau trăm năm hôn mê @c1147","Biến đổi quy luật vận chuyển vạn vật cả Nội giới lẫn Ngoại giới @c1147"],"dacDiem":"Hình thành từ thần thức hấp thu lực lượng kỳ dị bên trong Đạo quả cây bảy màu.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1147","denChuong":"","cachCoDuoc":"Tự hình thành bên trong Đạo quả cây bảy màu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1147","loai":"xuất hiện","importance":"major","giaiDoan":"Hình thành lần đầu","text":"Luồng thần thức trong Đạo quả cây bảy màu hấp thu lực lượng kỳ dị tạo thành hạt châu Tiên Nghịch, khiến Vương Lâm thức tỉnh sau trăm năm.","anchor":"Vương Lâm thức tỉnh vì hạt châu Tiên Nghịch xuất hiện"}]},"capNhatToi":"@c1147","nguon":["@c1147"],"uyLuc":"Biến đổi khi hình thành đủ làm càn khôn rung chuyển, thay đổi quy luật vận chuyển vạn vật cả Nội giới lẫn Ngoại giới."},{"id":"but-kim-sac","name":"Bút kim sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lý Thiến Mai"],"trangThai":"dang-dung","blurb":"Pháp bảo Vương Lâm tặng Lý Thiến Mai, vẽ ra uy lực cực mạnh. Nàng kiên quyết không cho ai mượn, liều mạng lấy lại khi bút rơi.","detail":"Cây bút kim sắc trên người Lý Thiến Mai, một khi vẽ ra thì uy lực cực mạnh. Nàng kiên quyết không cho ai mượn dù nhiều người thèm muốn. Có lần bị mười mãnh thú cấp mười hai vây đánh trọng thương hôn mê, bút rơi, nàng tỉnh dậy liền mang thương lao vào lấy lại.","nguonGoc":"Vương Lâm tặng","congNang":["Vẽ ra uy lực cực mạnh"],"chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1147","denChuong":"","cachCoDuoc":"Vương Lâm tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1147","loai":"dùng","importance":"normal","giaiDoan":"Chiến trường Yêu Tông","text":"Lý Thiến Mai dùng bút kim sắc chiến đấu mãnh thú, kiên quyết giữ, liều mạng lấy lại khi rơi.","anchor":"cây bút này một khi vẽ ra thì uy lực cực mạnh"}]},"capNhatToi":"@c1147","nguon":["@c1147"]},{"id":"phu-to-vuong-khi","name":"Phụ Tổ Vương Khí","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Vũ khí Cổ Thần cấp Phụ Tổ Vương","soHuu":[],"trangThai":"dang-co","blurb":"Phụ Tổ Vương Khí là Bát Linh, linh khí thứ tám của trận pháp Phong giới Nội giới, mang hình dạng cây búa khổng lồ tràn đầy khí tức tang thương của vũ khí Cổ Thần. Khi chém ngang quét dọc uy thế như trời giáng, muôn vật không thể phản kháng.","detail":"Phụ Tổ Vương Khí xuất hiện với tư cách linh khí thứ tám (Bát Linh) của trận pháp Phong giới Nội giới @c1149. Nó mang hình dạng một cây búa khổng lồ tràn đầy khí tức tang thương của vũ khí Cổ Thần. Thác Sâm kinh hoàng khi nhận ra đây vốn là vũ khí cấp Phụ Tổ Vương của tộc Cổ Thần, không thể tin một binh khí như vậy lại trở thành linh khí trận pháp. Uy lực chém xuống như trời giáng khiến muôn vật không thể phản kháng, song khi đối phương thi triển Mặc Lưu Phân Thần Thuật với sương mù đen, cây búa lại tỏ ra do dự dừng lại.","nguon":["@c1149"],"congNang":["Chém muôn vật không thể phản kháng, uy thế như trời giáng","Do dự dừng lại khi gặp Mặc Lưu Phân Thần Thuật (sương mù đen)"],"tabs":{"tienTrinh":[{"chuong":"@c1149","loai":"xuất hiện","importance":"major","giaiDoan":"Tái hiện dưới dạng Bát Linh trận pháp Phong giới","text":"Xuất hiện là linh khí thứ tám của trận pháp Phong giới. Thác Sâm kinh hoàng nhận ra đây là Phụ Tổ Vương Khí — vũ khí Cổ Thần cấp Phụ Tổ Vương, không thể tin nó lại trở thành linh khí trận pháp. Chém xuống khiến Thác Sâm liên tục phun máu nhưng do dự dừng lại khi gặp Mặc Lưu Phân Thần Thuật.","anchor":"Điều này… không thể nào! Vật này sao lại trở thành linh khí của trận pháp được"}]},"uyLuc":"Chém xuống như trời giáng, muôn vật không thể phản kháng.","dacDiem":"Hình dạng cây búa khổng lồ tràn đầy khí tức tang thương của vũ khí Cổ Thần, vốn là vũ khí cấp Phụ Tổ Vương của tộc Cổ Thần, nay thành linh khí thứ tám của trận pháp Phong giới."},{"id":"kim-dao-khong-lo","name":"Kim đao khổng lồ","cn":"","category":"khac","categoryLabel":"Khí linh trận pháp","phamCap":"Ngũ Linh (trận pháp Phong giới)","soHuu":[],"trangThai":"dang-co","blurb":"Một trong các khí linh thuộc nhóm Ngũ Linh của trận pháp Phong giới, ngưng tụ từ kim quang, khoảng trăm trượng.","detail":"Khí linh thuộc nhóm Ngũ Linh của trận pháp Phong giới Nội giới, ngưng tụ từ kim quang, khoảng trăm trượng, phóng thẳng về phía Thác Sâm.","nguon":["@c1149"]},{"id":"luu-tinh-chuy","name":"Lưu Tinh Chùy","cn":"","category":"khac","categoryLabel":"Khí linh trận pháp","phamCap":"Ngũ Linh (trận pháp Phong giới)","soHuu":[],"trangThai":"dang-co","blurb":"Khí linh ngưng tụ từ hồng quang, mặt chùy có vết máu, đã tắm máu nhiều kẻ xâm nhập qua nhiều năm.","detail":"Khí linh thuộc nhóm Ngũ Linh của trận pháp Phong giới, ngưng tụ từ hồng quang. Mặt chùy có vết máu, cực kỳ tàn bạo, đã giết nhiều kẻ xâm nhập qua rất nhiều năm. Hóa vạn trượng phóng về phía Thác Sâm.","nguon":["@c1149"]},{"id":"xe-ban-da-khong-lo","name":"Xe bắn đá khổng lồ","cn":"","category":"khac","categoryLabel":"Khí linh trận pháp","phamCap":"Lục Linh (trận pháp Phong giới)","soHuu":[],"trangThai":"dang-co","blurb":"Lục Linh của trận pháp Phong giới, vật phẩm tràn đầy khí tức cổ xưa, cao vài vạn trượng, phóng hỏa cầu lửa không màu cực nhiệt liên tục.","detail":"Khí linh thứ sáu (Lục Linh) của trận pháp Phong giới. Vật phẩm tràn đầy khí tức cổ xưa, cao vài vạn trượng, trên có lửa không màu cực nhiệt. Phóng hỏa cầu liên tục, lực lượng thiên địa tự ngưng tụ thành hỏa cầu mới. Số người chết vì chiếc xe bắn đá này đã đạt đến con số khó tưởng. Dưới sáu linh hợp công, Thác Sâm lần đầu bị bức rút lui.","nguon":["@c1149"]},{"id":"nha-bong-khong-lo","name":"Nha bổng khổng lồ","cn":"","category":"khac","categoryLabel":"Khí linh trận pháp","phamCap":"Thất Linh (trận pháp Phong giới)","soHuu":[],"trangThai":"dang-co","blurb":"Thất Linh của trận pháp Phong giới, hắc quang ngưng tụ, thân bổng bao phủ hắc khí, tuôn luồng khí tức hấp thu tâm thần.","detail":"Khí linh thứ bảy (Thất Linh) của trận pháp Phong giới. Hắc quang ngưng tụ, thân bổng bao phủ hắc khí đồng màu hư vô, tuôn luồng khí tức có thể hấp thu tâm thần đối thủ. Xuất hiện quét ngang tấn công Thác Sâm, phối hợp cùng các linh khác khiến Thác Sâm lần đầu khạc máu.","nguon":["@c1149"]},{"id":"dao-qua-cay-hoa-do-tham","name":"Đạo quả cây hoa đỏ thẫm","cn":"","category":"khac","categoryLabel":"Linh thực","phamCap":"Không rõ (cực phẩm, do Chưởng Tôn tâm huyết nuôi trồng)","soHuu":["Chưởng Tôn"],"trangThai":"da-dung","blurb":"Đạo quả kết từ cây hoa đỏ thẫm trong bảy cây hoa bảy màu, chứa đạo niệm tích lũy qua vạn đại từ viễn cổ đến nay về lôi, hỏa, chiến. Bị Thiên Nghịch hấp thu hoàn toàn.","detail":"Đạo quả do Chưởng Tôn bỏ rất nhiều tâm huyết nuôi trồng tẩm bổ trên cây hoa đỏ thẫm, một trong bảy cây hoa bảy màu trong tinh vực trận pháp. Bên trong chứa chất lỏng đạo niệm cảm ngộ của vô số người tu từ viễn cổ, thượng cổ, tiên giới, Tứ Đại Giới về hỏa đạo, lôi đạo, chiến đạo. Đạo quả bị Thiên Nghịch hấp thu — vỏ quả tan vỡ hóa tinh quang hồng sắc, thân cây trăm trượng cũng bị hút khô (@c1150). Nhờ đó Vương Lâm đột phá từ Tịnh Niết trung kỳ tới Tịnh Niết hậu kỳ đại viên mãn, thu hẹp vực ngăn cách tới Toái Niết.","congNang":["Chứa đạo niệm tích lũy qua vạn đại, cho phép người hấp thu cảm ngộ đạo lôi-hỏa-chiến","Giúp đột phá liên tục nhiều tiểu cảnh giới trong thời gian ngắn"],"nguonGoc":"Cây hoa đỏ thẫm trong bảy cây hoa bảy màu, do Chưởng Tôn nuôi trồng trong tinh vực trận pháp","chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1150","denChuong":"","cachCoDuoc":"Tự nuôi trồng","trangThai":"mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1150","loai":"dùng","importance":"major","giaiDoan":"Bị Thiên Nghịch hấp thu hoàn toàn","phamCap":"Cực phẩm","text":"Đạo quả kết trên cây hoa đỏ thẫm bị Thiên Nghịch hấp thu sạch — vỏ quả tan vỡ hóa tinh quang hồng sắc, thân cây trăm trượng bị hút khô. Vương Lâm nhờ đó đột phá từ Tịnh Niết trung kỳ tới đại viên mãn.","anchor":"Đạo quả đang héo rũ điên cuông, khi bị hút khô thì lớp vỏ tan vỡ hóa thành rất nhiều luồng tinh quang hồng sắc"}]},"nguon":["@c1150"],"uyLuc":"Giúp Vương Lâm đột phá từ Tịnh Niết trung kỳ tới Tịnh Niết hậu kỳ đại viên mãn, thu hẹp vực ngăn cách tới Toái Niết.","dacDiem":"Kết trên cây hoa đỏ thẫm trong bảy cây hoa bảy màu; khi bị hấp thu vỏ quả tan vỡ hóa tinh quang hồng sắc, thân cây trăm trượng bị hút khô."},{"id":"ngoc-boi-tran-linh-phong-gioi","name":"Ngọc bội (trận linh cuối cùng Phong Giới)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Trận linh","phamCap":"Không rõ","soHuu":[],"trangThai":"Xuất hiện","blurb":"Trận linh cuối cùng chưa từng lộ của trận pháp Phong Giới, hiện ra dưới dạng một ngọc bội khi cửa Thiên Nghịch mở.","detail":"Trận linh cuối cùng chưa từng xuất hiện của trận pháp Phong Giới, hiện ra sau khi cửa Thiên Nghịch mở. Khi xuất hiện gây gợn sóng vô tận và tiếng nổ kinh thiên trong đại trận Phong Giới.","congNang":["Trận linh then chốt của đại trận Phong Giới"],"tabs":{"tienTrinh":[{"chuong":"@c1151","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện lần đầu","text":"Trận linh cuối cùng chưa từng lộ của trận pháp Phong Giới hiện ra dưới dạng ngọc bội khi cửa Thiên Nghịch mở, gây gợn sóng kinh thiên.","anchor":"Trận linh cuối cùng này không ngờ lại là một ngọc bội"}]},"capNhatToi":"@c1151","nguon":["@c1151"]},{"id":"doan-kiem-bo-xuong-huou","name":"Đoản kiếm trên bộ xương hươu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (có phong ấn)","soHuu":["Vương Lâm"],"trangThai":"phong ấn","blurb":"Thanh đoản kiếm cắm trên bộ xương thú hình hươu trong động phủ thứ chín, có phong ấn giống hệt thanh kiếm Vương Lâm lấy trước kia. Khi rút ra, bộ xương chấn động hóa tro.","detail":"Nằm giữa sương mù bảy màu vĩnh hằng trong động phủ thứ chín của Tư Mã Mặc. Trên kiếm có phong ấn giống hệt thanh đoản kiếm trên bộ xương nai mà Vương Lâm lấy được trước đó. Vương Lâm rút ra, bộ xương hươu chấn động rồi hóa tro bụi. Thu lại nhưng chưa giải phong ấn.","congNang":["Chưa rõ (phong ấn chưa giải)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1153","denChuong":"","cachCoDuoc":"Rút từ bộ xương hươu trong động phủ thứ chín","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1153","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện và thu nhận","text":"Vương Lâm rút đoản kiếm từ bộ xương hươu trong động phủ thứ chín. Phong ấn trên kiếm giống hệt thanh kiếm lấy trước kia. Bộ xương chấn động hóa tro sau khi kiếm bị rút.","anchor":"bên trên cũng có phong ấn, dường như giống hệt thanh kiếm mà hắn lấy được trước kia"}]},"nguon":["@c1153"]},{"id":"bo-xuong-huou-dong-phu-thu-chin","name":"Bộ xương hươu (động phủ thứ chín)","category":"khac","categoryLabel":"Dị vật","soHuu":[],"trangThai":"đã hủy (hóa tro)","blurb":"Bộ xương thú hình hươu nhỏ nằm giữa sương mù bảy màu trong động phủ thứ chín, là nguồn phát sinh sương bảy màu. Hóa tro khi đoản kiếm bị rút ra.","detail":"Bộ xương thú hình hươu nhỏ nằm giữa sương mù bảy màu vĩnh hằng trong động phủ thứ chín của Tư Mã Mặc. Sương mù bảy màu dường như sinh ra từ bộ xương này. Khi Vương Lâm rút đoản kiếm phong ấn, bộ xương chấn động rồi hóa tro bụi.","congNang":["Nguồn sinh sương mù bảy màu"],"tabs":{"tienTrinh":[{"chuong":"@c1153","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện và hủy","text":"Vương Lâm phát hiện bộ xương hươu cắm đoản kiếm giữa sương mù bảy màu. Sương mù sinh ra từ bộ xương. Rút kiếm thì bộ xương chấn động hóa tro.","anchor":"Đám sương mù này cũng không phải là bỗng nhiên xuất hiện, dường như… dường như là từ bộ xương hươu kia sinh ra"}]},"nguon":["@c1153"]},{"id":"suong-mu-bay-mau-dong-phu-thu-chin","name":"Sương mù bảy màu (động phủ thứ chín)","category":"khac","categoryLabel":"Dị vật / Linh khí","soHuu":[],"trangThai":"đã bị hấp thụ hết","blurb":"Sương mù bảy màu tồn tại vĩnh hằng trong động phủ thứ chín, Tuế Nguyệt không thể xóa đi. Sinh ra từ bộ xương thú hình hươu, mang năng lượng đặc thù liên hệ mật thiết với hồn phách Thiên Vận Tử.","detail":"Sương mù bảy màu tồn tại vĩnh hằng trong động phủ thứ chín, Tuế Nguyệt cũng không thể xóa đi. Nó sinh ra từ bộ xương thú hình hươu và mang năng lượng đặc thù có liên hệ với Thiên Vận Tử. Hồn phách Thiên Vận Tử khát vọng cực mạnh với sương này, lần đầu tự phát vùng vẫy muốn thoát Phong Tiên Ấn khi ở gần sương (@c1153). Vương Lâm dung hợp hồn phách, dẫn toàn bộ sương hấp thụ qua tay vào Phong Tiên Ấn cho hồn phách Thiên Vận Tử; sau khi hấp thụ xuất hiện ảo ảnh Thiên Vận Tử có xác thịt thật.","congNang":["Năng lượng đặc thù liên hệ với Thiên Vận Tử, giúp hồn phách hướng tới tái tạo xác thịt","Kích động hồn phách Thiên Vận Tử tự phát vùng vẫy khi ở gần @c1153"],"tabs":{"tienTrinh":[{"chuong":"@c1153","loai":"dùng","importance":"major","giaiDoan":"Bị hồn phách Thiên Vận Tử hấp thụ toàn bộ","text":"Hồn phách Thiên Vận Tử tự phát vùng vẫy khi gần sương bảy màu. Vương Lâm dung hợp hồn phách, dẫn toàn bộ sương vào Phong Tiên Ấn cho hồn phách hấp thụ điên cuồng. Sau hấp thụ xuất hiện ảo ảnh Thiên Vận Tử thật sự có xác thịt.","anchor":"Như thể là vĩnh hằng, Tuế Nguyệt cũng không thể xóa đi màn sương bảy màu"}]},"nguon":["@c1153"],"dacDiem":"Tồn tại vĩnh hằng trong động phủ thứ chín, Tuế Nguyệt không thể xóa đi; sinh ra từ bộ xương thú hình hươu."},{"id":"ngoc-gian-tue-nguyet-cam-che","name":"Ngọc giản Tuế Nguyệt cấm chế","category":"khac","categoryLabel":"Ngọc giản","soHuu":[],"trangThai":"đã hủy","blurb":"Hai ngọc giản trong động phủ thứ sáu và thứ bảy ghi chép Tuế Nguyệt cấm chế. Vương Lâm ghi nhớ rồi bóp nát hủy để độc chiếm.","detail":"Hai ngọc giản nằm trong động phủ thứ sáu và thứ bảy của Tư Mã Mặc, ghi chép Tuế Nguyệt cấm chế — một trong tứ đại cấm chế. Vương Lâm phá núi đá mang Tuế Nguyệt cấm chế để lấy, ghi nhớ toàn bộ nội dung rồi bóp nát ngọc giản để không ai khác học được.","nguon":["@c1153"]},{"id":"cay-truy-mau-den","name":"Cây trùy màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vân Hồn Tử"],"trangThai":"bi-huy","blurb":"Pháp bảo của Vân Hồn Tử, phong ấn bên trong, phun máu giải phong tán khí tang thương. Vỡ tan khi xuyên cơn lốc xoáy trong Thất Thải giới.","detail":"Vân Hồn Tử lấy ra và phun máu giải phong ấn, phát tán khí tang thương. Khi xuyên qua cơn lốc xoáy, pháp bảo chịu không nổi lực hút mà vỡ tan. Nhờ lực vỡ của nó, Vân Hồn Tử được đẩy vào lỗ hổng thoát ra ngoài. Không phải vật tầm thường.","congNang":["Phong ấn bên trong, giải phong tán khí tang thương"],"chuSoHuu":[{"ten":"Vân Hồn Tử","tuChuong":"@c1154","denChuong":"@c1154","cachCoDuoc":"Không rõ","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1154","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện và bị hủy","text":"Vân Hồn Tử phun máu giải phong ấn cây trùy đen, phát tán khí tang thương. Pháp bảo vỡ tan khi xuyên cơn lốc xoáy, nhờ lực vỡ đẩy chủ nhân thoát ra.","anchor":"ngay cả pháp bảo của hắn cũng vỡ tan. Nhưng pháp bảo này lại không phải là vật tầm thường"}]},"nguon":["@c1154"]},{"id":"chiec-bua-mau-xanh","name":"Chiếc búa màu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không Niết","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo bậc Không Niết thứ hai từ túi trữ vật Thương Tùng Tử, bề mặt có rất nhiều phong ấn, chưa rõ nguyên liệu luyện hóa.","detail":"Vương Lâm lấy ra từ túi trữ vật Thương Tùng Tử ngay sau khi cho nổ Thủy Tinh Kiếm. Chiếc búa màu xanh không rõ được luyện hóa từ thứ gì, bên trên có rất nhiều phong ấn. Chưa kịp sử dụng tại thời điểm cuối chương.","nguon":["@c1155"],"hinhDang":"Búa màu xanh, bề mặt có nhiều phong ấn","nguonGoc":"Từ túi trữ vật của Thương Tùng Tử","chuHienThoi":"Vương Lâm","congNang":["Chưa rõ, chưa sử dụng @c1155"],"chuSoHuu":[{"ten":"Thương Tùng Tử","tuChuong":"","denChuong":"@c1155","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1155","denChuong":"","cachCoDuoc":"Lấy từ túi trữ vật Thương Tùng Tử","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1155","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm rút ra sau khi cho nổ Thủy Tinh Kiếm","text":"Vương Lâm lấy chiếc búa xanh bậc Không Niết thứ hai từ túi trữ vật Thương Tùng Tử, chưa kịp sử dụng.","anchor":"đây là một chiếc búa màu xanh, chiếc búa này không biết được luyện hóa từ thứ gì, bên trên có rất nhiều phong ấn"}]}},{"id":"vong-tay-mau-lam","name":"Vòng tay màu lam","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (chứa phúc hữu Thái Cổ Ngũ Tôn)","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Vòng tay màu lam sáng như ngọc, chứa phúc hữu truyền thừa từ Vân Mộng, do Nguyệt nhi kiếp trước tự tay tặng cho Vương Lâm. Chỉ khi được chủ nhân tự tay trao, phúc hữu mới phát huy tác dụng; người ngoài dù lấy được cũng vô dụng.","detail":"Trong giờ phút tuyệt vọng khi đối mặt cái chết trước ngón cái của Lam Mộng Đạo Tôn, Vương Lâm lấy vòng tay từ không gian trữ vật đeo lên tay trái. Lam quang tỏa ra bao phủ toàn thân, mang theo hơi ấm cơ thể từ trăm năm trước. Lam Mộng Đạo Tôn nhận ra đó là phúc hữu của con gái Nguyệt nhi, lập tức buông tha Vương Lâm.","congNang":["Chứa phúc hữu bảo hộ, khiến Lam Mộng Đạo Tôn nhận ra ân duyên và buông tha @c1157","Chỉ phát huy tác dụng khi được chủ nhân (Nguyệt nhi) tự tay trao @c1157","Tỏa lam quang bao phủ toàn thân, mang hơi ấm cơ thể từ trăm năm trước @c1157"],"chuSoHuu":[{"ten":"Nguyệt nhi","tuChuong":"","denChuong":"","cachCoDuoc":"Truyền thừa từ mẹ Vân Mộng","trangThai":"đã tặng"},{"ten":"Vương Lâm","tuChuong":"@c1157","denChuong":"","cachCoDuoc":"Được Nguyệt nhi kiếp trước tự tay tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1157","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện, cứu mạng Vương Lâm","text":"Vương Lâm đeo vòng tay lam lên tay trái trong giờ phút tuyệt vọng. Lam quang tỏa ra khiến Lam Mộng Đạo Tôn nhận ra phúc hữu của con gái, lập tức buông tha.","anchor":"trên vòng tay nà vẫn còn phúc hữu được truyền thừa từ Vân Mộng nàng"}]},"nguon":["@c1157"],"dacDiem":"Sáng như ngọc, tỏa lam quang mang hơi ấm cơ thể từ trăm năm trước."},{"id":"ngoc-gian-luu-kim-buu","name":"Ngọc giản của Lưu Kim Bưu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lưu Kim Bưu"],"trangThai":"đang sử dụng","blurb":"Ngọc giản phóng kim quang mang khí tức giả Toái Niết đại viên mãn, dùng để truyền âm uy hiếp Quy Nguyên Tông từ xa mười vạn dặm. (+) Ngọc giản ẩn chứa khí tức Toái Niết, dùng để truyền âm và uy hiếp. Phá tan hộ sơn đại trận Thiên Cương Tông. [CAN-SOAT-GOP]","detail":"Ngọc giản phá tan hộ sơn đại trận của Thiên Cương Tông, xuyên thấu nóc đại điện rơi xuống giữa ba trưởng lão. Tỏa khí tức Toái Niết cực mạnh, phát ra tiếng nói của Lưu Kim Bưu.","congNang":["Truyền âm từ xa","Phát khí tức Toái Niết uy hiếp đối phương","Phá hộ sơn đại trận ngũ giai phân tông"],"chuSoHuu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1158","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1158","loai":"dùng","importance":"normal","giaiDoan":"Phá trận uy hiếp Thiên Cương Tông","text":"Lưu Kim Bưu dùng ngọc giản phá tan hộ sơn đại trận Thiên Cương Tông, xuyên thấu nóc đại điện, tỏa khí tức Toái Niết uy hiếp ba trưởng lão.","anchor":"một ngọc giản ầm một tiếng phá tan hộ sơn đại trận của Thiên Cương Tông"}]},"nguon":["@c1158","@c1198","@c1200"]},{"id":"hai-thanh-doan-kiem-ky-di","name":"Hai thanh đoản kiếm kỳ dị","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hai thanh đoản kiếm Vương Lâm chiếm được trong Thất Thải giới, từng đâm vào bộ xương hươu thần bí.","detail":"Hai thanh đoản kiếm kỳ dị từng đâm vào bộ xương hươu thần bí trong Thất Thải giới, được Vương Lâm chiếm lấy. Lai lịch và công năng cụ thể chưa rõ.","dacDiem":"Từng đâm vào bộ xương hươu thần bí","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1159","denChuong":"","cachCoDuoc":"Chiếm được trong Thất Thải giới","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1159","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm chiếm được","text":"Vương Lâm hồi tưởng đã chiếm được hai thanh đoản kiếm kỳ dị đâm vào bộ xương hươu thần bí trong Thất Thải giới.","anchor":"lại chiếm được hai thanh đoản kiếm kỳ dị đâm vào bộ xương hươu thần bí"}]},"nguon":["@c1159"]},{"id":"ngoc-boi-yeu-tong","name":"Ngọc bội của thân ảnh Yêu Tông","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"dang-co","blurb":"Ngọc bội do thân ảnh mơ hồ trong đại điện Yêu Tông đưa cho Lý Thiến Mai, dùng để kích hoạt truyền tống trận tiết kiệm thời gian di chuyển.","detail":"Thân ảnh mơ hồ trấn giữ đại điện Yêu Tông đưa ngọc bội cho Lý Thiến Mai khi nhượng bộ cho nàng rời chiến trường ba tháng. Ngọc bội cho phép sử dụng truyền tống trận để nhanh chóng di chuyển thay vì đi đường thường.","congNang":["Kích hoạt quyền dùng truyền tống trận"],"chuSoHuu":[{"ten":"Lý Thiến Mai","tuChuong":"@c1163","denChuong":"","cachCoDuoc":"Được thân ảnh trong đại điện Yêu Tông trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1163","loai":"doi-chu","importance":"normal","giaiDoan":"Trao cho Lý Thiến Mai","text":"Thân ảnh mơ hồ trong đại điện Yêu Tông thở dài nhượng bộ, đưa ngọc bội cho Lý Thiến Mai dùng truyền tống trận để rời chiến trường ba tháng.","anchor":"hãy cầm ngọc bội của ta, dùng truyền tống trận chuẩn bị đi thôi"}]},"nguon":["@c1163"]},{"id":"te-thien-huong","name":"Tế Thiên Hương","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lý Nguyên Lôi"],"trangThai":"da-dung","blurb":"Hương màu đen to như cánh tay, khi thắp lên tỏa mùi hương kỳ dị khiến Văn Thú chán ghét mà dừng tấn công, là vật bắt buộc mang theo khi vào Phong Tiên Giới.","detail":"Tế Thiên Hương là loại hương đặc biệt màu đen to bằng cánh tay, khi thắp lên phát ra mùi hương kỳ dị có tác dụng khiến Văn Thú chán ghét và dừng tấn công. Nhóm hơn mười tu sĩ tiểu bối thăm dò bên ngoài Phong Tiên Giới đều mang theo và đồng loạt thắp lên khi đàn Văn Thú đỏ thẫm phun ra từ khe.","hinhDang":"Cây hương màu đen to như một cánh tay","congNang":["Tỏa mùi hương kỳ dị khiến Văn Thú chán ghét mà dừng tấn công"],"dacDiem":"Ai muốn vào Phong Tiên Giới đều mang theo","chuSoHuu":[{"ten":"Lý Nguyên Lôi","tuChuong":"@c1164","denChuong":"","cachCoDuoc":"Tự mang theo khi thăm dò Phong Tiên Giới","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1164","loai":"dùng","importance":"normal","giaiDoan":"Dùng xua đuổi Văn Thú","text":"Lý Nguyên Lôi cùng hơn mười tu sĩ đồng loạt thắp Tế Thiên Hương khi đàn Văn Thú đỏ thẫm dữ tợn phun ra từ khe Phong Tiên Giới, mùi hương kỳ dị khiến Văn Thú dừng tấn công.","anchor":"xuất hiện một cây hương màu đen to như một cánh tay, vung lên một cái thắp cây hương này lên"}]},"nguon":["@c1164"]}]};